"""
Parameterized generator for GH1057_ray_28511.

Source PR:    https://github.com/ray-project/ray/pull/28511
Source Issue: https://github.com/ray-project/ray/issues/1234

Seed varies: renames 'above' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1057_ray_28511'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1057_ray_28511'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('above', 'above' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1057_ray_28511',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'ray-project/ray',
                "pr_number": 28511,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/ray-project/ray/pull/28511",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'python/ray/tune/execution/ray_trial_executor.py': '# coding: utf-8\nimport copy\nimport inspect\nimport logging\nimport os\nimport random\nimport time\nimport traceback\nfrom collections import deque\nfrom contextlib import contextmanager\nfrom enum import Enum\nfrom functools import partial\nfrom typing import Callable, Dict, Iterable, List, Optional, Set, Union\n\nimport ray\nfrom ray.air import Checkpoint\nfrom ray.air._internal.checkpoint_manager import CheckpointStorage, _TrackedCheckpoint\nfrom ray.exceptions import GetTimeoutError, RayTaskError\nfrom ray.tune.error import (\n    TuneError,\n    _AbortTrialExecution,\n    _TuneNoNextExecutorEventError,\n    _TuneStartTrialError,\n)\nfrom ray.tune.logger import NoopLogger\nfrom ray.tune.result import STDERR_FILE, STDOUT_FILE, TRIAL_INFO\nfrom ray.tune.experiment.trial import Trial, _Location, _TrialInfo\nfrom ray.tune.utils import warn_if_slow\nfrom ray.tune.execution.placement_groups import (\n    _PlacementGroupManager,\n    _get_tune_pg_prefix,\n)\nfrom ray.tune.utils.resource_updater import _ResourceUpdater\nfrom ray.tune.trainable.util import TrainableUtil\nfrom ray.util import log_once\nfrom ray.util.annotations import DeveloperAPI\nfrom ray.util.placement_group import PlacementGroup, remove_placement_group\n\nlogger = logging.getLogger(__name__)\n\nDEFAULT_GET_TIMEOUT = 60.0  # seconds\n\nDEFAULT_ENV_VARS = {\n    # https://github.com/ray-project/ray/issues/28197\n    "PL_DISABLE_FORK": "1"\n}\n\n\nclass _ActorClassCache:\n    """Caches actor classes.\n\n    ray.remote is a registration call. It sends the serialized object to the\n    key value store (redis), and will be fetched at an arbitrary worker\n    later. Registration does not use any Ray scheduling resources.\n\n    Later, class.remote() actually creates the remote actor. The\n    actor will be instantiated on some arbitrary machine,\n    according to the underlying Ray scheduler.\n\n    Without this cache, you would register the same serialized object\n    over and over again. Naturally, since redis doesn’t spill to disk,\n    this can easily nuke the redis instance (and basically blow up Ray).\n    This cache instead allows us to register once and only once.\n\n    Note that we assume there can be multiple trainables in the\n    system at once.\n    """\n\n    def __init__(self):\n        self._cache = {}\n\n    def get(self, trainable_cls):\n        """Gets the wrapped trainable_cls, otherwise calls ray.remote."""\n        env_vars = DEFAULT_ENV_VARS.copy()\n        env_vars["TUNE_ORIG_WORKING_DIR"] = os.getcwd()\n\n        runtime_env = {"env_vars": env_vars}\n        if trainable_cls not in self._cache:\n            remote_cls = ray.remote(runtime_env=runtime_env)(trainable_cls)\n            self._cache[trainable_cls] = remote_cls\n        return self._cache[trainable_cls]\n\n\n_class_cache = _ActorClassCache()\n\n\nclass _LocalWrapper:\n    def __init__(self, result):\n        self._result = result\n\n    def unwrap(self):\n        """Returns the wrapped result."""\n        return self._result\n\n\ndef _post_stop_cleanup(future, pg, timeout: Optional[float] = None):\n    """Things to be done after a trial is stopped."""\n    assert isinstance(pg, PlacementGroup)\n    try:\n        # Let\'s check one more time if the future resolved. If not,\n        # we remove the PG which will terminate the actor.\n        ray.get(future, timeout=timeout)\n    except GetTimeoutError:\n        if log_once("tune_trial_cleanup_timeout"):\n            logger.error(\n                "Timed out when trying to stop the Ray actor gracefully. "\n                "Consider making `stop` a faster operation."\n            )\n    except Exception:\n        if log_once("tune_trial_cleanup_exception"):\n            logger.error(\n                f"An exception occurred when trying to stop the Ray actor:"\n                f"{traceback.format_exc()}"\n            )\n    finally:\n        remove_placement_group(pg)\n\n\nclass _TrialCleanup:\n    """Responsible for triggering force cleanup of remote actors,\n    without waiting for `Trainable.stop()` to finish.\n\n    Only instantiated when `TUNE_FORCE_TRIAL_CLEANUP_S` is set up.\n    """\n\n    def __init__(self, force_cleanup):\n        assert force_cleanup\n        self._force_cleanup = force_cleanup\n        self._future_to_insert_time = deque()\n\n    def add(self, future):\n        self._future_to_insert_time.append((future, time.time()))\n\n    def get_next(self):\n        """Get the next future that is eligible to be cleaned up forcibly."""\n        if len(self._future_to_insert_time) > 0 and (\n            self._future_to_insert_time[0][1] + self._force_cleanup < time.time()\n        ):\n            future, _time = self._future_to_insert_time.popleft()\n            return future\n        else:\n            return None\n\n    def is_empty(self):\n        return len(self._future_to_insert_time) == 0\n\n\ndef _noop_logger_creator(config, logdir):\n    # Set the working dir in the remote process, for user file writes\n    os.makedirs(logdir, exist_ok=True)\n    if not ray._private.worker._mode() == ray._private.worker.LOCAL_MODE:\n        os.chdir(logdir)\n    return NoopLogger(config, logdir)\n\n\nclass _ExecutorEventType(Enum):\n    """The executor event type.\n\n    Some of the events are internal events to executor while others\n    are handled by runner."""\n\n    NO_RUNNING_TRIAL_TIMEOUT = 1\n    PG_READY = 2\n    TRAINING_RESULT = 3\n    SAVING_RESULT = 4\n    RESTORING_RESULT = 5\n    STOP_RESULT = 6  # Internally to executor only.\n    ERROR = 7  # This is to signal to TrialRunner that there is an error.\n    YIELD = 8  # Yielding back to TrialRunner\'s main event loop.\n\n\nclass _ExecutorEvent:\n    """A struct that describes the event to be processed by TrialRunner.\n\n    Attributes:\n        result: A dict with keys of "future_result" and "exception".\n            "future_result" is the corresponding result when future returns\n            successfully.\n            "exception" is the exception as caught during ``ray.get(future)``.\n    """\n\n    KEY_FUTURE_RESULT = "future_result"\n    KEY_EXCEPTION = "exception"\n\n    def __init__(\n        self,\n        event_type: _ExecutorEventType,\n        trial: Optional[Trial] = None,\n        result: Optional[Dict] = None,\n    ):\n        self.type = event_type\n        self.trial = trial\n        self.result = result\n\n    def __repr__(self):\n        return f"[{self.type}] for {self.trial}"\n\n\n@DeveloperAPI\nclass RayTrialExecutor:\n    """An implementation of TrialExecutor based on Ray."""\n\n    def __init__(\n        self,\n        reuse_actors: bool = False,\n        result_buffer_length: Optional[int] = None,\n        refresh_period: Optional[float] = None,\n    ):\n        self._cached_trial_state = {}\n        self._trials_to_cache = set()\n\n        # future --> (type, trial/pg)\n        self._futures = {}\n\n        force_trial_cleanup = int(os.environ.get("TUNE_FORCE_TRIAL_CLEANUP_S", "600"))\n        self._get_next_event_wait = int(\n            os.environ.get("TUNE_GET_EXECUTOR_EVENT_WAIT_S", "5")\n        )\n        if force_trial_cleanup:\n            self._trial_cleanup = _TrialCleanup(force_trial_cleanup)\n        else:\n            self._trial_cleanup = None\n\n        self._resource_updater = _ResourceUpdater(refresh_period)\n\n        self._has_cleaned_up_pgs = False\n        self._reuse_actors = reuse_actors\n        # The maxlen will be updated when `setup(max_pending_trials)` is called\n        self._cached_actor_pg = deque(maxlen=1)\n        self._pg_manager = _PlacementGroupManager(prefix=_get_tune_pg_prefix())\n        self._staged_trials = set()\n        self._trial_just_finished = False\n        self._trial_just_finished_before = False\n        self.last_pg_recon = 0\n        self.pg_recon_interval = float(\n            os.environ.get("TUNE_PLACEMENT_GROUP_RECON_INTERVAL", "5")\n        )\n\n        self._buffer_length = result_buffer_length or int(\n            os.getenv("TUNE_RESULT_BUFFER_LENGTH", 1)\n        )\n        self._buffer_min_time_s = float(os.getenv("TUNE_RESULT_BUFFER_MIN_TIME_S", 0.0))\n        self._buffer_max_time_s = float(\n            os.getenv("TUNE_RESULT_BUFFER_MAX_TIME_S", 100.0)\n        )\n        self._trainable_kwargs = {}\n\n    def setup(\n        self, max_pending_trials: int, trainable_kwargs: Optional[Dict] = None\n    ) -> None:\n        if len(self._cached_actor_pg) > 0:\n            logger.warning(\n                "Cannot update maximum number of queued actors for reuse "\n                "during a run."\n            )\n        else:\n            self._cached_actor_pg = deque(maxlen=max_pending_trials)\n        self._pg_manager.set_max_staging(max_pending_trials)\n        self._trainable_kwargs = trainable_kwargs or {}\n\n    def set_status(self, trial: Trial, status: str) -> None:\n        """Sets status and checkpoints metadata if needed.\n\n        Only checkpoints metadata if trial status is a terminal condition.\n        PENDING, PAUSED, and RUNNING switches have checkpoints taken care of\n        in the TrialRunner.\n\n        Args:\n            trial: Trial to checkpoint.\n            status: Status to set trial to.\n        """\n        if trial.status == status:\n            logger.debug("Trial %s: Status %s unchanged.", trial, trial.status)\n        else:\n            logger.debug(\n                "Trial %s: Changing status from %s to %s.", trial, trial.status, status\n            )\n        trial.set_status(status)\n        if status in [Trial.TERMINATED, Trial.ERROR]:\n            self._trials_to_cache.add(trial)\n\n    def mark_trial_to_checkpoint(self, trial: Trial) -> None:\n        self._trials_to_cache.add(trial)\n\n    def get_checkpoints(self) -> Dict[str, str]:\n        """Returns a copy of mapping of the trial ID to pickled metadata."""\n        for trial in self._trials_to_cache:\n            self._cached_trial_state[trial.trial_id] = trial.get_json_state()\n        self._trials_to_cache.clear()\n        return self._cached_trial_state\n\n    def _stage_and_update_status(self, trials: Iterable[Trial]):\n        """Check and update statuses of scheduled placement groups.\n\n        Stages placement groups of all trials.\n        """\n        if not self._has_cleaned_up_pgs:\n            # Clean up existing placement groups after trigger the tuning\n            # run step() method for the first time\n            self._pg_manager.cleanup_existing_pg()\n            self._has_cleaned_up_pgs = True\n\n        for trial in trials:\n            if trial.status not in (Trial.PENDING, Trial.PAUSED):\n                continue\n            if trial in self._staged_trials:\n                continue\n            if self._pg_manager.trial_in_use(trial):\n                continue\n\n            if not self._pg_manager.stage_trial_pg(trial):\n                # Break if we reached the limit of pending placement groups.\n                break\n            self._staged_trials.add(trial)\n\n        self._pg_manager.update_status()\n\n    def get_staged_trial(self):\n        """Get a trial whose placement group was successfully staged.\n\n        Can also return None if no trial is available.\n\n        Returns:\n            Trial object or None.\n\n        """\n        # TODO(xwjiang): This method should consider `self._cached_actor_pg`.\n        for trial in self._staged_trials:\n            if self._pg_manager.has_ready(trial):\n                return trial\n\n        return None\n\n    def _setup_remote_runner(self, trial):\n        trial.init_logdir()\n        # We checkpoint metadata here to try mitigating logdir duplication\n        self._trials_to_cache.add(trial)\n        logger_creator = partial(_noop_logger_creator, logdir=trial.logdir)\n\n        if len(self._cached_actor_pg) > 0:\n            assert self._reuse_actors\n            existing_runner, pg = self._cached_actor_pg.popleft()\n            logger.debug(f"Trial {trial}: Reusing cached runner " f"{existing_runner}")\n\n            trial.set_runner(existing_runner)\n            if pg:\n                self._pg_manager.assign_cached_pg(pg, trial)\n\n            if not self.reset_trial(\n                trial, trial.config, trial.experiment_tag, logger_creator\n            ):\n                raise _AbortTrialExecution(\n                    "Trainable runner reuse requires reset_config() to be "\n                    "implemented and return True."\n                )\n            return existing_runner\n\n        trainable_cls = trial.get_trainable_cls()\n        if not trainable_cls:\n            raise _AbortTrialExecution(\n                f"Invalid trainable: {trial.trainable_name}. If you passed "\n                f"a string, make sure the trainable was registered before."\n            )\n        _actor_cls = _class_cache.get(trainable_cls)\n\n        if not self._pg_manager.has_ready(trial):\n            return None\n\n        full_actor_class = self._pg_manager.get_full_actor_cls(trial, _actor_cls)\n        # Clear the Trial\'s location (to be updated later on result)\n        # since we don\'t know where the remote runner is placed.\n        trial.set_location(_Location())\n        logger.debug("Trial %s: Setting up new remote runner.", trial)\n        # Logging for trials is handled centrally by TrialRunner, so\n        # configure the remote runner to use a noop-logger.\n        trial_config = copy.deepcopy(trial.config)\n        trial_config[TRIAL_INFO] = _TrialInfo(trial)\n\n        stdout_file, stderr_file = trial.log_to_file\n        trial_config[STDOUT_FILE] = stdout_file\n        trial_config[STDERR_FILE] = stderr_file\n        kwargs = {\n            "config": trial_config,\n            "logger_creator": logger_creator,\n        }\n        if trial.uses_cloud_checkpointing:\n            # We keep these kwargs separate for backwards compatibility\n            # with trainables that don\'t provide these keyword arguments\n            kwargs["remote_checkpoint_dir"] = trial.remote_checkpoint_dir\n            kwargs["custom_syncer"] = trial.custom_syncer\n\n            if self._trainable_kwargs:\n                kwargs.update(self._trainable_kwargs)\n\n            # Throw a meaningful error if trainable does not use the\n            # new API\n            sig = inspect.signature(trial.get_trainable_cls())\n            try:\n                sig.bind_partial(**kwargs)\n            except Exception as e:\n                raise RuntimeError(\n                    "Your trainable class does not accept a "\n                    "`remote_checkpoint_dir` or `custom_syncer` argument "\n                    "in its constructor, but you\'ve passed a "\n                    "`upload_dir` to your SyncConfig. Without accepting "\n                    "these parameters and passing them to the base trainable "\n                    "constructor in the init call, cloud checkpointing is "\n                    "effectively disabled. To resolve this issue, add the "\n                    "parameters to your trainable class constructor or "\n                    "disable cloud checkpointing by setting `upload_dir=None`."\n                ) from e\n\n        with self._change_working_directory(trial):\n            return full_actor_class.remote(**kwargs)\n\n    def _train(self, trial):\n        """Start one iteration of training and save remote id."""\n\n        if self._find_future(trial):\n            logging.debug(\n                "Trial {} already has a queued future. Skipping this "\n                "`train` call. This may occur if a trial has "\n                "been unpaused within a scheduler callback.".format(str(trial))\n            )\n            return\n\n        assert trial.status == Trial.RUNNING, trial.status\n        buffer_time_s = max(\n            self._buffer_min_time_s,\n            min(self._buffer_max_time_s, len(self._futures) // 10),\n        )\n        with self._change_working_directory(trial):\n            buffer_length = self._buffer_length\n            if buffer_length > 1 and trial.checkpoint_at_end:\n                # If a trial checkpoint can be triggered externally,\n                # it is not safe to buffer results.\n                if log_once("trial_executor_buffer_checkpoint"):\n                    logger.warning(\n                        "Disabling buffered training as you passed "\n                        "`checkpoint_at_end` to `air.CheckpointConfig()`."\n                    )\n                buffer_length = 1\n\n            if buffer_length > 1:\n                if trial.checkpoint_freq > 0:\n                    buffer_length = min(buffer_length, trial.checkpoint_freq)\n                remote = trial.runner.train_buffered.remote(\n                    buffer_time_s, buffer_length\n                )\n            else:\n                remote = trial.runner.train.remote()\n\n        # Local Mode\n        if isinstance(remote, dict):\n            remote = _LocalWrapper(remote)\n\n        self._futures[remote] = (_ExecutorEventType.TRAINING_RESULT, trial)\n        trial_item = self._find_future(trial)\n        assert len(trial_item) < 2, trial_item\n\n    def _start_trial(self, trial: Trial) -> bool:\n        """Starts trial and restores last result if trial was paused.\n\n        Args:\n            trial: The trial to start.\n\n        Returns:\n            True if trial was started successfully, False otherwise.\n\n        See `RayTrialExecutor.restore` for possible errors raised.\n        """\n        self.set_status(trial, Trial.PENDING)\n        runner = self._setup_remote_runner(trial)\n        if not runner:\n            return False\n        trial.set_runner(runner)\n        self.restore(trial)\n        self.set_status(trial, Trial.RUNNING)\n\n        self._staged_trials.discard(trial)\n\n        if not trial.is_restoring:\n            self._train(trial)\n        return True\n\n    def _stop_trial(\n        self,\n        trial: Trial,\n        error: bool = False,\n        exc: Optional[Union[TuneError, RayTaskError]] = None,\n    ):\n        """Stops this trial.\n\n        Stops this trial, releasing all allocating resources. If stopping the\n        trial fails, the run will be marked as terminated in error, but no\n        exception will be thrown.\n\n        Args:\n            error: Whether to mark this trial as terminated in error.\n            exc: Optional exception.\n\n        """\n        self.set_status(trial, Trial.ERROR if error or exc else Trial.TERMINATED)\n        self._trial_just_finished = True\n        trial.set_location(_Location())\n\n        try:\n            trial.write_error_log(exc=exc)\n            if hasattr(trial, "runner") and trial.runner:\n                if (\n                    not error\n                    and self._reuse_actors\n                    and (\n                        len(self._cached_actor_pg)\n                        < (self._cached_actor_pg.maxlen or float("inf"))\n                    )\n                ):\n                    logger.debug("Reusing actor for %s", trial.runner)\n                    # Move PG into cache (disassociate from trial)\n                    pg = self._pg_manager.cache_trial_pg(trial)\n                    if pg:\n                        # True if a placement group was replaced\n                        self._cached_actor_pg.append((trial.runner, pg))\n                        should_destroy_actor = False\n                    else:\n                        # False if no placement group was replaced. This should\n                        # only be the case if there are no more trials with\n                        # this placement group factory to run\n                        logger.debug(\n                            f"Could not cache actor of trial {trial} for "\n                            "reuse, as there are no pending trials "\n                            "requiring its resources."\n                        )\n                        should_destroy_actor = True\n                else:\n                    should_destroy_actor = True\n\n                if should_destroy_actor:\n                    logger.debug("Trial %s: Destroying actor.", trial)\n\n                    with self._change_working_directory(trial):\n                        future = trial.runner.stop.remote()\n\n                    pg = self._pg_manager.remove_from_in_use(trial)\n                    self._futures[future] = (\n                        _ExecutorEventType.STOP_RESULT,\n                        pg,\n                    )\n                    if self._trial_cleanup:  # force trial cleanup within a deadline\n                        self._trial_cleanup.add(future)\n\n                self._staged_trials.discard(trial)\n\n        except Exception:\n            logger.exception("Trial %s: Error stopping runner.", trial)\n            self.set_status(trial, Trial.ERROR)\n        finally:\n            trial.set_runner(None)\n\n    def start_trial(self, trial: Trial) -> bool:\n        """Starts the trial.\n\n        Will not return resources if trial repeatedly fails on start.\n\n        Args:\n            trial: Trial to be started.\n\n        Returns:\n            True if the remote runner has been started. False if trial was\n                not started (e.g. because of lacking resources/pending PG).\n        """\n        try:\n            return self._start_trial(trial)\n        except _AbortTrialExecution as e:\n            logger.exception("Trial %s: Error starting runner, aborting!", trial)\n            time.sleep(2)\n            self._stop_trial(trial, exc=e)\n            return False\n        except Exception as e:\n            logger.exception("Trial %s: Unexpected error starting runner.", trial)\n            time.sleep(2)\n            if isinstance(e, TuneError):\n                self._stop_trial(trial, exc=e)\n            else:\n                self._stop_trial(\n                    trial, exc=_TuneStartTrialError(traceback.format_exc())\n                )\n            # Note that we don\'t return the resources, since they may\n            # have been lost. TODO(ujvl): is this the right thing to do?\n            return False\n\n    def _find_future(self, trial):\n        out = [rid for rid, t in self._futures.items() if t[1] is trial]\n        assert (\n            len(out) <= 1\n        ), "Expecting one future for any given trial at any given time."\n        return out\n\n    def stop_trial(\n        self,\n        trial: Trial,\n        error: bool = False,\n        exc: Optional[Union[TuneError, RayTaskError]] = None,\n    ) -> None:\n        prior_status = trial.status\n        if prior_status == Trial.RUNNING:\n            logger.debug("Trial %s: Returning resources.", trial)\n            out = self._find_future(trial)\n            for result_id in out:\n                self._futures.pop(result_id)\n        self._stop_trial(trial, error=error or exc, exc=exc)\n\n    def continue_training(self, trial: Trial) -> None:\n        """Continues the training of this trial."""\n        self._train(trial)\n\n    def pause_trial(self, trial: Trial) -> None:\n        """Pauses the trial.\n\n        We want to release resources (specifically GPUs) when pausing an\n        experiment. This results in PAUSED state that similar to TERMINATED.\n        """\n        assert trial.status == Trial.RUNNING, trial.status\n        try:\n            self.save(trial, CheckpointStorage.MEMORY)\n            self.stop_trial(trial)\n            self.set_status(trial, Trial.PAUSED)\n        except Exception:\n            logger.exception("Error pausing runner.")\n            self.set_status(trial, Trial.ERROR)\n\n    def reset_trial(\n        self,\n        trial: Trial,\n        new_config: Dict,\n        new_experiment_tag: str,\n        logger_creator: Optional[Callable[[Dict], "ray.tune.Logger"]] = None,\n    ) -> bool:\n        """Tries to invoke `Trainable.reset()` to reset trial.\n\n        Args:\n            trial: Trial to be reset.\n            new_config: New configuration for Trial trainable.\n            new_experiment_tag: New experiment name for trial.\n            logger_creator: Function that instantiates a logger on the\n                actor process.\n\n        Returns:\n            True if `reset_config` is successful else False.\n        """\n        trial.set_experiment_tag(new_experiment_tag)\n        trial.set_config(new_config)\n        trainable = trial.runner\n\n        # Pass magic variables\n        extra_config = copy.deepcopy(new_config)\n        extra_config[TRIAL_INFO] = _TrialInfo(trial)\n\n        stdout_file, stderr_file = trial.log_to_file\n        extra_config[STDOUT_FILE] = stdout_file\n        extra_config[STDERR_FILE] = stderr_file\n\n        with self._change_working_directory(trial):\n            with warn_if_slow("reset"):\n                try:\n                    reset_val = ray.get(\n                        trainable.reset.remote(extra_config, logger_creator),\n                        timeout=DEFAULT_GET_TIMEOUT,\n                    )\n                except GetTimeoutError:\n                    logger.exception("Trial %s: reset timed out.", trial)\n                    return False\n        return reset_val\n\n    def has_resources_for_trial(self, trial: Trial) -> bool:\n        """Returns whether there are resources available for this trial.\n\n        This will return True as long as we didn\'t reach the maximum number\n        of pending trials. It will also return True if the trial placement\n        group is already staged.\n\n        Args:\n            trial: Trial object which should be scheduled.\n\n        Returns:\n            boolean\n\n        """\n        return (\n            trial in self._staged_trials\n            or (\n                len(self._cached_actor_pg) > 0\n                and (self._pg_manager.has_cached_pg(trial.placement_group_factory))\n            )\n            or self._pg_manager.can_stage()\n            or self._pg_manager.has_ready(trial, update=True)\n            or self._pg_manager.has_staging(trial)\n        )\n\n    def debug_string(self) -> str:\n        """Returns a human readable message for printing to the console."""\n        total_resources = self._pg_manager.occupied_resources()\n        return self._resource_updater.debug_string(total_resources)\n\n    def on_step_begin(self, trials: List[Trial]) -> None:\n        """Before step() is called, update the available resources."""\n        self._resource_updater.update_avail_resources()\n        self._trial_just_finished_before = self._trial_just_finished\n        self._trial_just_finished = False\n\n    def on_step_end(self, trials: List[Trial]) -> None:\n        self._do_force_trial_cleanup()\n        if time.time() > self.last_pg_recon + self.pg_recon_interval:\n            # Only do this every now and then - usually the placement groups\n            # should not get out of sync, and calling this often is inefficient\n            self._pg_manager.reconcile_placement_groups(trials)\n            self.last_pg_recon = time.time()\n\n        self._pg_manager.cleanup()\n\n    def _do_force_trial_cleanup(self) -> None:\n        if self._trial_cleanup:\n            while True:\n                next_future_to_clean = self._trial_cleanup.get_next()\n                if not next_future_to_clean:\n                    break\n                if next_future_to_clean in self._futures:\n                    _, pg = self._futures.pop(next_future_to_clean)\n                    # Immediately clean this future\n                    _post_stop_cleanup(next_future_to_clean, pg, timeout=0.01)\n                else:\n                    # This just means that before the deadline reaches,\n                    # the future is already cleaned up.\n                    pass\n\n    def force_reconcilation_on_next_step_end(self) -> None:\n        self.last_pg_recon = -float("inf")\n\n    def save(\n        self,\n        trial: Trial,\n        storage: CheckpointStorage = CheckpointStorage.PERSISTENT,\n        result: Optional[Dict] = None,\n    ) -> _TrackedCheckpoint:\n        """Saves the trial\'s state to a checkpoint asynchronously.\n\n        Args:\n            trial: The trial to be saved.\n            storage: Where to store the checkpoint. Defaults to\n                PERSISTENT.\n            result: The state of this trial as a dictionary to be saved.\n                If result is None, the trial\'s last result will be used.\n\n        Returns:\n             Checkpoint object, or None if an Exception occurs.\n        """\n        logger.debug(f"saving trial {trial}")\n        result = result or trial.last_result\n        with self._change_working_directory(trial):\n            if storage == CheckpointStorage.MEMORY:\n                value = trial.runner.save_to_object.remote()\n                checkpoint = _TrackedCheckpoint(\n                    dir_or_data=value, storage_mode=storage, metrics=result\n                )\n                trial.on_checkpoint(checkpoint)\n            else:\n                value = trial.runner.save.remote()\n                checkpoint = _TrackedCheckpoint(\n                    dir_or_data=value, storage_mode=storage, metrics=result\n                )\n                trial.saving_to = checkpoint\n                self._futures[value] = (_ExecutorEventType.SAVING_RESULT, trial)\n        return checkpoint\n\n    def restore(self, trial: Trial) -> None:\n        """Restores training state from a given model checkpoint.\n\n        Args:\n            trial: The trial to be restored.\n\n        Raises:\n            RuntimeError: This error is raised if no runner is found.\n            AbortTrialExecution: This error is raised if the trial is\n                ineligible for restoration, given the Tune input arguments.\n        """\n        checkpoint = trial.checkpoint\n        if checkpoint.dir_or_data is None:\n            return\n        if trial.runner is None:\n            raise RuntimeError(\n                "Trial {}: Unable to restore - no runner found.".format(trial)\n            )\n        checkpoint_dir = checkpoint.dir_or_data\n        node_ip = checkpoint.node_ip\n        if checkpoint.storage_mode == CheckpointStorage.MEMORY:\n            logger.debug("Trial %s: Attempting restore from object", trial)\n            # Note that we don\'t store the remote since in-memory checkpoints\n            # don\'t guarantee fault tolerance and don\'t need to be waited on.\n            with self._change_working_directory(trial):\n                trial.runner.restore_from_object.remote(checkpoint_dir)\n        else:\n            logger.debug("Trial %s: Attempting restore from %s", trial, checkpoint_dir)\n            if (\n                trial.uses_cloud_checkpointing\n                or not trial.sync_on_checkpoint\n                or not os.path.exists(checkpoint_dir)\n            ):\n                # If using cloud checkpointing, trial will get cp from cloud.\n                # If not syncing to driver, assume it has access to the cp\n                # on the local fs.\n                with self._change_working_directory(trial):\n                    remote = trial.runner.restore.remote(checkpoint_dir, node_ip)\n            elif trial.sync_on_checkpoint:\n                # This provides FT backwards compatibility in the\n                # case where no cloud checkpoints are provided.\n                logger.debug("Trial %s: Reading checkpoint into memory", trial)\n                checkpoint_path = TrainableUtil.find_checkpoint_dir(checkpoint_dir)\n                obj = Checkpoint.from_directory(checkpoint_path).to_bytes()\n                with self._change_working_directory(trial):\n                    remote = trial.runner.restore_from_object.remote(obj)\n            else:\n                raise _AbortTrialExecution(\n                    "Pass in `sync_on_checkpoint=True` for driver-based trial"\n                    "restoration. Pass in an `upload_dir` for remote "\n                    "storage-based restoration"\n                )\n\n            self._futures[remote] = (_ExecutorEventType.RESTORING_RESULT, trial)\n            trial.restoring_from = checkpoint\n\n    def export_trial_if_needed(self, trial: Trial) -> Dict:\n        """Exports model of this trial based on trial.export_formats.\n\n        Return:\n            A dict that maps ExportFormats to successfully exported models.\n        """\n        if trial.export_formats and len(trial.export_formats) > 0:\n            with self._change_working_directory(trial):\n                return ray.get(\n                    trial.runner.export_model.remote(trial.export_formats),\n                    timeout=DEFAULT_GET_TIMEOUT,\n                )\n        return {}\n\n    def has_gpus(self) -> bool:\n        return self._resource_updater.get_num_gpus() > 0\n\n    def cleanup(self, trials: List[Trial]) -> None:\n        while self._futures:\n            if self._trial_cleanup and self._trial_cleanup.is_empty():\n                break\n\n            # Non-blocking trial cleanup futures\n            self._do_force_trial_cleanup()\n\n            # Deal with other futures\n            ready, _ = ray.wait(list(self._futures.keys()), timeout=0)\n            if not ready:\n                continue\n            event_type, trial_or_pg = self._futures.pop(ready[0])\n\n            # It could be STOP future after all, if so, deal with it here.\n            if event_type == _ExecutorEventType.STOP_RESULT:\n                pg = trial_or_pg\n                # Blocking here is ok as the future returned\n                _post_stop_cleanup(ready[0], pg, timeout=None)\n\n        self._pg_manager.reconcile_placement_groups(trials)\n        self._pg_manager.cleanup(force=True)\n        self._pg_manager.cleanup_existing_pg(block=True)\n\n    @contextmanager\n    def _change_working_directory(self, trial):\n        """Context manager changing working directory to trial logdir.\n        Used in local mode.\n\n        For non-local mode it is no-op.\n        """\n        if ray._private.worker._mode() == ray._private.worker.LOCAL_MODE:\n            old_dir = os.getcwd()\n            try:\n                os.chdir(trial.logdir)\n                yield\n            finally:\n                os.chdir(old_dir)\n        else:\n            yield\n\n    def get_next_executor_event(\n        self, live_trials: Set[Trial], next_trial_exists: bool\n    ) -> _ExecutorEvent:\n        """Get the next executor event to be processed in TrialRunner.\n\n        In case there are multiple events available for handling, the next\n        event is determined by the following priority:\n        1. if there is `next_trial_exists`, and if there is cached resources\n        to use, PG_READY is emitted.\n        2. if there is `next_trial_exists` and there is no cached resources\n        to use, wait on pg future and randomized other futures. If multiple\n        futures are ready, pg future will take priority to be handled first.\n        3. if there is no `next_trial_exists`, wait on just randomized other\n        futures.\n\n        An example of #3 would be synchronous hyperband. Although there are pgs\n        ready, the scheduler is holding back scheduling new trials since the\n        whole band of trials is waiting for the slowest trial to finish. In\n        this case, we prioritize handling training result to avoid deadlock\n        situation.\n\n        This is a blocking wait with a timeout (specified with env var).\n        The reason for the timeout is\n        we still want to print status info periodically in TrialRunner for\n        better user experience.\n\n        The handle of `ExecutorEvent.STOP_RESULT` is purely internal to\n        RayTrialExecutor itself. All the other future results are handled by\n        TrialRunner.\n\n        In the future we may want to do most of the handle of\n        `ExecutorEvent.RESTORE_RESULT` and `SAVING_RESULT` in\n        RayTrialExecutor itself and only notify TrialRunner to invoke\n        corresponding callbacks. This view is more consistent with our goal\n        of TrialRunner responsible for external facing Trial state transition,\n        while RayTrialExecutor responsible for internal facing transitions,\n        namely, `is_saving`, `is_restoring` etc.\n\n        Also you may notice that the boundary between RayTrialExecutor and\n        PlacementGroupManager right now is really blurry. This will be\n        improved once we move to an ActorPool abstraction.\n\n        `next_trial_exists` means that there is a trial to run - prioritize\n        returning PG_READY in this case.\n        """\n        # First update status of staged placement groups\n        self._stage_and_update_status(live_trials)\n        while True:\n            ###################################################################\n            # when next_trial_exists and there are cached resources\n            ###################################################################\n            # There could be existing PGs from either `self._cached_actor_pg`\n            # or from `self._pg_manager._ready`. If so and if there is indeed\n            # a next trial to run, we return `PG_READY` future for trial\n            # runner. The next trial can then be scheduled on this PG.\n            if next_trial_exists:\n                if len(self._cached_actor_pg) > 0:\n                    return _ExecutorEvent(_ExecutorEventType.PG_READY)\n                # TODO(xwjiang): Expose proper API when we decide to do\n                #  ActorPool abstraction.\n                if any(len(r) > 0 for r in self._pg_manager._ready.values()):\n                    return _ExecutorEvent(_ExecutorEventType.PG_READY)\n\n            ###################################################################\n            # Prepare for futures to wait\n            ###################################################################\n            futures_to_wait = list(self._futures.keys())\n            random.shuffle(futures_to_wait)\n            if next_trial_exists:\n                # Only wait for pg explicitly if there is next trial to run.\n                # In which case, handling PG_READY triumphs handling other events.\n                # Since we want to place pending trial ASAP.\n                futures_to_wait = (\n                    self._pg_manager.get_staging_future_list() + futures_to_wait\n                )\n            logger.debug(\n                f"get_next_executor_event before wait with futures "\n                f"{futures_to_wait} and "\n                f"next_trial_exists={next_trial_exists}"\n            )\n\n            ready_futures, _ = ray.wait(\n                futures_to_wait, num_returns=1, timeout=self._get_next_event_wait\n            )\n\n            ###################################################################\n            # Dealing with no future returned case.\n            ###################################################################\n            if len(ready_futures) == 0:\n                if len(self._futures) == 0:\n                    # No running trial and timing out with wait, could be we may\n                    # have insufficient cluster resources that makes tune run\n                    # infeasible.\n                    # TODO: Move InsufficientResourceManager\'s logic\n                    #  to TrialExecutor. It is not Runner\'s responsibility!\n                    return _ExecutorEvent(_ExecutorEventType.NO_RUNNING_TRIAL_TIMEOUT)\n                else:\n                    # Training simply takes long time, yield the control back to main\n                    # event loop to print progress info etc.\n                    return _ExecutorEvent(_ExecutorEventType.YIELD)\n\n            ###################################################################\n            # If there is future returned.\n            ###################################################################\n            assert len(ready_futures) == 1\n            ready_future = ready_futures[0]\n\n            ###################################################################\n            # If it is a PG_READY event.\n            ###################################################################\n            if ready_future not in self._futures.keys():\n                self._pg_manager.handle_ready_future(ready_future)\n                return _ExecutorEvent(_ExecutorEventType.PG_READY)\n\n            ###################################################################\n            # non PG_READY event\n            ###################################################################\n            result_type, trial_or_pg = self._futures.pop(ready_future)\n            if result_type == _ExecutorEventType.STOP_RESULT:\n                pg = trial_or_pg\n                # This will block, which is ok as the stop future returned\n                _post_stop_cleanup(ready_future, pg, timeout=None)\n            else:\n                trial = trial_or_pg\n                assert isinstance(trial, Trial)\n                try:\n                    future_result = ray.get(ready_future)\n                    # For local mode\n                    if isinstance(future_result, _LocalWrapper):\n                        future_result = future_result.unwrap()\n                    if result_type in (\n                        _ExecutorEventType.TRAINING_RESULT,\n                        _ExecutorEventType.SAVING_RESULT,\n                        _ExecutorEventType.RESTORING_RESULT,\n                    ):\n                        logger.debug(f"Returning [{result_type}] for trial {trial}")\n                        return _ExecutorEvent(\n                            result_type,\n                            trial,\n                            result={_ExecutorEvent.KEY_FUTURE_RESULT: future_result},\n                        )\n                    else:\n                        raise TuneError(f"Unexpected future type - [{result_type}]")\n                except RayTaskError as e:\n                    return _ExecutorEvent(\n                        _ExecutorEventType.ERROR,\n                        trial,\n                        result={_ExecutorEvent.KEY_EXCEPTION: e.as_instanceof_cause()},\n                    )\n                except Exception:\n                    return _ExecutorEvent(\n                        _ExecutorEventType.ERROR,\n                        trial,\n                        result={\n                            _ExecutorEvent.KEY_EXCEPTION: _TuneNoNextExecutorEventError(\n                                traceback.format_exc()\n                            )\n                        },\n                    )\n',
            'python/ray/tune/execution/trial_runner.py': 'from dataclasses import dataclass\nfrom typing import Any, List, Mapping, Optional, Union, Tuple\n\nimport click\nfrom datetime import datetime\nimport json\nimport logging\nimport os\nimport time\nimport traceback\nimport warnings\n\nimport ray\nfrom ray.air._internal.checkpoint_manager import CheckpointStorage\nfrom ray.exceptions import RayTaskError\nfrom ray.tune.error import _TuneStopTrialError\nfrom ray.tune.impl.out_of_band_serialize_dataset import out_of_band_serialize_dataset\nfrom ray.util import get_node_ip_address\nfrom ray.tune import TuneError\nfrom ray.tune.callback import CallbackList, Callback\nfrom ray.tune.experiment import Experiment\nfrom ray.tune.execution.insufficient_resources_manager import (\n    _InsufficientResourcesManager,\n)\nfrom ray.tune.execution.ray_trial_executor import (\n    RayTrialExecutor,\n    _ExecutorEventType,\n    _ExecutorEvent,\n)\nfrom ray.tune.result import (\n    DEBUG_METRICS,\n    DEFAULT_METRIC,\n    DONE,\n    TIME_THIS_ITER_S,\n    RESULT_DUPLICATE,\n    SHOULD_CHECKPOINT,\n)\nfrom ray.tune.schedulers import FIFOScheduler, TrialScheduler\nfrom ray.tune.stopper import NoopStopper, Stopper\nfrom ray.tune.search import BasicVariantGenerator, SearchAlgorithm\nfrom ray.tune.syncer import SyncConfig, get_node_to_storage_syncer, Syncer\nfrom ray.tune.experiment import Trial\nfrom ray.tune.utils import warn_if_slow, flatten_dict\nfrom ray.tune.utils.log import Verbosity, has_verbosity\nfrom ray.tune.execution.placement_groups import PlacementGroupFactory\nfrom ray.tune.utils.serialization import TuneFunctionDecoder, TuneFunctionEncoder\nfrom ray.tune.web_server import TuneServer\nfrom ray.util.annotations import DeveloperAPI\nfrom ray.util.debug import log_once\n\nMAX_DEBUG_TRIALS = 20\n\nlogger = logging.getLogger(__name__)\n\n\ndef _find_newest_experiment_checkpoint(ckpt_dir) -> Optional[str]:\n    """Returns path to most recently modified checkpoint."""\n    full_paths = [\n        os.path.join(ckpt_dir, fname)\n        for fname in os.listdir(ckpt_dir)\n        if fname.startswith("experiment_state") and fname.endswith(".json")\n    ]\n    if not full_paths:\n        return None\n    return max(full_paths)\n\n\ndef _load_trial_from_checkpoint(trial_cp: dict, stub: bool = False, **kwargs):\n    new_trial = Trial(\n        trial_cp["trainable_name"], stub=stub, _setup_default_resource=False, **kwargs\n    )\n    new_trial.__setstate__(trial_cp)\n    return new_trial\n\n\ndef _load_trials_from_experiment_checkpoint(\n    experiment_checkpoint: Mapping[str, Any], stub: bool = False\n) -> List[Trial]:\n    """Create trial objects from experiment checkpoint.\n\n    Given an experiment checkpoint (TrialRunner state dict), return\n    list of trials."""\n    checkpoints = [\n        json.loads(cp, cls=TuneFunctionDecoder) if isinstance(cp, str) else cp\n        for cp in experiment_checkpoint["checkpoints"]\n    ]\n\n    trials = []\n    for trial_cp in checkpoints:\n        trials.append(_load_trial_from_checkpoint(trial_cp, stub=stub))\n\n    return trials\n\n\n@dataclass\nclass _ResumeConfig:\n    resume_unfinished: bool = True\n    resume_errored: bool = False\n    restart_errored: bool = False\n\n\nclass _ExperimentCheckpointManager:\n    """Helper class for managing experiment-level checkpoints.\n\n    This class implements the ``checkpoint()`` method used to checkpoint\n    experiment state. When called, this will serialize and write to disk\n    the state of the trial runner, trial executor, and search algorithm, to\n    a specified checkpoint file.\n\n    The checkpoint period is automatically adjusted to\n    ``max(10, time_per_checkpoint * 19)``. This means that at most 5% of the\n    time (1/20) will be used for writing checkpoints, while 95% of the time\n    (19/20) will be used to handle the rest of the training loop.\n\n    """\n\n    def __init__(\n        self,\n        checkpoint_dir: str,\n        checkpoint_period: Union[int, float, str],\n        start_time: float,\n        session_str: str,\n        syncer: Syncer,\n        sync_trial_checkpoints: bool,\n        local_dir: str,\n        remote_dir: str,\n    ):\n        self._checkpoint_dir = checkpoint_dir\n        self._auto_checkpoint_enabled = checkpoint_period == "auto"\n        if self._auto_checkpoint_enabled:\n            self._checkpoint_period = 10.0  # Initial value\n        else:\n            self._checkpoint_period = float(checkpoint_period)\n\n        self._start_time = start_time\n        self._session_str = session_str\n\n        self._syncer = syncer\n        self._sync_trial_checkpoints = sync_trial_checkpoints\n        self._local_dir = local_dir\n        self._remote_dir = remote_dir\n\n        self._last_checkpoint_time = 0.0\n\n    @property\n    def auto_checkpoint_enabled(self):\n        return self._auto_checkpoint_enabled\n\n    def checkpoint(\n        self,\n        checkpoint_file: str,\n        trial_runner: "TrialRunner",\n        trial_executor: RayTrialExecutor,\n        search_alg: SearchAlgorithm,\n        force: bool = False,\n    ):\n        """Saves execution state to `self._local_checkpoint_dir`.\n\n        Overwrites the current session checkpoint, which starts when self\n        is instantiated. Throttle depends on self._checkpoint_period.\n\n        Also automatically saves the search algorithm to the local\n        checkpoint dir.\n\n        Args:\n            force: Forces a checkpoint despite checkpoint_period.\n        """\n        if not self._checkpoint_dir:\n            return\n\n        now = time.time()\n        if now - self._last_checkpoint_time < self._checkpoint_period and (not force):\n            return\n\n        def _serialize_and_write():\n            runner_state = {\n                "checkpoints": list(trial_executor.get_checkpoints().values()),\n                "runner_data": trial_runner.__getstate__(),\n                "stats": {\n                    "start_time": self._start_time,\n                    "timestamp": self._last_checkpoint_time,\n                },\n            }\n            tmp_file_name = os.path.join(self._checkpoint_dir, ".tmp_checkpoint")\n            with open(tmp_file_name, "w") as f:\n                json.dump(runner_state, f, indent=2, cls=TuneFunctionEncoder)\n\n            os.replace(tmp_file_name, checkpoint_file)\n            search_alg.save_to_dir(self._checkpoint_dir, session_str=self._session_str)\n\n        checkpoint_time_start = time.monotonic()\n        with out_of_band_serialize_dataset():\n            _serialize_and_write()\n\n        if self._sync_trial_checkpoints:\n            exclude = None\n        else:\n            exclude = ["*/checkpoint_*"]\n\n        if self._syncer:\n            # Todo: Implement sync_timeout for experiment-level syncing\n            # (it is currently only used for trainable-to-cloud syncing)\n            if force:\n                # Wait until previous sync command finished\n                self._syncer.wait()\n                self._syncer.sync_up(\n                    local_dir=self._local_dir,\n                    remote_dir=self._remote_dir,\n                    exclude=exclude,\n                )\n            else:\n                self._syncer.sync_up_if_needed(\n                    local_dir=self._local_dir,\n                    remote_dir=self._remote_dir,\n                    exclude=exclude,\n                )\n\n        checkpoint_time_taken = time.monotonic() - checkpoint_time_start\n\n        if self._auto_checkpoint_enabled:\n            # Multiplying this time by 19 means we spend ~5% of the time\n            # writing global checkpoints and 95% of the time processing trials\n            self._checkpoint_period = max(10.0, checkpoint_time_taken * 19)\n            logger.debug(\n                f"Global experiment checkpointing took "\n                f"{checkpoint_time_taken:.2f} seconds. "\n                f"Adjusting checkpoint period to "\n                f"{self._checkpoint_period:.2f} seconds."\n            )\n\n        self._last_checkpoint_time = time.time()\n        return self._checkpoint_dir\n\n\n@DeveloperAPI\nclass TrialRunner:\n    """A TrialRunner implements the event loop for scheduling trials on Ray.\n\n    .. code-block: python\n\n        runner = TrialRunner()\n        runner.add_trial(Trial(...))\n        runner.add_trial(Trial(...))\n        while not runner.is_finished():\n            runner.step()\n            print(runner.debug_string())\n\n    The main job of TrialRunner is scheduling trials to efficiently use cluster\n    resources, without overloading the cluster.\n\n    While Ray itself provides resource management for tasks and actors, this is\n    not sufficient when scheduling trials that may instantiate multiple actors.\n    This is because if insufficient resources are available, concurrent trials\n    could deadlock waiting for new resources to become available. Furthermore,\n    oversubscribing the cluster could degrade training performance, leading to\n    misleading benchmark results.\n\n    Args:\n        search_alg: SearchAlgorithm for generating\n            Trial objects.\n        scheduler: Defaults to FIFOScheduler.\n        local_checkpoint_dir: Path where\n            global checkpoints are stored and restored from.\n        remote_checkpoint_dir: Remote path where\n            global checkpoints are stored and restored from. Used\n            if `resume` == REMOTE.\n        sync_config: See `tune.py:run`.\n        stopper: Custom class for stopping whole experiments. See\n            ``Stopper``.\n        resume: see `tune.py:run`.\n        server_port: Port number for launching TuneServer.\n        fail_fast: Finishes as soon as a trial fails if True.\n            If fail_fast=\'raise\' provided, Tune will automatically\n            raise the exception received by the Trainable. fail_fast=\'raise\'\n            can easily leak resources and should be used with caution.\n        checkpoint_period: Trial runner checkpoint periodicity in\n            seconds. Defaults to ``"auto"``, which adjusts checkpointing\n            time so that at most 5% of the time is spent on writing\n            checkpoints.\n        trial_executor: Defaults to RayTrialExecutor.\n        callbacks: List of callbacks that will be called at different\n            times in the training loop. Must be instances of the\n            ``ray.tune.execution.trial_runner.Callback`` class.\n        metric: Metric used to check received results. If a result is\n            reported without this metric, an error will be raised. The error\n            can be omitted by not providing a metric or by setting the env\n            variable ``TUNE_DISABLE_STRICT_METRIC_CHECKING=0``\n\n    """\n\n    CKPT_FILE_TMPL = "experiment_state-{}.json"\n    VALID_RESUME_TYPES = [True, "LOCAL", "REMOTE", "PROMPT", "ERRORED_ONLY", "AUTO"]\n    RAISE = "RAISE"\n\n    def __init__(\n        self,\n        search_alg: Optional[SearchAlgorithm] = None,\n        scheduler: Optional[TrialScheduler] = None,\n        local_checkpoint_dir: Optional[str] = None,\n        remote_checkpoint_dir: Optional[str] = None,\n        sync_config: Optional[SyncConfig] = None,\n        stopper: Optional[Stopper] = None,\n        resume: Union[str, bool] = False,\n        server_port: Optional[int] = None,\n        fail_fast: bool = False,\n        checkpoint_period: Union[str, int] = None,\n        trial_executor: Optional[RayTrialExecutor] = None,\n        callbacks: Optional[List[Callback]] = None,\n        metric: Optional[str] = None,\n        # Deprecate on next refactor\n        driver_sync_trial_checkpoints: bool = False,\n    ):\n        self._search_alg = search_alg or BasicVariantGenerator()\n        self._scheduler_alg = scheduler or FIFOScheduler()\n        self.trial_executor = trial_executor or RayTrialExecutor()\n        self._insufficient_resources_manager = _InsufficientResourcesManager()\n        self._pending_trial_queue_times = {}\n\n        # Set the number of maximum pending trials\n        max_pending_trials = os.getenv("TUNE_MAX_PENDING_TRIALS_PG", "auto")\n        if max_pending_trials == "auto":\n            # Auto detect\n            if isinstance(self._search_alg, BasicVariantGenerator):\n                # Use a minimum of 16 to trigger fast autoscaling\n                # Scale up to at most the number of available cluster CPUs\n                cluster_cpus = ray.cluster_resources().get("CPU", 1.0)\n                self._max_pending_trials = max(16, int(cluster_cpus * 1.1))\n\n                if self._max_pending_trials > 128:\n                    logger.warning(\n                        f"The maximum number of pending trials has been "\n                        f"automatically set to the number of available "\n                        f"cluster CPUs, which is high "\n                        f"({self._max_pending_trials} CPUs/pending trials). "\n                        f"If you\'re running an experiment with a large number "\n                        f"of trials, this could lead to scheduling overhead. "\n                        f"In this case, consider setting the "\n                        f"`TUNE_MAX_PENDING_TRIALS_PG` environment variable "\n                        f"to the desired maximum number of concurrent trials."\n                    )\n            else:\n                self._max_pending_trials = 1\n        else:\n            # Manual override\n            self._max_pending_trials = int(max_pending_trials)\n\n        sync_config = sync_config or SyncConfig()\n\n        self.trial_executor.setup(\n            max_pending_trials=self._max_pending_trials,\n            trainable_kwargs={"sync_timeout": sync_config.sync_timeout},\n        )\n\n        self._metric = metric\n\n        self._total_time = 0\n        self._iteration = 0\n        self._has_errored = False\n        self._fail_fast = fail_fast\n        if isinstance(self._fail_fast, str):\n            self._fail_fast = self._fail_fast.upper()\n            if self._fail_fast == TrialRunner.RAISE:\n                warnings.warn(\n                    "fail_fast=\'raise\' detected. Be careful when using this "\n                    "mode as resources (such as Ray processes, "\n                    "file descriptors, and temporary files) may not be "\n                    "cleaned up properly. To use "\n                    "a safer mode, use fail_fast=True."\n                )\n            else:\n                raise ValueError(\n                    "fail_fast must be one of {bool, RAISE}. " f"Got {self._fail_fast}."\n                )\n\n        self._print_trial_errors = bool(\n            int(os.environ.get("TUNE_PRINT_ALL_TRIAL_ERRORS", "1"))\n        )\n\n        self._server = None\n        self._server_port = server_port\n        if server_port is not None:\n            self._server = TuneServer(self, self._server_port)\n\n        self._trials = []\n        self._live_trials = set()  # Set of non-terminated trials\n        self._cached_trial_decisions = {}\n        self._queued_trial_decisions = {}\n\n        self._stop_queue = []\n        self._should_stop_experiment = False  # used by TuneServer\n        self._local_checkpoint_dir = local_checkpoint_dir\n\n        if self._local_checkpoint_dir:\n            os.makedirs(self._local_checkpoint_dir, exist_ok=True)\n\n        self._remote_checkpoint_dir = remote_checkpoint_dir\n\n        self._syncer = get_node_to_storage_syncer(sync_config)\n        self._stopper = stopper or NoopStopper()\n        self._resumed = False\n\n        should_resume, resume_config = self._validate_resume(\n            resume_type=resume,\n            driver_sync_trial_checkpoints=driver_sync_trial_checkpoints,\n        )\n\n        if should_resume:\n            try:\n                self.resume(\n                    resume_unfinished=resume_config.resume_unfinished,\n                    resume_errored=resume_config.resume_errored,\n                    restart_errored=resume_config.restart_errored,\n                )\n                self._resumed = True\n            except Exception as e:\n                if has_verbosity(Verbosity.V3_TRIAL_DETAILS):\n                    logger.error(str(e))\n                logger.exception("Runner restore failed.")\n                if self._fail_fast:\n                    raise\n                logger.info("Restarting experiment.")\n        else:\n            logger.debug("Starting a new experiment.")\n\n        self._start_time = time.time()\n        self._last_checkpoint_time = -float("inf")\n\n        self._session_str = datetime.fromtimestamp(self._start_time).strftime(\n            "%Y-%m-%d_%H-%M-%S"\n        )\n        self.checkpoint_file = None\n        if self._local_checkpoint_dir:\n            self.checkpoint_file = os.path.join(\n                self._local_checkpoint_dir,\n                TrialRunner.CKPT_FILE_TMPL.format(self._session_str),\n            )\n\n        self._callbacks = CallbackList(callbacks or [])\n\n        if checkpoint_period is None:\n            checkpoint_period = os.getenv("TUNE_GLOBAL_CHECKPOINT_S", "auto")\n\n        self._checkpoint_period = checkpoint_period\n        self._checkpoint_manager = self._create_checkpoint_manager(\n            driver_sync_trial_checkpoints\n        )\n\n    def setup_experiments(\n        self, experiments: List[Experiment], total_num_samples: int\n    ) -> None:\n        """Obtains any necessary information from experiments.\n\n        Mainly used to setup callbacks.\n\n        Args:\n            experiments: List of Experiments\n                to use.\n            total_num_samples: Total number of samples\n                factoring in grid search samplers.\n        """\n        experiment = experiments[0]\n        spec = experiment.public_spec if experiment else {}\n        spec["total_num_samples"] = total_num_samples\n        self._callbacks.setup(**spec)\n\n    def end_experiment_callbacks(self) -> None:\n        """Calls ``on_experiment_end`` method in callbacks."""\n        self._callbacks.on_experiment_end(trials=self._trials)\n\n    def _create_checkpoint_manager(self, sync_trial_checkpoints: bool = True):\n        return _ExperimentCheckpointManager(\n            checkpoint_dir=self._local_checkpoint_dir,\n            checkpoint_period=self._checkpoint_period,\n            start_time=self._start_time,\n            session_str=self._session_str,\n            syncer=self._syncer,\n            sync_trial_checkpoints=sync_trial_checkpoints,\n            local_dir=self._local_checkpoint_dir,\n            remote_dir=self._remote_checkpoint_dir,\n        )\n\n    @property\n    def resumed(self):\n        return self._resumed\n\n    @property\n    def search_alg(self):\n        return self._search_alg\n\n    @property\n    def scheduler_alg(self):\n        return self._scheduler_alg\n\n    def _validate_resume(\n        self, resume_type: Union[str, bool], driver_sync_trial_checkpoints=True\n    ) -> Tuple[bool, Optional[_ResumeConfig]]:\n        """Checks whether to resume experiment.\n\n        Args:\n            resume_type: One of ["REMOTE", "LOCAL", "PROMPT", "AUTO"]. Can\n                be suffixed with one or more of ["+ERRORED", "+ERRORED_ONLY",\n                "+RESTART_ERRORED", "+RESTART_ERRORED_ONLY"]\n            driver_sync_trial_checkpoints: Boolean indicating if the driver\n                should sync trial checkpoints from the driver node to cloud.\n\n        Returns:\n            Tuple of (should_resume, _ResumeConfig).\n        """\n        if not resume_type:\n            return False, None\n\n        if resume_type is True:\n            resume_type = "LOCAL"\n        elif resume_type == "ERRORED_ONLY":\n            warnings.warn(\n                "Passing `resume=\'ERRORED_ONLY\'` to tune.run() is deprecated and "\n                "will be removed in the future. Please pass e.g. "\n                "`resume=\'LOCAL+RESTART_ERRORED_ONLY\'` instead."\n            )\n            resume_type = "LOCAL+RESTART_ERRORED_ONLY"\n\n        # Parse resume string, e.g. AUTO+ERRORED\n        resume_config = _ResumeConfig()\n        resume_settings = resume_type.split("+")\n        resume_type = resume_settings[0]\n\n        for setting in resume_settings:\n            if setting == "ERRORED":\n                resume_config.resume_errored = True\n            elif setting == "RESTART_ERRORED":\n                resume_config.restart_errored = True\n            elif setting == "ERRORED_ONLY":\n                resume_config.resume_unfinished = False\n                resume_config.restart_errored = False\n                resume_config.resume_errored = True\n            elif setting == "RESTART_ERRORED_ONLY":\n                resume_config.resume_unfinished = False\n                resume_config.restart_errored = True\n                resume_config.resume_errored = False\n\n        assert (\n            resume_type in self.VALID_RESUME_TYPES\n        ), "resume_type {} is not one of {}".format(\n            resume_type, self.VALID_RESUME_TYPES\n        )\n        # Not clear if we need this assertion, since we should always have a\n        # local checkpoint dir.\n        assert self._local_checkpoint_dir or (\n            self._remote_checkpoint_dir and self._syncer\n        )\n\n        if resume_type == "AUTO":\n            if self._remote_checkpoint_dir and self._syncer:\n                logger.info(\n                    f"Trying to find and download experiment checkpoint at "\n                    f"{self._remote_checkpoint_dir}"\n                )\n                # Todo: This syncs the entire experiment including trial\n                # checkpoints. We should exclude these in the future.\n                try:\n                    self._syncer.sync_down_if_needed(\n                        remote_dir=self._remote_checkpoint_dir,\n                        local_dir=self._local_checkpoint_dir,\n                    )\n                    self._syncer.wait()\n                except TuneError as e:\n                    logger.warning(\n                        f"Got error when trying to sync down: {e} "\n                        f"\\nPlease check this error message for potential "\n                        f"access problems - if a directory was not found, "\n                        f"that is expected at this stage when you\'re starting "\n                        f"a new experiment."\n                    )\n                    logger.info(\n                        "No remote checkpoint was found or an error occurred "\n                        "when trying to download the experiment checkpoint. "\n                        "Please check the previous warning message for more "\n                        "details. "\n                        "Ray Tune will now start a new experiment."\n                    )\n                    return False, None\n                if not self.checkpoint_exists(self._local_checkpoint_dir):\n                    logger.warning(\n                        "A remote checkpoint was fetched, but no checkpoint "\n                        "data was found. This can happen when e.g. the cloud "\n                        "bucket exists but does not contain any data. "\n                        "Ray Tune will start a new, fresh run."\n                    )\n                    return False, None\n                logger.info(\n                    "A remote experiment checkpoint was found and will be "\n                    "used to restore the previous experiment state."\n                )\n                return True, resume_config\n            elif not self.checkpoint_exists(self._local_checkpoint_dir):\n                logger.info(\n                    "No local checkpoint was found. "\n                    "Ray Tune will now start a new experiment."\n                )\n                return False, None\n            logger.info(\n                "A local experiment checkpoint was found and will be used "\n                "to restore the previous experiment state."\n            )\n            return True, resume_config\n\n        if resume_type in ["LOCAL", "PROMPT"]:\n            if not self.checkpoint_exists(self._local_checkpoint_dir):\n                raise ValueError(\n                    f"You called resume ({resume_type}) when no checkpoint "\n                    f"exists in local directory "\n                    f"({self._local_checkpoint_dir}). If you want to start "\n                    f\'a new experiment, use `resume="AUTO"` or \'\n                    f"`resume=None`. If you expected an experiment to "\n                    f"already exist, check if you supplied the correct "\n                    f"`local_dir` to `air.RunConfig()`."\n                )\n            elif resume_type == "PROMPT":\n                if click.confirm(\n                    f"Resume from local directory? " f"({self._local_checkpoint_dir})"\n                ):\n                    return True, resume_config\n\n        if resume_type in ["REMOTE", "PROMPT"]:\n            if resume_type == "PROMPT" and not click.confirm(\n                f"Try downloading from remote directory? "\n                f"({self._remote_checkpoint_dir})"\n            ):\n                return False, None\n            if not self._remote_checkpoint_dir or not self._syncer:\n                raise ValueError(\n                    "Called resume from remote without remote directory or "\n                    "without valid syncer. "\n                    "Fix this by passing a `SyncConfig` object with "\n                    "`upload_dir` set to `Tuner(sync_config=...)`."\n                )\n\n            # Try syncing down the upload directory.\n            logger.info(\n                f"Downloading experiment checkpoint from "\n                f"{self._remote_checkpoint_dir}"\n            )\n            if driver_sync_trial_checkpoints:\n                exclude = None\n            else:\n                exclude = ["*/checkpoint_*"]\n\n            try:\n                self._syncer.sync_down_if_needed(\n                    remote_dir=self._remote_checkpoint_dir,\n                    local_dir=self._local_checkpoint_dir,\n                    exclude=exclude,\n                )\n                self._syncer.wait()\n            except TuneError as e:\n                raise RuntimeError(\n                    "Syncing the remote experiment checkpoint to the driver "\n                    "failed. Please check the error message. If you want to "\n                    \'start a new experiment, use `resume="AUTO"` or \'\n                    "`resume=None`. If you expected an experiment to "\n                    "already exist, check if you supplied the correct "\n                    "`upload_dir` to the `tune.SyncConfig` passed to "\n                    "`tune.Tuner()`."\n                ) from e\n\n            if not self.checkpoint_exists(self._local_checkpoint_dir):\n                raise ValueError(\n                    "Called resume when no checkpoint exists "\n                    "in remote or local directory."\n                )\n        return True, resume_config\n\n    @classmethod\n    def checkpoint_exists(cls, directory):\n        if not os.path.exists(directory):\n            return False\n        return any(\n            (fname.startswith("experiment_state") and fname.endswith(".json"))\n            for fname in os.listdir(directory)\n        )\n\n    def checkpoint(self, force: bool = False):\n        """Saves execution state to `self._local_checkpoint_dir`.\n\n        Overwrites the current session checkpoint, which starts when self\n        is instantiated. Throttle depends on self._checkpoint_period.\n\n        Also automatically saves the search algorithm to the local\n        checkpoint dir.\n\n        Args:\n            force: Forces a checkpoint despite checkpoint_period.\n        """\n        with warn_if_slow(\n            "experiment_checkpoint",\n            message="Checkpointing the experiment state took "\n            "{duration:.3f} s, which may be a performance "\n            "bottleneck. Please ensure the "\n            "`TUNE_GLOBAL_CHECKPOINT_S` environment variable is "\n            "something significantly higher than this duration "\n            "to ensure compute time is mostly spent on the main "\n            "training loop.",\n            # No backlog warning if forced checkpoint as we wait\n            # for previous sync to finish.\n            disable=self._checkpoint_manager.auto_checkpoint_enabled or force,\n        ):\n\n            self._checkpoint_manager.checkpoint(\n                checkpoint_file=self.checkpoint_file,\n                trial_runner=self,\n                trial_executor=self.trial_executor,\n                search_alg=self._search_alg,\n                force=force,\n            )\n\n    def resume(\n        self,\n        resume_unfinished: bool = True,\n        resume_errored: bool = False,\n        restart_errored: bool = False,\n    ):\n        """Resumes all checkpointed trials from previous run.\n\n        Requires user to manually re-register their objects. Also stops\n        all ongoing trials.\n        """\n        newest_ckpt_path = _find_newest_experiment_checkpoint(\n            self._local_checkpoint_dir\n        )\n\n        if not newest_ckpt_path:\n            raise ValueError(\n                f"Tried to resume from checkpoint dir "\n                f"`{self._local_checkpoint_dir}`, but no "\n                f"experiment checkpoint data was found."\n            )\n\n        logger.info(f"Using following checkpoint to resume: {newest_ckpt_path}")\n        with open(newest_ckpt_path, "r") as f:\n            runner_state = json.load(f, cls=TuneFunctionDecoder)\n            self.checkpoint_file = newest_ckpt_path\n\n        logger.warning(\n            "".join(\n                [\n                    "Attempting to resume experiment from {}. ".format(\n                        self._local_checkpoint_dir\n                    ),\n                    "This will ignore any new changes to the specification.",\n                ]\n            )\n        )\n\n        self.__setstate__(runner_state["runner_data"])\n        if self._search_alg.has_checkpoint(self._local_checkpoint_dir):\n            self._search_alg.restore_from_dir(self._local_checkpoint_dir)\n\n        trials = _load_trials_from_experiment_checkpoint(runner_state)\n        for trial in sorted(trials, key=lambda t: t.last_update_time, reverse=True):\n            trial_to_add = trial\n            if trial.status == Trial.ERROR:\n                if resume_errored:\n                    trial_to_add = trial.reset()\n                    trial_to_add.restore_path = trial.checkpoint.dir_or_data\n                elif restart_errored:\n                    trial_to_add = trial.reset()\n                    trial_to_add.restore_path = None\n            elif trial.status != Trial.TERMINATED and not resume_unfinished:\n                trial_to_add.status = Trial.TERMINATED\n            self.add_trial(trial_to_add)\n\n    def update_pending_trial_resources(\n        self, resources: Union[dict, PlacementGroupFactory]\n    ):\n        """Update trial resources when resuming from checkpoint.\n\n        Only updating the pending ones.\n        """\n        assert resources\n        if isinstance(resources, dict) and "gpu" not in resources:\n            resources["gpu"] = 0\n        for trial in self._trials:\n            if trial.status == Trial.PENDING:\n                trial.update_resources(resources=resources)\n\n    def is_finished(self):\n        """Returns whether all trials have finished running."""\n        # The checks here are partly redundant but optimized for quick\n        # evaluation. Specifically, if there are live trials, we check\n        # these live trials first. Only if none of the live trials is\n        # live anymore do we loop over all trials for a final check.\n        trials_done = (\n            len(self._live_trials) == 0\n            or all(trial.is_finished() for trial in self._live_trials)\n        ) and all(trial.is_finished() for trial in self._trials)\n        return trials_done and self._search_alg.is_finished()\n\n    def _update_trial_queue_and_get_next_trial(self) -> Optional[Trial]:\n        """Adding suggested trials to the live queue of trials (they start as PENDING trials).\n\n        Returns:\n            next_trial: Trial\n        """\n        wait_for_trial = True  # wait for new trials when all trials are finished\n        num_pending_trials = 0\n        for trial in self._live_trials:\n            if not trial.is_finished():\n                wait_for_trial = False\n                if trial.status == Trial.PENDING:\n                    num_pending_trials += 1\n\n        if not self._search_alg.is_finished():\n            # Create pending trials until it fails.\n            while num_pending_trials < self._max_pending_trials:\n                if not self._update_trial_queue(blocking=wait_for_trial):\n                    break\n                wait_for_trial = False  # wait at most one trial\n                num_pending_trials += 1\n\n        with warn_if_slow("choose_trial_to_run"):\n            return self._scheduler_alg.choose_trial_to_run(self)\n\n    def _wait_and_handle_event(self, next_trial: Optional[Trial]):\n        try:\n            # Single wait of entire tune loop.\n            event = self.trial_executor.get_next_executor_event(\n                self._live_trials, next_trial is not None\n            )\n            if event.type == _ExecutorEventType.PG_READY:\n                self._on_pg_ready(next_trial)\n            elif event.type == _ExecutorEventType.NO_RUNNING_TRIAL_TIMEOUT:\n                self._insufficient_resources_manager.on_no_available_trials(\n                    self.get_trials()\n                )\n            elif event.type == _ExecutorEventType.YIELD:\n                pass\n            else:\n                trial = event.trial\n                result = event.result\n                if event.type == _ExecutorEventType.ERROR:\n                    self._on_executor_error(trial, result[_ExecutorEvent.KEY_EXCEPTION])\n                elif event.type == _ExecutorEventType.RESTORING_RESULT:\n                    self._on_restoring_result(trial)\n                else:\n                    assert event.type in (\n                        _ExecutorEventType.SAVING_RESULT,\n                        _ExecutorEventType.TRAINING_RESULT,\n                    ), f"Unexpected future type - {event.type}"\n                    if event.type == _ExecutorEventType.TRAINING_RESULT:\n                        self._on_training_result(\n                            trial, result[_ExecutorEvent.KEY_FUTURE_RESULT]\n                        )\n                    else:\n                        self._on_saving_result(\n                            trial, result[_ExecutorEvent.KEY_FUTURE_RESULT]\n                        )\n                    self._post_process_on_training_saving_result(trial)\n        except Exception as e:\n            if e is TuneError or self._fail_fast == TrialRunner.RAISE:\n                raise e\n            else:\n                raise TuneError(traceback.format_exc())\n\n    def step(self):\n        """Runs one step of the trial event loop.\n\n        Callers should typically run this method repeatedly in a loop. They\n        may inspect or modify the runner\'s state in between calls to step().\n        """\n        if self.is_finished():\n            raise TuneError("Called step when all trials finished?")\n        with warn_if_slow("on_step_begin"):\n            self.trial_executor.on_step_begin(self.get_trials())\n        with warn_if_slow("callbacks.on_step_begin"):\n            self._callbacks.on_step_begin(\n                iteration=self._iteration, trials=self._trials\n            )\n\n        next_trial = self._update_trial_queue_and_get_next_trial()\n        if next_trial:\n            logger.debug(f"Got new trial to run: {next_trial}")\n\n        self._wait_and_handle_event(next_trial)\n\n        self._stop_experiment_if_needed()\n\n        try:\n            self.checkpoint()\n        except Exception as e:\n            logger.warning(f"Trial Runner checkpointing failed: {str(e)}")\n        self._iteration += 1\n\n        if self._server:\n            with warn_if_slow("server"):\n                self._process_stop_requests()\n\n            if self.is_finished():\n                self._server.shutdown()\n\n        self._reconcile_live_trials()\n\n        with warn_if_slow("on_step_end"):\n            self.trial_executor.on_step_end(self.get_trials())\n        with warn_if_slow("callbacks.on_step_end"):\n            self._callbacks.on_step_end(iteration=self._iteration, trials=self._trials)\n\n    def _on_pg_ready(self, next_trial: Optional[Trial]):\n        def _start_trial(trial: Trial) -> bool:\n            """Helper function to start trial and call callbacks"""\n            with warn_if_slow("start_trial"):\n                if self.trial_executor.start_trial(trial):\n                    self._callbacks.on_trial_start(\n                        iteration=self._iteration, trials=self._trials, trial=trial\n                    )\n                    return True\n                return False\n\n        assert next_trial is not None\n        logger.debug(f"Trying to start trial: {next_trial}")\n        if not _start_trial(next_trial) and next_trial.status != Trial.ERROR:\n            # Only try to start another trial if previous trial startup\n            # did not error (e.g. it just didn\'t start because its\n            # placement group is not ready, yet).\n            # Without this clause, this test fails:\n            # test_trial_runner_pg.py::\n            # TrialRunnerPlacementGroupHeterogeneousTest::\n            # testResourceDeadlock\n            next_trial = self.trial_executor.get_staged_trial()\n            if next_trial is not None:\n                # Must be able to start.\n                assert _start_trial(next_trial)\n            else:\n                logger.debug(f"Reconciling resource requests: {self.get_trials()}")\n                self.trial_executor._pg_manager.reconcile_placement_groups(\n                    self.get_trials()\n                )\n\n    def _on_saving_result(self, trial, checkpoint_value: Union[ray.ObjectRef, str]):\n        with warn_if_slow("process_trial_save") as _profile:\n            self._process_trial_save(trial, checkpoint_value)\n        with warn_if_slow("callbacks.on_trial_save"):\n            self._callbacks.on_trial_save(\n                iteration=self._iteration, trials=self._trials, trial=trial\n            )\n        if _profile.too_slow and trial.sync_on_checkpoint:\n            # TODO(ujvl): Suggest using cloud checkpointing once\n            #  API has converged.\n\n            msg = (\n                "Consider turning off forced head-worker trial "\n                "checkpoint syncs by setting sync_on_checkpoint=False"\n                ". Note that this may result in faulty trial "\n                "restoration if a failure occurs while the checkpoint "\n                "is being synced from the worker to the head node."\n            )\n\n            if trial.location.hostname and (\n                trial.location.hostname != get_node_ip_address()\n            ):\n                if log_once("tune_head_worker_checkpoint"):\n                    logger.warning(msg)\n\n    def _on_restoring_result(self, trial):\n        with warn_if_slow("process_trial_restore"):\n            self._process_trial_restore(trial)\n        with warn_if_slow("callbacks.on_trial_restore"):\n            self._callbacks.on_trial_restore(\n                iteration=self._iteration, trials=self._trials, trial=trial\n            )\n\n    def _on_training_result(self, trial, result):\n        if not isinstance(result, list):\n            result = [result]\n        with warn_if_slow("process_trial_result"):\n            self._process_trial_results(trial, result)\n\n    def _post_process_on_training_saving_result(self, trial):\n        # `self._queued_trial_decisions` now contains a final decision\n        # based on all results\n        if trial not in self._cached_trial_decisions:\n            final_decision = self._queued_trial_decisions.pop(trial.trial_id, None)\n            if final_decision:\n                self._execute_action(trial, final_decision)\n\n    def _on_executor_error(self, trial, e: Union[RayTaskError, TuneError]):\n        error_msg = f"Trial {trial}: Error processing event."\n        if self._fail_fast == TrialRunner.RAISE:\n            raise e\n        else:\n            if self._print_trial_errors:\n                logger.error(error_msg, exc_info=e)\n            self._process_trial_failure(trial, exc=e)\n\n    def get_trial(self, tid):\n        trial = [t for t in self._trials if t.trial_id == tid]\n        return trial[0] if trial else None\n\n    def get_trials(self):\n        """Returns the list of trials managed by this TrialRunner.\n\n        Note that the caller usually should not mutate trial state directly.\n        """\n        return self._trials\n\n    def get_live_trials(self):\n        """Returns the set of trials that are not in Trial.TERMINATED state."""\n        return self._live_trials\n\n    def add_trial(self, trial: Trial):\n        """Adds a new trial to this TrialRunner.\n\n        Trials may be added at any time.\n\n        Args:\n            trial: Trial to queue.\n        """\n        self._trials.append(trial)\n        if trial.status != Trial.TERMINATED:\n            self._live_trials.add(trial)\n        with warn_if_slow("scheduler.on_trial_add"):\n            self._scheduler_alg.on_trial_add(\n                TrialRunnerWrapper(self, runner_whitelist_attr={"search_alg"}), trial\n            )\n        self.trial_executor.mark_trial_to_checkpoint(trial)\n\n    def debug_string(self, delim="\\n"):\n        from ray.tune.progress_reporter import _trial_progress_str\n\n        result_keys = [list(t.last_result) for t in self.get_trials() if t.last_result]\n        metrics = set().union(*result_keys)\n        messages = [\n            self._scheduler_alg.debug_string(),\n            self.trial_executor.debug_string(),\n            _trial_progress_str(self.get_trials(), metrics, force_table=True),\n        ]\n        return delim.join(messages)\n\n    def _stop_experiment_if_needed(self):\n        """Stops all trials."""\n        fail_fast = self._fail_fast and self._has_errored\n        if self._stopper.stop_all() or fail_fast or self._should_stop_experiment:\n            self._search_alg.set_finished()\n            [\n                self.trial_executor.stop_trial(t)\n                for t in self._trials\n                if t.status is not Trial.ERROR\n            ]\n\n    def _process_trial_results(self, trial, results):\n        logger.debug(f"Processing trial results for trial {trial}: {results}")\n        with warn_if_slow(\n            "process_trial_results",\n            message="Processing trial results took {duration:.3f} s, "\n            "which may be a performance bottleneck. Please consider "\n            "reporting results less frequently to Ray Tune.",\n        ):\n            for i, result in enumerate(results):\n                with warn_if_slow("process_trial_result"):\n                    decision = self._process_trial_result(trial, result)\n                if decision is None:\n                    # If we didn\'t get a decision, this means a\n                    # non-training future (e.g. a save) was scheduled.\n                    # We do not allow processing more results then.\n                    if i < len(results) - 1:\n                        if log_once("trial_runner_buffer_checkpoint"):\n                            logger.warning(\n                                f"Trial {trial} has a non-training future "\n                                f"scheduled but {len(results) - i} results "\n                                f"left to process. This means that a "\n                                f"checkpoint was requested, but buffered "\n                                f"training was continued before it was "\n                                f"saved. Consider using non-buffered "\n                                f"training by setting the env variable "\n                                f"`TUNE_RESULT_BUFFER_LENGTH=1`."\n                            )\n                elif decision == TrialScheduler.STOP:\n                    # If the decision is to stop the trial,\n                    # ignore all results that came after that.\n                    break\n\n    def _process_trial_result(self, trial, result):\n        result.update(trial_id=trial.trial_id)\n        is_duplicate = RESULT_DUPLICATE in result\n        force_checkpoint = result.get(SHOULD_CHECKPOINT, False)\n        # TrialScheduler and SearchAlgorithm still receive a\n        # notification because there may be special handling for\n        # the `on_trial_complete` hook.\n        if is_duplicate:\n            logger.debug("Trial finished without logging \'done\'.")\n            result = trial.last_result\n            result.update(done=True)\n\n        self._total_time += result.get(TIME_THIS_ITER_S, 0)\n\n        flat_result = flatten_dict(result)\n        self._validate_result_metrics(flat_result)\n\n        if self._stopper(trial.trial_id, result) or trial.should_stop(flat_result):\n            decision = TrialScheduler.STOP\n        else:\n            with warn_if_slow("scheduler.on_trial_result"):\n                decision = self._scheduler_alg.on_trial_result(self, trial, flat_result)\n        if decision == TrialScheduler.STOP:\n            result.update(done=True)\n        else:\n            # Only updating search alg if the trial is not to be stopped.\n            with warn_if_slow("search_alg.on_trial_result"):\n                self._search_alg.on_trial_result(trial.trial_id, flat_result)\n\n        # If this is not a duplicate result, the callbacks should\n        # be informed about the result.\n        if not is_duplicate:\n            with warn_if_slow("callbacks.on_trial_result"):\n                self._callbacks.on_trial_result(\n                    iteration=self._iteration,\n                    trials=self._trials,\n                    trial=trial,\n                    result=result.copy(),\n                )\n            trial.update_last_result(result)\n            # Include in next experiment checkpoint\n            self.trial_executor.mark_trial_to_checkpoint(trial)\n\n        # Checkpoints to disk. This should be checked even if\n        # the scheduler decision is STOP or PAUSE. Note that\n        # PAUSE only checkpoints to memory and does not update\n        # the global checkpoint state.\n        self._checkpoint_trial_if_needed(trial, force=force_checkpoint)\n\n        if trial.is_saving:\n            logger.debug(f"Caching trial decision for trial {trial}: {decision}")\n            # Cache decision to execute on after the save is processed.\n            # This prevents changing the trial\'s state or kicking off\n            # another training step prematurely.\n            self._cached_trial_decisions[trial.trial_id] = decision\n            return None\n        else:\n            self._queue_decision(trial, decision)\n            return decision\n\n    def _validate_result_metrics(self, result):\n        """\n        Check if any of the required metrics was not reported\n        in the last result. If the only items are ``done`` or any of\n        DEBUG_METRICS, this means that no result was ever received and\n        the trial just returned. This is also okay and will not raise\n        an error.\n\n        This will ignore checking for the DEFAULT_METRIC.\n        """\n        if int(os.environ.get("TUNE_DISABLE_STRICT_METRIC_CHECKING", 0)) != 1 and (\n            len({k for k in result if k not in list(DEBUG_METRICS) + [DONE]}) > 1\n        ):\n            base_metric = self._metric if self._metric != DEFAULT_METRIC else None\n            scheduler_metric = (\n                self._scheduler_alg.metric\n                if self._scheduler_alg.metric != DEFAULT_METRIC\n                else None\n            )\n            search_metrics = (\n                self._search_alg.metric\n                if self._search_alg.metric != DEFAULT_METRIC\n                else None\n            )\n\n            if isinstance(search_metrics, str):\n                search_metrics = [search_metrics]\n\n            if base_metric and base_metric not in result:\n                report_metric = base_metric\n                location = "tune.TuneConfig()"\n            elif scheduler_metric and scheduler_metric not in result:\n                report_metric = scheduler_metric\n                location = type(self._scheduler_alg).__name__\n            elif search_metrics and any(\n                search_metric not in result for search_metric in search_metrics\n            ):\n                report_metric = list(\n                    filter(\n                        lambda search_metric: search_metric not in result,\n                        search_metrics,\n                    )\n                )\n                if len(report_metric) == 1:\n                    report_metric = report_metric[0]\n                location = type(self._search_alg).__name__\n            else:\n                report_metric = None\n                location = None\n\n            if report_metric:\n                raise ValueError(\n                    "Trial returned a result which did not include the "\n                    "specified metric(s) `{}` that `{}` expects. "\n                    "Make sure your calls to `tune.report()` include the "\n                    "metric, or set the "\n                    "TUNE_DISABLE_STRICT_METRIC_CHECKING "\n                    "environment variable to 1. Result: {}".format(\n                        report_metric, location, result\n                    )\n                )\n\n    def _process_trial_save(\n        self, trial: Trial, checkpoint_value: Union[ray.ObjectRef, str]\n    ):\n        """Processes a trial save.\n\n        Acts on the decision cached during the last `_process_trial` call.\n\n        Args:\n            trial: Trial being saved.\n        """\n        logger.debug("Trial %s: Processing trial save.", trial)\n\n        try:\n            trial.saving_to.dir_or_data = checkpoint_value\n            self._callbacks.on_checkpoint(\n                iteration=self._iteration,\n                trials=self._trials,\n                trial=trial,\n                checkpoint=trial.saving_to,\n            )\n            trial.on_checkpoint(trial.saving_to)\n            if trial.checkpoint.storage_mode != CheckpointStorage.MEMORY:\n                self.trial_executor.mark_trial_to_checkpoint(trial)\n        except Exception:\n            logger.exception(\n                "Trial %s: Error handling checkpoint %s", trial, checkpoint_value\n            )\n            if self._fail_fast == TrialRunner.RAISE:\n                raise\n\n        trial.saving_to = None\n        decision = self._cached_trial_decisions.pop(trial.trial_id, None)\n        if decision and checkpoint_value:\n            self._queue_decision(trial, decision)\n\n    def _process_trial_restore(self, trial: Trial):\n        """Processes a trial restore.\n\n        Args:\n            trial: Trial being restored.\n        """\n        logger.debug("Trial %s: Processing trial restore.", trial)\n        trial.on_restore()\n        logger.debug("Trial %s: Restore processed successfully", trial)\n        self.trial_executor.set_status(trial, Trial.RUNNING)\n        self.trial_executor.continue_training(trial)\n        self._live_trials.add(trial)\n\n    def _process_trial_failure(\n        self, trial: Trial, exc: Optional[Union[TuneError, RayTaskError]] = None\n    ):\n        """Handle trial failure.\n\n        Attempt trial recovery if possible, clean up state otherwise.\n\n        Args:\n            trial: Failed trial.\n            exc: Exception prior to invoking this method.\n        """\n        self._has_errored = True\n        if trial.status == Trial.RUNNING:\n            if trial.should_recover():\n                self._try_recover(trial, exc=exc)\n            else:\n                self._scheduler_alg.on_trial_error(self, trial)\n                self._search_alg.on_trial_complete(trial.trial_id, error=True)\n                self._callbacks.on_trial_error(\n                    iteration=self._iteration, trials=self._trials, trial=trial\n                )\n                self.trial_executor.stop_trial(trial, exc=exc)\n\n    def _queue_decision(self, trial, decision):\n        # Get old decision, setting it to the current decision if it isn\'t set\n        old_decision = self._queued_trial_decisions.setdefault(trial.trial_id, decision)\n\n        # Stopping always takes precedence. If we decided to stop, just quit\n        if old_decision is TrialScheduler.STOP:\n            return\n\n        # The old decision wasn\'t STOP. We update the decision only if it is\n        # STOP or PAUSE. The action will only be CONTINUE if it was set by\n        # the first received result and was never updated after that.\n        if decision is TrialScheduler.STOP or decision is TrialScheduler.PAUSE:\n            self._queued_trial_decisions[trial.trial_id] = decision\n\n    def _execute_action(self, trial: Trial, decision: str):\n        """Executes action based on decision.\n\n        Args:\n            trial: Trial to act on.\n            decision: Scheduling decision to undertake.\n        """\n        if decision == TrialScheduler.CONTINUE:\n            self.trial_executor.continue_training(trial)\n        elif decision == TrialScheduler.PAUSE:\n            self.trial_executor.pause_trial(trial)\n        elif decision == TrialScheduler.STOP:\n            self.stop_trial(trial)\n        elif decision == TrialScheduler.NOOP:\n            pass\n        else:\n            raise ValueError("Invalid decision: {}".format(decision))\n\n    def _checkpoint_trial_if_needed(self, trial, force=False):\n        """Checkpoints trial based off trial.last_result."""\n        if trial.should_checkpoint() or force:\n            # Save trial runtime if possible.\n            if trial.runner:\n                self.trial_executor.save(trial, storage=CheckpointStorage.PERSISTENT)\n\n    def _try_recover(self, trial: Trial, exc: Union[TuneError, RayTaskError]):\n        """Tries to recover trial.\n\n        Notifies SearchAlgorithm and Scheduler if failure to recover.\n\n        Args:\n            trial: Trial to recover.\n            exc: Exception prior to invoking this method.\n        """\n        self._cached_trial_decisions.pop(trial.trial_id, None)\n        # Resetting this, in case that the trial is in saving status when it crashes.\n        if trial.is_saving:\n            trial.saving_to = None\n        if trial.is_restoring:\n            # Restore was unsuccessful, try again without checkpoint.\n            trial.clear_checkpoint()\n        self.trial_executor.stop_trial(trial, error=exc is not None, exc=exc)\n        if self.trial_executor.has_resources_for_trial(trial):\n            requeue_trial = False\n            logger.info(\n                "Trial %s: Attempting to restore trial state from last checkpoint.",\n                trial,\n            )\n            # TODO(xwjiang): For better consistency, consider not starting\n            #  trials here. Instead rely on requeuing the trial.\n            started = self.trial_executor.start_trial(trial)\n            if not started:\n                requeue_trial = True\n            elif trial.status == Trial.ERROR:\n                logger.exception(\n                    "Trial %s: Error restoring trial from checkpoint, abort.", trial\n                )\n                if started:\n                    # Clean up again if an actor was launched\n                    self.trial_executor.stop_trial(trial, error=True)\n                self._scheduler_alg.on_trial_error(self, trial)\n                self._search_alg.on_trial_complete(trial.trial_id, error=True)\n                self._callbacks.on_trial_error(\n                    iteration=self._iteration, trials=self._trials, trial=trial\n                )\n            else:\n                logger.debug("Trial %s: Restore dispatched correctly.", trial)\n        else:\n            requeue_trial = True\n\n        if requeue_trial:\n            logger.debug("Trial %s: Notifying Scheduler and requeueing.", trial)\n            self._requeue_trial(trial)\n\n    def _requeue_trial(self, trial):\n        """Notification to TrialScheduler and requeue trial.\n\n        This does not notify the SearchAlgorithm because the function\n        evaluation is still in progress.\n\n        """\n        self._scheduler_alg.on_trial_error(self, trial)\n        self.trial_executor.set_status(trial, Trial.PENDING)\n\n        # TODO(rliaw): Right now, this pushes the trial to the end of queue\n        # because restoration can be expensive. However, this is not\n        # ideal since it just hides the issue - a better fix would\n        # be to use an actor table to detect the IP of the Trainable\n        # and rsync the files there.\n        # See https://github.com/ray-project/ray/issues/5168\n        self._trials.pop(self._trials.index(trial))\n        self._trials.append(trial)\n        self._live_trials.add(trial)\n\n        with warn_if_slow("scheduler.on_trial_add"):\n            self._scheduler_alg.on_trial_add(\n                TrialRunnerWrapper(self, runner_whitelist_attr={"search_alg"}), trial\n            )\n\n    def _update_trial_queue(self, blocking: bool = False, timeout: int = 600) -> bool:\n        """Adds next trials to queue if possible.\n\n        Note that the timeout is currently unexposed to the user.\n\n        Args:\n            blocking: Blocks until either a trial is available\n                or is_finished (timeout or search algorithm finishes).\n            timeout: Seconds before blocking times out.\n\n        Returns:\n            Boolean indicating if a new trial was created or not.\n        """\n        trial = self._search_alg.next_trial()\n        if blocking and not trial:\n            start = time.time()\n            # Checking `is_finished` instead of _search_alg.is_finished\n            # is fine because blocking only occurs if all trials are\n            # finished and search_algorithm is not yet finished\n            while (\n                not trial and not self.is_finished() and time.time() - start < timeout\n            ):\n                logger.debug("Blocking for next trial...")\n                trial = self._search_alg.next_trial()\n                time.sleep(1)\n\n        if trial:\n            self.add_trial(trial)\n            return True\n\n        return False\n\n    def request_stop_trial(self, trial):\n        self._stop_queue.append(trial)\n\n    def request_stop_experiment(self):\n        self._should_stop_experiment = True\n\n    def _process_stop_requests(self):\n        while self._stop_queue:\n            t = self._stop_queue.pop()\n            self.stop_trial(t)\n\n    def stop_trial(self, trial):\n        """The canonical implementation of stopping a trial.\n\n        Trials may be in any external status when this function is called.\n        If trial is in state PENDING or PAUSED, calls `on_trial_remove` for\n        scheduler and `on_trial_complete()` for search_alg.\n        If trial is in state RUNNING, calls `on_trial_complete` for scheduler\n        and search_alg if RUNNING. Caller to ensure that there is no\n        outstanding future to be handled for the trial. If there is, the future\n        would be discarded.\n        """\n        try:\n            if trial.status in [Trial.ERROR, Trial.TERMINATED]:\n                return\n            elif trial.status in [Trial.PENDING, Trial.PAUSED]:\n                self._scheduler_alg.on_trial_remove(self, trial)\n                self._search_alg.on_trial_complete(trial.trial_id)\n            elif trial.status is Trial.RUNNING:\n                # By this time trial.last_result should have been\n                # updated already.\n                self._scheduler_alg.on_trial_complete(\n                    self, trial, flatten_dict(trial.last_result)\n                )\n                self._search_alg.on_trial_complete(\n                    trial.trial_id, result=flatten_dict(trial.last_result)\n                )\n            self._callbacks.on_trial_complete(\n                iteration=self._iteration, trials=self._trials, trial=trial\n            )\n            self.trial_executor.export_trial_if_needed(trial)\n            self.trial_executor.stop_trial(trial)\n            self._live_trials.discard(trial)\n        except Exception as e:\n            logger.exception("Trial %s: Error stopping trial.", trial)\n            if self._fail_fast == TrialRunner.RAISE:\n                raise\n            if isinstance(e, TuneError):\n                self._process_trial_failure(trial, exc=e)\n            else:\n                self._process_trial_failure(\n                    trial, _TuneStopTrialError(traceback.format_exc())\n                )\n\n    def cleanup_trials(self):\n        self.trial_executor.cleanup(self.get_trials())\n\n    def cleanup(self):\n        """Cleanup trials and callbacks."""\n        self.cleanup_trials()\n        self.end_experiment_callbacks()\n\n    def _reconcile_live_trials(self):\n        """Loop through live trials and remove if terminated"""\n        for trial in list(self._live_trials):\n            # Only for TERMINATED trials. ERRORed trials might be retried.\n            if trial.status == Trial.TERMINATED:\n                self._live_trials.remove(trial)\n\n    def __getstate__(self):\n        """Gets state for trial.\n\n        Note that this is not used as a pickling override as\n        does not have all fields.\n        """\n        state = self.__dict__.copy()\n        for k in [\n            "_trials",\n            "_live_trials",\n            "_stop_queue",\n            "_server",\n            "_search_alg",\n            "_scheduler_alg",\n            "_pending_trial_queue_times",\n            "trial_executor",\n            "_syncer",\n            "_callbacks",\n            "_checkpoint_manager",\n        ]:\n            del state[k]\n        state["launch_web_server"] = bool(self._server)\n        return state\n\n    def __setstate__(self, state):\n        launch_web_server = state.pop("launch_web_server")\n\n        # Use session_str from previous checkpoint if does not exist\n        session_str = state.pop("_session_str")\n        self.__dict__.setdefault("_session_str", session_str)\n        # Use start_time from previous checkpoint if does not exist\n        start_time = state.pop("_start_time")\n        self.__dict__.setdefault("_start_time", start_time)\n\n        self.__dict__.update(state)\n        self._checkpoint_manager = self._create_checkpoint_manager()\n\n        if launch_web_server:\n            self._server = TuneServer(self, self._server_port)\n\n\nclass _TrialExecutorWrapper(RayTrialExecutor):\n    """Wraps around TrialExecutor class, intercepts API calls and warns users\n    of restricted API access.\n\n    This is meant to facilitate restricting\n    the current API exposure of TrialExecutor by TrialScheduler.\n    """\n\n    def __init__(\n        self, trial_executor: RayTrialExecutor, whitelist_attr: Optional[set] = None\n    ):\n        self._trial_executor = trial_executor\n        self._whitelist_attr = whitelist_attr or set()\n\n    def __getattr__(self, attr):\n        if attr not in self._whitelist_attr:\n            if log_once("restrict_accessing_trial_executor"):\n                logger.warning(\n                    f"You are trying to access {attr} interface of "\n                    f"TrialExecutor in TrialScheduler, which is being "\n                    f"restricted. If you believe it is reasonable for "\n                    f"your scheduler to access this TrialExecutor API, "\n                    f"please reach out to Ray team on GitHub. A more "\n                    f"strict API access pattern would be enforced "\n                    f"starting 1.12.0"\n                )\n        return getattr(self._trial_executor, attr)\n\n\n@DeveloperAPI\nclass TrialRunnerWrapper(TrialRunner):\n    """Wraps around TrialRunner class, intercepts API calls and warns users\n    of restricted API access.\n\n    This is meant to facilitate restricting\n    the current API exposure of TrialRunner by TrialScheduler.\n    """\n\n    _EXECUTOR_ATTR = "trial_executor"\n\n    def __init__(\n        self,\n        trial_runner: TrialRunner,\n        runner_whitelist_attr: Optional[set] = None,\n        executor_whitelist_attr: Optional[set] = None,\n    ):\n        self._trial_runner = trial_runner\n        self._trial_executor = _TrialExecutorWrapper(\n            trial_runner.trial_executor, executor_whitelist_attr\n        )\n        self._runner_whitelist_attr = runner_whitelist_attr or set()\n\n    def __getattr__(self, attr):\n        if attr == self._EXECUTOR_ATTR:\n            return self._trial_executor\n        if attr not in self._runner_whitelist_attr:\n            if log_once("restrict_accessing_trial_runner"):\n                logger.warning(\n                    f"You are trying to access {attr} interface of "\n                    f"TrialRunner in TrialScheduler, which is being "\n                    f"restricted. If you believe it is reasonable for "\n                    f"your scheduler to access this TrialRunner API, "\n                    f"please reach out to Ray team on GitHub. A more "\n                    f"strict API access pattern would be enforced "\n                    f"starting 1.12s.0"\n                )\n        return getattr(self._trial_runner, attr)\n',
            'python/ray/tune/schedulers/pbt.py': 'import copy\nimport json\nimport logging\nimport math\nimport os\nimport random\nimport shutil\nfrom typing import Callable, Dict, List, Optional, Tuple, Union\n\nfrom ray.air._internal.checkpoint_manager import CheckpointStorage\nfrom ray.tune.execution import trial_runner\nfrom ray.tune.error import TuneError\nfrom ray.tune.result import DEFAULT_METRIC, TRAINING_ITERATION\nfrom ray.tune.search import SearchGenerator\nfrom ray.tune.utils.util import SafeFallbackEncoder\nfrom ray.tune.search.sample import Domain, Function\nfrom ray.tune.schedulers import FIFOScheduler, TrialScheduler\nfrom ray.tune.search.variant_generator import format_vars\nfrom ray.tune.experiment import Trial\nfrom ray.util import PublicAPI\nfrom ray.util.debug import log_once\n\nlogger = logging.getLogger(__name__)\n\n\nclass _PBTTrialState:\n    """Internal PBT state tracked per-trial."""\n\n    def __init__(self, trial: Trial):\n        self.orig_tag = trial.experiment_tag\n        self.last_score = None\n        self.last_checkpoint = None\n        self.last_perturbation_time = 0\n        self.last_train_time = 0  # Used for synchronous mode.\n        self.last_result = None  # Used for synchronous mode.\n\n    def __repr__(self) -> str:\n        return str(\n            (\n                self.last_score,\n                self.last_checkpoint,\n                self.last_train_time,\n                self.last_perturbation_time,\n            )\n        )\n\n\ndef _explore(\n    config: Dict,\n    mutations: Dict,\n    resample_probability: float,\n    custom_explore_fn: Optional[Callable],\n) -> Dict:\n    """Return a config perturbed as specified.\n\n    Args:\n        config: Original hyperparameter configuration.\n        mutations: Specification of mutations to perform as documented\n            in the PopulationBasedTraining scheduler.\n        resample_probability: Probability of allowing resampling of a\n            particular variable.\n        custom_explore_fn: Custom explore fn applied after built-in\n            config perturbations are.\n    """\n    new_config = copy.deepcopy(config)\n    for key, distribution in mutations.items():\n        if isinstance(distribution, dict):\n            new_config.update(\n                {key: _explore(config[key], mutations[key], resample_probability, None)}\n            )\n        elif isinstance(distribution, list):\n            if (\n                random.random() < resample_probability\n                or config[key] not in distribution\n            ):\n                new_config[key] = random.choice(distribution)\n            elif random.random() > 0.5:\n                new_config[key] = distribution[\n                    max(0, distribution.index(config[key]) - 1)\n                ]\n            else:\n                new_config[key] = distribution[\n                    min(len(distribution) - 1, distribution.index(config[key]) + 1)\n                ]\n        else:\n            if random.random() < resample_probability:\n                new_config[key] = (\n                    distribution.sample(None)\n                    if isinstance(distribution, Domain)\n                    else distribution()\n                )\n            elif random.random() > 0.5:\n                new_config[key] = config[key] * 1.2\n            else:\n                new_config[key] = config[key] * 0.8\n            if isinstance(config[key], int):\n                new_config[key] = int(new_config[key])\n    if custom_explore_fn:\n        new_config = custom_explore_fn(new_config)\n        assert new_config is not None, "Custom explore fn failed to return new config"\n    return new_config\n\n\ndef _make_experiment_tag(orig_tag: str, config: Dict, mutations: Dict) -> str:\n    """Appends perturbed params to the trial name to show in the console."""\n\n    resolved_vars = {}\n    for k in mutations.keys():\n        resolved_vars[("config", k)] = config[k]\n    return "{}@perturbed[{}]".format(orig_tag, format_vars(resolved_vars))\n\n\ndef _fill_config(\n    config: Dict, attr: str, search_space: Union[Callable, Domain, list, dict]\n):\n    """Add attr to config by sampling from search_space."""\n    if callable(search_space):\n        config[attr] = search_space()\n    elif isinstance(search_space, Domain):\n        config[attr] = search_space.sample(None)\n    elif isinstance(search_space, list):\n        config[attr] = random.choice(search_space)\n    elif isinstance(search_space, dict):\n        config[attr] = {}\n        for k, v in search_space.items():\n            _fill_config(config[attr], k, v)\n\n\n@PublicAPI\nclass PopulationBasedTraining(FIFOScheduler):\n    """Implements the Population Based Training (PBT) algorithm.\n\n    https://www.deepmind.com/blog/population-based-training-of-neural-networks\n\n    PBT trains a group of models (or agents) in parallel. Periodically, poorly\n    performing models clone the state of the top performers, and a random\n    mutation is applied to their hyperparameters in the hopes of\n    outperforming the current top models.\n\n    Unlike other hyperparameter search algorithms, PBT mutates hyperparameters\n    during training time. This enables very fast hyperparameter discovery and\n    also automatically discovers good annealing schedules.\n\n    This Tune PBT implementation considers all trials added as part of the\n    PBT population. If the number of trials exceeds the cluster capacity,\n    they will be time-multiplexed as to balance training progress across the\n    population. To run multiple trials, use `tune.TuneConfig(num_samples=<int>)`.\n\n    In {LOG_DIR}/{MY_EXPERIMENT_NAME}/, all mutations are logged in\n    `pbt_global.txt` and individual policy perturbations are recorded\n    in pbt_policy_{i}.txt. Tune logs: [target trial tag, clone trial tag,\n    target trial iteration, clone trial iteration, old config, new config]\n    on each perturbation step.\n\n    Args:\n        time_attr: The training result attr to use for comparing time.\n            Note that you can pass in something non-temporal such as\n            `training_iteration` as a measure of progress, the only requirement\n            is that the attribute should increase monotonically.\n        metric: The training result objective value attribute. Stopping\n            procedures will use this attribute. If None but a mode was passed,\n            the `ray.tune.result.DEFAULT_METRIC` will be used per default.\n        mode: One of {min, max}. Determines whether objective is\n            minimizing or maximizing the metric attribute.\n        perturbation_interval: Models will be considered for\n            perturbation at this interval of `time_attr`. Note that\n            perturbation incurs checkpoint overhead, so you shouldn\'t set this\n            to be too frequent.\n        burn_in_period: Models will not be considered for\n            perturbation before this interval of `time_attr` has passed. This\n            guarantees that models are trained for at least a certain amount\n            of time or timesteps before being perturbed.\n        hyperparam_mutations: Hyperparams to mutate. The format is\n            as follows: for each key, either a list, function,\n            or a tune search space object (tune.loguniform, tune.uniform,\n            etc.) can be provided. A list specifies an allowed set of\n            categorical values. A function or tune search space object\n            specifies the distribution of a continuous parameter. You must\n            use tune.choice, tune.uniform, tune.loguniform, etc.. Arbitrary\n            tune.sample_from objects are not supported.\n            You must specify at least one of `hyperparam_mutations` or\n            `custom_explore_fn`.\n            Tune will use the search space provided by\n            `hyperparam_mutations` for the initial samples if the\n            corresponding attributes are not present in `config`.\n        quantile_fraction: Parameters are transferred from the top\n            `quantile_fraction` fraction of trials to the bottom\n            `quantile_fraction` fraction. Needs to be between 0 and 0.5.\n            Setting it to 0 essentially implies doing no exploitation at all.\n        resample_probability: The probability of resampling from the\n            original distribution when applying `hyperparam_mutations`. If not\n            resampled, the value will be perturbed by a factor of 1.2 or 0.8\n            if continuous, or changed to an adjacent value if discrete.\n        custom_explore_fn: You can also specify a custom exploration\n            function. This function is invoked as `f(config)` after built-in\n            perturbations from `hyperparam_mutations` are applied, and should\n            return `config` updated as needed. You must specify at least one of\n            `hyperparam_mutations` or `custom_explore_fn`.\n        log_config: Whether to log the ray config of each model to\n            local_dir at each exploit. Allows config schedule to be\n            reconstructed.\n        require_attrs: Whether to require time_attr and metric to appear\n            in result for every iteration. If True, error will be raised\n            if these values are not present in trial result.\n        synch: If False, will use asynchronous implementation of\n            PBT. Trial perturbations occur every perturbation_interval for each\n            trial independently. If True, will use synchronous implementation\n            of PBT. Perturbations will occur only after all trials are\n            synced at the same time_attr every perturbation_interval.\n            Defaults to False. See Appendix A.1 here\n            https://arxiv.org/pdf/1711.09846.pdf.\n\n    .. code-block:: python\n\n        import random\n        from ray import tune\n        from ray.tune.schedulers import PopulationBasedTraining\n\n        pbt = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="episode_reward_mean",\n            mode="max",\n            perturbation_interval=10,  # every 10 `time_attr` units\n                                       # (training_iterations in this case)\n            hyperparam_mutations={\n                # Perturb factor1 by scaling it by 0.8 or 1.2. Resampling\n                # resets it to a value sampled from the lambda function.\n                "factor_1": lambda: random.uniform(0.0, 20.0),\n                # Alternatively, use tune search space primitives.\n                # The search space for factor_1 is equivalent to factor_2.\n                "factor_2": tune.uniform(0.0, 20.0),\n                # Perturb factor3 by changing it to an adjacent value, e.g.\n                # 10 -> 1 or 10 -> 100. Resampling will choose at random.\n                "factor_3": [1, 10, 100, 1000, 10000],\n                # Using tune.choice is NOT equivalent to the above.\n                # factor_4 is treated as a continuous hyperparameter.\n                "factor_4": tune.choice([1, 10, 100, 1000, 10000]),\n            })\n        tuner = tune.Tuner(\n            trainable,\n            tune_config=tune.TuneConfig(\n                scheduler=pbt,\n                num_samples=8,\n            ),\n        )\n        tuner.fit()\n\n    """\n\n    def __init__(\n        self,\n        time_attr: str = "time_total_s",\n        metric: Optional[str] = None,\n        mode: Optional[str] = None,\n        perturbation_interval: float = 60.0,\n        burn_in_period: float = 0.0,\n        hyperparam_mutations: Dict = None,\n        quantile_fraction: float = 0.25,\n        resample_probability: float = 0.25,\n        custom_explore_fn: Optional[Callable] = None,\n        log_config: bool = True,\n        require_attrs: bool = True,\n        synch: bool = False,\n    ):\n        hyperparam_mutations = hyperparam_mutations or {}\n        for value in hyperparam_mutations.values():\n            if not (isinstance(value, (list, dict, Domain)) or callable(value)):\n                raise TypeError(\n                    "`hyperparam_mutation` values must be either "\n                    "a List, Dict, a tune search space object, or "\n                    "a callable."\n                )\n            if isinstance(value, Function):\n                raise ValueError(\n                    "arbitrary tune.sample_from objects are not "\n                    "supported for `hyperparam_mutation` values."\n                    "You must use other built in primitives like"\n                    "tune.uniform, tune.loguniform, etc."\n                )\n\n            if not hyperparam_mutations and not custom_explore_fn:\n                raise TuneError(\n                    "You must specify at least one of `hyperparam_mutations` "\n                    "or `custom_explore_fn` to use PBT."\n                )\n\n        if quantile_fraction > 0.5 or quantile_fraction < 0:\n            raise ValueError(\n                "You must set `quantile_fraction` to a value between 0 and"\n                "0.5. Current value: \'{}\'".format(quantile_fraction)\n            )\n\n        if perturbation_interval <= 0:\n            raise ValueError(\n                "perturbation_interval must be a positive number greater "\n                "than 0. Current value: \'{}\'".format(perturbation_interval)\n            )\n\n        if mode:\n            assert mode in ["min", "max"], "`mode` must be \'min\' or \'max\'."\n\n        FIFOScheduler.__init__(self)\n        self._metric = metric\n        self._mode = mode\n        self._metric_op = None\n        if self._mode == "max":\n            self._metric_op = 1.0\n        elif self._mode == "min":\n            self._metric_op = -1.0\n        self._time_attr = time_attr\n        self._perturbation_interval = perturbation_interval\n        self._burn_in_period = burn_in_period\n        self._hyperparam_mutations = hyperparam_mutations\n        self._quantile_fraction = quantile_fraction\n        self._resample_probability = resample_probability\n        self._trial_state = {}\n        self._custom_explore_fn = custom_explore_fn\n        self._log_config = log_config\n        self._require_attrs = require_attrs\n        self._synch = synch\n        self._next_perturbation_sync = max(\n            self._perturbation_interval,\n            self._burn_in_period,\n        )\n\n        # Metrics\n        self._num_checkpoints = 0\n        self._num_perturbations = 0\n\n    def set_search_properties(\n        self, metric: Optional[str], mode: Optional[str], **spec\n    ) -> bool:\n        if self._metric and metric:\n            return False\n        if self._mode and mode:\n            return False\n\n        if metric:\n            self._metric = metric\n        if mode:\n            self._mode = mode\n\n        if self._mode == "max":\n            self._metric_op = 1.0\n        elif self._mode == "min":\n            self._metric_op = -1.0\n\n        if self._metric is None and self._mode:\n            # If only a mode was passed, use anonymous metric\n            self._metric = DEFAULT_METRIC\n\n        return True\n\n    def on_trial_add(self, trial_runner: "trial_runner.TrialRunner", trial: Trial):\n        if trial_runner.search_alg is not None and isinstance(\n            trial_runner.search_alg, SearchGenerator\n        ):\n            raise ValueError(\n                "Search algorithms cannot be used with {} "\n                "schedulers. Please remove {}.".format(\n                    self.__class__.__name__, trial_runner.search_alg\n                )\n            )\n\n        if not self._metric or not self._metric_op:\n            raise ValueError(\n                "{} has been instantiated without a valid `metric` ({}) or "\n                "`mode` ({}) parameter. Either pass these parameters when "\n                "instantiating the scheduler, or pass them as parameters "\n                "to `tune.TuneConfig()`".format(\n                    self.__class__.__name__, self._metric, self._mode\n                )\n            )\n\n        self._trial_state[trial] = _PBTTrialState(trial)\n\n        for attr in self._hyperparam_mutations.keys():\n            if attr not in trial.config:\n                if log_once(attr + "-missing"):\n                    logger.debug(\n                        "Cannot find {} in config. Using search "\n                        "space provided by hyperparam_mutations."\n                    )\n                # Add attr to trial\'s config by sampling search space from\n                # hyperparam_mutations.\n                _fill_config(trial.config, attr, self._hyperparam_mutations[attr])\n                # Make sure this attribute is added to CLI output.\n                trial.evaluated_params[attr] = trial.config[attr]\n\n    def on_trial_result(\n        self, trial_runner: "trial_runner.TrialRunner", trial: Trial, result: Dict\n    ) -> str:\n        if self._time_attr not in result:\n            time_missing_msg = (\n                "Cannot find time_attr {} "\n                "in trial result {}. Make sure that this "\n                "attribute is returned in the "\n                "results of your Trainable.".format(self._time_attr, result)\n            )\n            if self._require_attrs:\n                raise RuntimeError(\n                    time_missing_msg\n                    + "If this error is expected, you can change this to "\n                    "a warning message by "\n                    "setting PBT(require_attrs=False)"\n                )\n            else:\n                if log_once("pbt-time_attr-error"):\n                    logger.warning(time_missing_msg)\n        if self._metric not in result:\n            metric_missing_msg = (\n                "Cannot find metric {} in trial result {}. "\n                "Make sure that this attribute is returned "\n                "in the "\n                "results of your Trainable.".format(self._metric, result)\n            )\n            if self._require_attrs:\n                raise RuntimeError(\n                    metric_missing_msg + "If this error is expected, "\n                    "you can change this to a warning message by "\n                    "setting PBT(require_attrs=False)"\n                )\n            else:\n                if log_once("pbt-metric-error"):\n                    logger.warning(metric_missing_msg)\n\n        if self._metric not in result or self._time_attr not in result:\n            return TrialScheduler.CONTINUE\n\n        time = result[self._time_attr]\n        state = self._trial_state[trial]\n\n        # Continue training if burn-in period has not been reached, yet.\n        if time < self._burn_in_period:\n            return TrialScheduler.CONTINUE\n\n        # Continue training if perturbation interval has not been reached, yet.\n        if time - state.last_perturbation_time < self._perturbation_interval:\n            return TrialScheduler.CONTINUE  # avoid checkpoint overhead\n\n        self._save_trial_state(state, time, result, trial)\n\n        if not self._synch:\n            state.last_perturbation_time = time\n            lower_quantile, upper_quantile = self._quantiles()\n            decision = TrialScheduler.CONTINUE\n            for other_trial in trial_runner.get_trials():\n                if other_trial.status in [Trial.PENDING, Trial.PAUSED]:\n                    decision = TrialScheduler.PAUSE\n                    break\n            self._checkpoint_or_exploit(\n                trial, trial_runner.trial_executor, upper_quantile, lower_quantile\n            )\n            return TrialScheduler.NOOP if trial.status == Trial.PAUSED else decision\n        else:\n            # Synchronous mode.\n            if any(\n                self._trial_state[t].last_train_time < self._next_perturbation_sync\n                and t != trial\n                for t in trial_runner.get_live_trials()\n            ):\n                logger.debug("Pausing trial {}".format(trial))\n            else:\n                # All trials are synced at the same timestep.\n                lower_quantile, upper_quantile = self._quantiles()\n                all_trials = trial_runner.get_trials()\n                not_in_quantile = []\n                for t in all_trials:\n                    if t not in lower_quantile and t not in upper_quantile:\n                        not_in_quantile.append(t)\n                # Move upper quantile trials to beginning and lower quantile\n                # to end. This ensures that checkpointing of strong trials\n                # occurs before exploiting of weaker ones.\n                all_trials = upper_quantile + not_in_quantile + lower_quantile\n                for t in all_trials:\n                    logger.debug("Perturbing Trial {}".format(t))\n                    self._trial_state[t].last_perturbation_time = time\n                    self._checkpoint_or_exploit(\n                        t, trial_runner.trial_executor, upper_quantile, lower_quantile\n                    )\n\n                all_train_times = [\n                    self._trial_state[t].last_train_time\n                    for t in trial_runner.get_trials()\n                ]\n                max_last_train_time = max(all_train_times)\n                self._next_perturbation_sync = max(\n                    self._next_perturbation_sync + self._perturbation_interval,\n                    max_last_train_time,\n                )\n            # In sync mode we should pause all trials once result comes in.\n            # Once a perturbation step happens for all trials, they should\n            # still all be paused.\n            # choose_trial_to_run will then pick the next trial to run out of\n            # the paused trials.\n            return (\n                TrialScheduler.NOOP\n                if trial.status == Trial.PAUSED\n                else TrialScheduler.PAUSE\n            )\n\n    def _save_trial_state(\n        self, state: _PBTTrialState, time: int, result: Dict, trial: Trial\n    ):\n        """Saves necessary trial information when result is received.\n        Args:\n            state: The state object for the trial.\n            time: The current timestep of the trial.\n            result: The trial\'s result dictionary.\n            trial: The trial object.\n        """\n\n        # This trial has reached its perturbation interval.\n        # Record new state in the state object.\n        score = self._metric_op * result[self._metric]\n        state.last_score = score\n        state.last_train_time = time\n        state.last_result = result\n\n        return score\n\n    def _checkpoint_or_exploit(\n        self,\n        trial: Trial,\n        trial_executor: "trial_runner.RayTrialExecutor",\n        upper_quantile: List[Trial],\n        lower_quantile: List[Trial],\n    ):\n        """Checkpoint if in upper quantile, exploits if in lower."""\n        state = self._trial_state[trial]\n        if trial in upper_quantile:\n            # The trial last result is only updated after the scheduler\n            # callback. So, we override with the current result.\n            logger.debug("Trial {} is in upper quantile".format(trial))\n            logger.debug("Checkpointing {}".format(trial))\n            if trial.status == Trial.PAUSED:\n                # Paused trial will always have an in-memory checkpoint.\n                state.last_checkpoint = trial.checkpoint\n            else:\n                state.last_checkpoint = trial_executor.save(\n                    trial, CheckpointStorage.MEMORY, result=state.last_result\n                )\n            self._num_checkpoints += 1\n        else:\n            state.last_checkpoint = None  # not a top trial\n\n        if trial in lower_quantile:\n            logger.debug("Trial {} is in lower quantile".format(trial))\n            trial_to_clone = random.choice(upper_quantile)\n            assert trial is not trial_to_clone\n            if not self._trial_state[trial_to_clone].last_checkpoint:\n                logger.info(\n                    "[pbt]: no checkpoint for trial."\n                    " Skip exploit for Trial {}".format(trial)\n                )\n                return\n            self._exploit(trial_executor, trial, trial_to_clone)\n\n    def _log_config_on_step(\n        self,\n        trial_state: _PBTTrialState,\n        new_state: _PBTTrialState,\n        trial: Trial,\n        trial_to_clone: Trial,\n        new_config: Dict,\n    ):\n        """Logs transition during exploit/exploit step.\n\n        For each step, logs: [target trial tag, clone trial tag, target trial\n        iteration, clone trial iteration, old config, new config].\n        """\n        trial_name, trial_to_clone_name = (trial_state.orig_tag, new_state.orig_tag)\n        trial_id = trial.trial_id\n        trial_to_clone_id = trial_to_clone.trial_id\n        trial_path = os.path.join(trial.local_dir, "pbt_policy_" + trial_id + ".txt")\n        trial_to_clone_path = os.path.join(\n            trial_to_clone.local_dir, "pbt_policy_" + trial_to_clone_id + ".txt"\n        )\n        policy = [\n            trial_name,\n            trial_to_clone_name,\n            trial.last_result.get(TRAINING_ITERATION, 0),\n            trial_to_clone.last_result.get(TRAINING_ITERATION, 0),\n            trial_to_clone.config,\n            new_config,\n        ]\n        # Log to global file.\n        with open(os.path.join(trial.local_dir, "pbt_global.txt"), "a+") as f:\n            print(json.dumps(policy, cls=SafeFallbackEncoder), file=f)\n        # Overwrite state in target trial from trial_to_clone.\n        if os.path.exists(trial_to_clone_path):\n            shutil.copyfile(trial_to_clone_path, trial_path)\n        # Log new exploit in target trial log.\n        with open(trial_path, "a+") as f:\n            f.write(json.dumps(policy, cls=SafeFallbackEncoder) + "\\n")\n\n    def _get_new_config(self, trial, trial_to_clone):\n        """Gets new config for trial by exploring trial_to_clone\'s config."""\n        return _explore(\n            trial_to_clone.config,\n            self._hyperparam_mutations,\n            self._resample_probability,\n            self._custom_explore_fn,\n        )\n\n    def _exploit(\n        self,\n        trial_executor: "trial_runner.RayTrialExecutor",\n        trial: Trial,\n        trial_to_clone: Trial,\n    ):\n        """Transfers perturbed state from trial_to_clone -> trial.\n\n        If specified, also logs the updated hyperparam state.\n        """\n        trial_state = self._trial_state[trial]\n        new_state = self._trial_state[trial_to_clone]\n        logger.info(\n            "[exploit] transferring weights from trial "\n            "{} (score {}) -> {} (score {})".format(\n                trial_to_clone, new_state.last_score, trial, trial_state.last_score\n            )\n        )\n\n        new_config = self._get_new_config(trial, trial_to_clone)\n\n        # Only log mutated hyperparameters and not entire config.\n        old_hparams = {\n            k: v\n            for k, v in trial_to_clone.config.items()\n            if k in self._hyperparam_mutations\n        }\n        new_hparams = {\n            k: v for k, v in new_config.items() if k in self._hyperparam_mutations\n        }\n        logger.info(\n            "[explore] perturbed config from {} -> {}".format(old_hparams, new_hparams)\n        )\n\n        if self._log_config:\n            self._log_config_on_step(\n                trial_state, new_state, trial, trial_to_clone, new_config\n            )\n\n        new_tag = _make_experiment_tag(\n            trial_state.orig_tag, new_config, self._hyperparam_mutations\n        )\n        if trial.status == Trial.PAUSED:\n            # If trial is paused we update it with a new checkpoint.\n            # When the trial is started again, the new checkpoint is used.\n            if not self._synch:\n                raise TuneError(\n                    "Trials should be paused here only if in "\n                    "synchronous mode. If you encounter this error"\n                    " please raise an issue on Ray Github."\n                )\n        else:\n            trial_executor.stop_trial(trial)\n            trial_executor.set_status(trial, Trial.PAUSED)\n        trial.set_experiment_tag(new_tag)\n        trial.set_config(new_config)\n        trial.on_checkpoint(new_state.last_checkpoint)\n\n        self._num_perturbations += 1\n        # Transfer over the last perturbation time as well\n        trial_state.last_perturbation_time = new_state.last_perturbation_time\n        trial_state.last_train_time = new_state.last_train_time\n\n    def _quantiles(self) -> Tuple[List[Trial], List[Trial]]:\n        """Returns trials in the lower and upper `quantile` of the population.\n\n        If there is not enough data to compute this, returns empty lists.\n        """\n        trials = []\n        for trial, state in self._trial_state.items():\n            logger.debug("Trial {}, state {}".format(trial, state))\n            if trial.is_finished():\n                logger.debug("Trial {} is finished".format(trial))\n            if state.last_score is not None and not trial.is_finished():\n                trials.append(trial)\n        trials.sort(key=lambda t: self._trial_state[t].last_score)\n\n        if len(trials) <= 1:\n            return [], []\n        else:\n            num_trials_in_quantile = int(\n                math.ceil(len(trials) * self._quantile_fraction)\n            )\n            if num_trials_in_quantile > len(trials) / 2:\n                num_trials_in_quantile = int(math.floor(len(trials) / 2))\n            return (trials[:num_trials_in_quantile], trials[-num_trials_in_quantile:])\n\n    def choose_trial_to_run(\n        self, trial_runner: "trial_runner.TrialRunner"\n    ) -> Optional[Trial]:\n        """Ensures all trials get fair share of time (as defined by time_attr).\n\n        This enables the PBT scheduler to support a greater number of\n        concurrent trials than can fit in the cluster at any given time.\n        """\n        candidates = []\n        for trial in trial_runner.get_trials():\n            if (\n                trial.status\n                in [\n                    Trial.PENDING,\n                    Trial.PAUSED,\n                ]\n                and trial_runner.trial_executor.has_resources_for_trial(trial)\n            ):\n                if not self._synch:\n                    candidates.append(trial)\n                elif (\n                    self._trial_state[trial].last_train_time\n                    < self._next_perturbation_sync\n                ):\n                    candidates.append(trial)\n        candidates.sort(key=lambda trial: self._trial_state[trial].last_train_time)\n        return candidates[0] if candidates else None\n\n    # Unit test only. TODO(xwjiang): Remove test-specific APIs.\n    def reset_stats(self):\n        self._num_perturbations = 0\n        self._num_checkpoints = 0\n\n    # Unit test only. TODO(xwjiang): Remove test-specific APIs.\n    def last_scores(self, trials: List[Trial]) -> List[float]:\n        scores = []\n        for trial in trials:\n            state = self._trial_state[trial]\n            if state.last_score is not None and not trial.is_finished():\n                scores.append(state.last_score)\n        return scores\n\n    def debug_string(self) -> str:\n        return "PopulationBasedTraining: {} checkpoints, {} perturbs".format(\n            self._num_checkpoints, self._num_perturbations\n        )\n\n\n@PublicAPI\nclass PopulationBasedTrainingReplay(FIFOScheduler):\n    """Replays a Population Based Training run.\n\n    Population Based Training does not return a single hyperparameter\n    configuration, but rather a schedule of configurations. For instance,\n    PBT might discover that a larger learning rate leads to good results\n    in the first training iterations, but that a smaller learning rate\n    is preferable later.\n\n    This scheduler enables replaying these parameter schedules from\n    a finished PBT run. This requires that population based training has\n    been run with ``log_config=True``, which is the default setting.\n\n    The scheduler will only accept and train a single trial. It will\n    start with the initial config of the existing trial and update the\n    config according to the schedule.\n\n    Args:\n        policy_file: The PBT policy file. Usually this is\n            stored in ``~/ray_results/experiment_name/pbt_policy_xxx.txt``\n            where ``xxx`` is the trial ID.\n\n    Example:\n\n    .. code-block:: python\n\n        # Replaying a result from ray.tune.examples.pbt_convnet_example\n        from ray import air, tune\n\n        from ray.tune.examples.pbt_convnet_example import PytorchTrainable\n        from ray.tune.schedulers import PopulationBasedTrainingReplay\n\n        replay = PopulationBasedTrainingReplay(\n            "~/ray_results/pbt_test/pbt_policy_XXXXX_00001.txt")\n\n        tuner = tune.Tuner(\n            PytorchTrainable,\n            run_config=air.RunConfig(\n                stop={"training_iteration": 100}\n            ),\n            tune_config=tune.TuneConfig(\n                scheduler=replay,\n            ),\n        )\n        tuner.fit()\n\n\n    """\n\n    def __init__(self, policy_file: str):\n        policy_file = os.path.expanduser(policy_file)\n        if not os.path.exists(policy_file):\n            raise ValueError("Policy file not found: {}".format(policy_file))\n\n        self.policy_file = policy_file\n\n        # Find and read pbt policy file, potentially raise error\n        initial_config, self._policy = self._load_policy(self.policy_file)\n\n        self.experiment_tag = "replay_{}".format(os.path.basename(self.policy_file))\n        self.config = initial_config\n        self.current_config = self.config\n\n        self._trial = None\n        self._current_step = 0\n        self._num_perturbations = 0\n\n        self._policy_iter = iter(self._policy)\n        self._next_policy = next(self._policy_iter, None)\n\n    def _load_policy(self, policy_file: str) -> Tuple[Dict, List[Tuple[int, Dict]]]:\n        raw_policy = []\n        with open(policy_file, "rt") as fp:\n            for row in fp.readlines():\n                try:\n                    parsed_row = json.loads(row)\n                except json.JSONDecodeError:\n                    raise ValueError(\n                        "Could not read PBT policy file: {}.".format(policy_file)\n                    ) from None\n                raw_policy.append(tuple(parsed_row))\n\n        # Loop through policy from end to start to obtain changepoints\n        policy = []\n        last_new_tag = None\n        last_old_conf = None\n        for (old_tag, new_tag, old_step, new_step, old_conf, new_conf) in reversed(\n            raw_policy\n        ):\n            if last_new_tag and old_tag != last_new_tag:\n                # Tag chain ended. This means that previous changes were\n                # overwritten by the last change and should be ignored.\n                break\n            last_new_tag = new_tag\n            last_old_conf = old_conf\n\n            policy.append((new_step, new_conf))\n\n        return last_old_conf, list(reversed(policy))\n\n    def on_trial_add(self, trial_runner: "trial_runner.TrialRunner", trial: Trial):\n        if self._trial:\n            raise ValueError(\n                "More than one trial added to PBT replay run. This "\n                "means the same schedule will be trained multiple "\n                "times. Do you want to set `n_samples=1`?"\n            )\n        self._trial = trial\n        if self._trial.config and self._policy:\n            logger.warning(\n                "Trial was initialized with a config, which was overwritten. "\n                "Did you start the PBT replay with a `config` parameter?"\n            )\n        elif self._trial.config and not self._policy:\n            # Only train with initial policy\n            self.config = self._trial.config\n        elif not self._trial.config and not self._policy:\n            raise ValueError(\n                "No replay policy found and trial initialized without a "\n                "valid config. Either pass a `config` argument to `tune.Tuner()`"\n                "or consider not using PBT replay for this run."\n            )\n        self._trial.set_config(self.config)\n\n    def on_trial_result(\n        self, trial_runner: "trial_runner.TrialRunner", trial: Trial, result: Dict\n    ) -> str:\n        if TRAINING_ITERATION not in result:\n            # No time reported\n            return TrialScheduler.CONTINUE\n\n        if not self._next_policy:\n            # No more changes in the config\n            return TrialScheduler.CONTINUE\n\n        step = result[TRAINING_ITERATION]\n        self._current_step = step\n\n        change_at, new_config = self._next_policy\n\n        if step < change_at:\n            # Don\'t change the policy just yet\n            return TrialScheduler.CONTINUE\n\n        logger.info(\n            "Population Based Training replay is now at step {}. "\n            "Configuration will be changed to {}.".format(step, new_config)\n        )\n\n        checkpoint = trial_runner.trial_executor.save(\n            trial, CheckpointStorage.MEMORY, result=result\n        )\n\n        new_tag = _make_experiment_tag(self.experiment_tag, new_config, new_config)\n\n        trial_executor = trial_runner.trial_executor\n        trial_executor.stop_trial(trial)\n        trial_executor.set_status(trial, Trial.PAUSED)\n        trial.set_experiment_tag(new_tag)\n        trial.set_config(new_config)\n        trial.on_checkpoint(checkpoint)\n\n        self.current_config = new_config\n        self._num_perturbations += 1\n        self._next_policy = next(self._policy_iter, None)\n\n        return TrialScheduler.NOOP\n\n    def debug_string(self) -> str:\n        return "PopulationBasedTraining replay: Step {}, perturb {}".format(\n            self._current_step, self._num_perturbations\n        )\n',
            'python/ray/tune/tests/test_trial_scheduler.py': 'from collections import Counter\nimport os\nimport json\nimport random\nimport unittest\nimport time\n\nimport numpy as np\nimport sys\nimport tempfile\nimport shutil\nfrom unittest.mock import MagicMock\n\nimport ray\nfrom ray import tune\nfrom ray.air._internal.checkpoint_manager import _TrackedCheckpoint, CheckpointStorage\nfrom ray.tune import Trainable\nfrom ray.tune.execution.ray_trial_executor import RayTrialExecutor\nfrom ray.tune.result import TRAINING_ITERATION\nfrom ray.tune.schedulers import (\n    FIFOScheduler,\n    HyperBandScheduler,\n    AsyncHyperBandScheduler,\n    PopulationBasedTraining,\n    MedianStoppingRule,\n    TrialScheduler,\n    HyperBandForBOHB,\n)\n\nfrom ray.tune.schedulers.pbt import _explore, PopulationBasedTrainingReplay\nfrom ray.tune.search._mock import _MockSearcher\nfrom ray.tune.search import ConcurrencyLimiter\nfrom ray.tune.experiment import Trial\nfrom ray.tune.resources import Resources\n\nfrom ray.rllib import _register_all\n\n_register_all()\n\n\ndef result(t, rew):\n    return dict(time_total_s=t, episode_reward_mean=rew, training_iteration=int(t))\n\n\ndef mock_trial_runner(trials=None):\n    trial_runner = MagicMock()\n    trial_runner.get_trials.return_value = trials or []\n    return trial_runner\n\n\nclass EarlyStoppingSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def basicSetup(self, rule):\n        t1 = Trial("PPO")  # mean is 450, max 900, t_max=10\n        t2 = Trial("PPO")  # mean is 450, max 450, t_max=5\n        runner = mock_trial_runner()\n        for i in range(10):\n            r1 = result(i, i * 100)\n            print("basicSetup:", i)\n            self.assertEqual(\n                rule.on_trial_result(runner, t1, r1), TrialScheduler.CONTINUE\n            )\n        for i in range(5):\n            r2 = result(i, 450)\n            self.assertEqual(\n                rule.on_trial_result(runner, t2, r2), TrialScheduler.CONTINUE\n            )\n        return t1, t2\n\n    def testMedianStoppingConstantPerf(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=1,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(5, 450)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(6, 0)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(10, 450)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingOnCompleteOnly(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=1,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(100, 0)), TrialScheduler.CONTINUE\n        )\n        rule.on_trial_complete(runner, t1, result(101, 1000))\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(101, 0)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingGracePeriod(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=2.5,\n            min_samples_required=1,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        rule.on_trial_complete(runner, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(1, 10)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(2, 10)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(3, 10)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingMinSamples(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=2,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        t3 = Trial("PPO")\n        # Insufficient samples to evaluate t3\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(5, 10)), TrialScheduler.CONTINUE\n        )\n        rule.on_trial_complete(runner, t2, result(5, 1000))\n        # Sufficient samples to evaluate t3\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(5, 10)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingUsesMedian(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=1,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        rule.on_trial_complete(runner, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(1, 260)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(2, 260)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingSoftStop(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=1,\n            hard_stop=False,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        rule.on_trial_complete(runner, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(1, 260)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(2, 260)), TrialScheduler.PAUSE\n        )\n\n    def _test_metrics(self, result_func, metric, mode):\n        rule = MedianStoppingRule(\n            grace_period=0,\n            min_samples_required=1,\n            time_attr="training_iteration",\n            metric=metric,\n            mode=mode,\n        )\n        t1 = Trial("PPO")  # mean is 450, max 900, t_max=10\n        t2 = Trial("PPO")  # mean is 450, max 450, t_max=5\n        runner = mock_trial_runner()\n        for i in range(10):\n            self.assertEqual(\n                rule.on_trial_result(runner, t1, result_func(i, i * 100)),\n                TrialScheduler.CONTINUE,\n            )\n        for i in range(5):\n            self.assertEqual(\n                rule.on_trial_result(runner, t2, result_func(i, 450)),\n                TrialScheduler.CONTINUE,\n            )\n        rule.on_trial_complete(runner, t1, result_func(10, 1000))\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result_func(5, 450)),\n            TrialScheduler.CONTINUE,\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result_func(6, 0)), TrialScheduler.CONTINUE\n        )\n\n    def testAlternateMetrics(self):\n        def result2(t, rew):\n            return dict(training_iteration=t, neg_mean_loss=rew)\n\n        self._test_metrics(result2, "neg_mean_loss", "max")\n\n    def testAlternateMetricsMin(self):\n        def result2(t, rew):\n            return dict(training_iteration=t, mean_loss=-rew)\n\n        self._test_metrics(result2, "mean_loss", "min")\n\n\n# Only barebone impl for start/stop_trial. No internal state maintained.\nclass _MockTrialExecutor(RayTrialExecutor):\n    def start_trial(self, trial, checkpoint_obj=None, train=True):\n        trial.logger_running = True\n        trial.restored_checkpoint = checkpoint_obj.dir_or_data\n        trial.status = Trial.RUNNING\n        return True\n\n    def stop_trial(self, trial, error=False, error_msg=None):\n        trial.status = Trial.ERROR if error else Trial.TERMINATED\n\n    def restore(self, trial, checkpoint=None, block=False):\n        pass\n\n    def save(self, trial, type=CheckpointStorage.PERSISTENT, result=None):\n        return _TrackedCheckpoint(\n            dir_or_data=trial.trainable_name,\n            storage_mode=CheckpointStorage.PERSISTENT,\n            metrics=result,\n        )\n\n    def reset_trial(self, trial, new_config, new_experiment_tag):\n        return False\n\n    def debug_string(self):\n        return "This is a mock TrialExecutor."\n\n    def export_trial_if_needed(self):\n        return {}\n\n    def fetch_result(self):\n        return []\n\n    def get_next_available_trial(self):\n        return None\n\n    def get_running_trials(self):\n        return []\n\n    def has_resources_for_trial(self, trial: Trial):\n        return True\n\n\nclass _MockTrialRunner:\n    def __init__(self, scheduler):\n        self._scheduler_alg = scheduler\n        self.search_alg = None\n        self.trials = []\n        self.trial_executor = _MockTrialExecutor()\n\n    def process_action(self, trial, action):\n        if action == TrialScheduler.CONTINUE:\n            pass\n        elif action == TrialScheduler.PAUSE:\n            self._pause_trial(trial)\n        elif action == TrialScheduler.STOP:\n            self.trial_executor.stop_trial(trial)\n\n    def stop_trial(self, trial):\n        if trial.status in [Trial.ERROR, Trial.TERMINATED]:\n            return\n        elif trial.status in [Trial.PENDING, Trial.PAUSED]:\n            self._scheduler_alg.on_trial_remove(self, trial)\n        else:\n            self._scheduler_alg.on_trial_complete(self, trial, result(100, 10))\n\n    def add_trial(self, trial):\n        self.trials.append(trial)\n        self._scheduler_alg.on_trial_add(self, trial)\n\n    def get_trials(self):\n        return self.trials\n\n    def get_live_trials(self):\n        return {t for t in self.trials if t.status != Trial.TERMINATED}\n\n    def _pause_trial(self, trial):\n        self.trial_executor.save(trial, CheckpointStorage.MEMORY, None)\n        trial.status = Trial.PAUSED\n\n    def _launch_trial(self, trial):\n        trial.status = Trial.RUNNING\n\n\nclass HyperbandSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(object_store_memory=int(1e8))\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def schedulerSetup(self, num_trials, max_t=81):\n        """Setup a scheduler and Runner with max Iter = 9.\n\n        Bracketing is placed as follows:\n        (5, 81);\n        (8, 27) -> (3, 54);\n        (15, 9) -> (5, 27) -> (2, 45);\n        (34, 3) -> (12, 9) -> (4, 27) -> (2, 42);\n        (81, 1) -> (27, 3) -> (9, 9) -> (3, 27) -> (1, 41);"""\n        sched = HyperBandScheduler(\n            metric="episode_reward_mean", mode="max", max_t=max_t\n        )\n        for i in range(num_trials):\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n        runner = _MockTrialRunner(sched)\n        return sched, runner\n\n    def default_statistics(self):\n        """Default statistics for HyperBand."""\n        sched = HyperBandScheduler()\n        res = {\n            str(s): {"n": sched._get_n0(s), "r": sched._get_r0(s)}  # noqa\n            for s in range(sched._s_max_1)\n        }\n        res["max_trials"] = sum(v["n"] for v in res.values())\n        res["brack_count"] = sched._s_max_1\n        res["s_max"] = sched._s_max_1 - 1\n        return res\n\n    def downscale(self, n, sched):\n        return int(np.ceil(n / sched._eta))\n\n    def basicSetup(self):\n        """Setup and verify full band."""\n\n        stats = self.default_statistics()\n        sched, _ = self.schedulerSetup(stats["max_trials"])\n\n        self.assertEqual(len(sched._hyperbands), 1)\n        self.assertEqual(sched._cur_band_filled(), True)\n\n        filled_band = sched._hyperbands[0]\n        for bracket in filled_band:\n            self.assertEqual(bracket.filled(), True)\n        return sched\n\n    def advancedSetup(self):\n        sched = self.basicSetup()\n        for i in range(4):\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n\n        self.assertEqual(sched._cur_band_filled(), False)\n\n        unfilled_band = sched._hyperbands[-1]\n        self.assertEqual(len(unfilled_band), 2)\n        bracket = unfilled_band[-1]\n        self.assertEqual(bracket.filled(), False)\n        self.assertEqual(len(bracket.current_trials()), 7)\n\n        return sched\n\n    def testConfigSameEta(self):\n        sched = HyperBandScheduler(metric="episode_reward_mean", mode="max")\n        i = 0\n        while not sched._cur_band_filled():\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n            i += 1\n        self.assertEqual(len(sched._hyperbands[0]), 5)\n        self.assertEqual(sched._hyperbands[0][0]._n, 5)\n        self.assertEqual(sched._hyperbands[0][0]._r, 81)\n        self.assertEqual(sched._hyperbands[0][-1]._n, 81)\n        self.assertEqual(sched._hyperbands[0][-1]._r, 1)\n\n        reduction_factor = 10\n        sched = HyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            max_t=1000,\n            reduction_factor=reduction_factor,\n        )\n        i = 0\n        while not sched._cur_band_filled():\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n            i += 1\n        self.assertEqual(len(sched._hyperbands[0]), 4)\n        self.assertEqual(sched._hyperbands[0][0]._n, 4)\n        self.assertEqual(sched._hyperbands[0][0]._r, 1000)\n        self.assertEqual(sched._hyperbands[0][-1]._n, 1000)\n        self.assertEqual(sched._hyperbands[0][-1]._r, 1)\n\n    def testConfigSameEtaSmall(self):\n        sched = HyperBandScheduler(metric="episode_reward_mean", mode="max", max_t=1)\n        i = 0\n        while len(sched._hyperbands) < 2:\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n            i += 1\n        self.assertEqual(len(sched._hyperbands[0]), 1)\n\n    def testSuccessiveHalving(self):\n        """Setup full band, then iterate through last bracket (n=81)\n        to make sure successive halving is correct."""\n\n        stats = self.default_statistics()\n        sched, mock_runner = self.schedulerSetup(stats["max_trials"])\n        big_bracket = sched._state["bracket"]\n        cur_units = stats[str(stats["s_max"])]["r"]\n        # The last bracket will downscale 4 times\n        for x in range(stats["brack_count"] - 1):\n            trials = big_bracket.current_trials()\n            current_length = len(trials)\n            for trl in trials:\n                mock_runner._launch_trial(trl)\n\n            # Provides results from 0 to 8 in order, keeping last one running\n            for i, trl in enumerate(trials):\n                action = sched.on_trial_result(mock_runner, trl, result(cur_units, i))\n                if i < current_length - 1:\n                    self.assertEqual(action, TrialScheduler.PAUSE)\n                mock_runner.process_action(trl, action)\n\n            self.assertEqual(action, TrialScheduler.CONTINUE)\n            new_length = len(big_bracket.current_trials())\n            self.assertEqual(new_length, self.downscale(current_length, sched))\n            cur_units = int(cur_units * sched._eta)\n        self.assertEqual(len(big_bracket.current_trials()), 1)\n\n    def testHalvingStop(self):\n        stats = self.default_statistics()\n        num_trials = stats[str(0)]["n"] + stats[str(1)]["n"]\n        sched, mock_runner = self.schedulerSetup(num_trials)\n        big_bracket = sched._state["bracket"]\n        for trl in big_bracket.current_trials():\n            mock_runner._launch_trial(trl)\n\n        # # Provides result in reverse order, killing the last one\n        cur_units = stats[str(1)]["r"]\n        for i, trl in reversed(list(enumerate(big_bracket.current_trials()))):\n            action = sched.on_trial_result(mock_runner, trl, result(cur_units, i))\n            mock_runner.process_action(trl, action)\n\n        self.assertEqual(action, TrialScheduler.STOP)\n\n    def testStopsLastOne(self):\n        stats = self.default_statistics()\n        num_trials = stats[str(0)]["n"]  # setup one bracket\n        sched, mock_runner = self.schedulerSetup(num_trials)\n        big_bracket = sched._state["bracket"]\n        for trl in big_bracket.current_trials():\n            mock_runner._launch_trial(trl)\n\n        # # Provides result in reverse order, killing the last one\n        cur_units = stats[str(0)]["r"]\n        for i, trl in enumerate(big_bracket.current_trials()):\n            action = sched.on_trial_result(mock_runner, trl, result(cur_units, i))\n            mock_runner.process_action(trl, action)\n\n        self.assertEqual(action, TrialScheduler.STOP)\n\n    def testTrialErrored(self):\n        """If a trial errored, make sure successive halving still happens"""\n\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + 3\n        sched, mock_runner = self.schedulerSetup(trial_count)\n        t1, t2, t3 = sched._state["bracket"].current_trials()\n        for t in [t1, t2, t3]:\n            mock_runner._launch_trial(t)\n\n        sched.on_trial_error(mock_runner, t3)\n        self.assertEqual(\n            TrialScheduler.PAUSE,\n            sched.on_trial_result(mock_runner, t1, result(stats[str(1)]["r"], 10)),\n        )\n        self.assertEqual(\n            TrialScheduler.CONTINUE,\n            sched.on_trial_result(mock_runner, t2, result(stats[str(1)]["r"], 10)),\n        )\n\n    def testTrialErrored2(self):\n        """Check successive halving happened even when last trial failed"""\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + stats[str(1)]["n"]\n        sched, mock_runner = self.schedulerSetup(trial_count)\n        trials = sched._state["bracket"].current_trials()\n        for t in trials[:-1]:\n            mock_runner._launch_trial(t)\n            sched.on_trial_result(mock_runner, t, result(stats[str(1)]["r"], 10))\n\n        mock_runner._launch_trial(trials[-1])\n        sched.on_trial_error(mock_runner, trials[-1])\n        self.assertEqual(\n            len(sched._state["bracket"].current_trials()),\n            self.downscale(stats[str(1)]["n"], sched),\n        )\n\n    def testTrialEndedEarly(self):\n        """Check successive halving happened even when one trial failed"""\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + 3\n        sched, mock_runner = self.schedulerSetup(trial_count)\n\n        t1, t2, t3 = sched._state["bracket"].current_trials()\n        for t in [t1, t2, t3]:\n            mock_runner._launch_trial(t)\n\n        sched.on_trial_complete(mock_runner, t3, result(1, 12))\n        self.assertEqual(\n            TrialScheduler.PAUSE,\n            sched.on_trial_result(mock_runner, t1, result(stats[str(1)]["r"], 10)),\n        )\n        self.assertEqual(\n            TrialScheduler.CONTINUE,\n            sched.on_trial_result(mock_runner, t2, result(stats[str(1)]["r"], 10)),\n        )\n\n    def testTrialEndedEarly2(self):\n        """Check successive halving happened even when last trial failed"""\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + stats[str(1)]["n"]\n        sched, mock_runner = self.schedulerSetup(trial_count)\n        trials = sched._state["bracket"].current_trials()\n        for t in trials[:-1]:\n            mock_runner._launch_trial(t)\n            sched.on_trial_result(mock_runner, t, result(stats[str(1)]["r"], 10))\n\n        mock_runner._launch_trial(trials[-1])\n        sched.on_trial_complete(mock_runner, trials[-1], result(100, 12))\n        self.assertEqual(\n            len(sched._state["bracket"].current_trials()),\n            self.downscale(stats[str(1)]["n"], sched),\n        )\n\n    def testAddAfterHalving(self):\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + 1\n        sched, mock_runner = self.schedulerSetup(trial_count)\n        bracket_trials = sched._state["bracket"].current_trials()\n        init_units = stats[str(1)]["r"]\n\n        for t in bracket_trials:\n            mock_runner._launch_trial(t)\n\n        for i, t in enumerate(bracket_trials):\n            action = sched.on_trial_result(mock_runner, t, result(init_units, i))\n        self.assertEqual(action, TrialScheduler.CONTINUE)\n        t = Trial("__fake")\n        sched.on_trial_add(None, t)\n        mock_runner._launch_trial(t)\n        self.assertEqual(len(sched._state["bracket"].current_trials()), 2)\n\n        # Make sure that newly added trial gets fair computation (not just 1)\n        self.assertEqual(\n            TrialScheduler.CONTINUE,\n            sched.on_trial_result(mock_runner, t, result(init_units, 12)),\n        )\n        new_units = init_units + int(init_units * sched._eta)\n        self.assertEqual(\n            TrialScheduler.PAUSE,\n            sched.on_trial_result(mock_runner, t, result(new_units, 12)),\n        )\n\n    def _test_metrics(self, result_func, metric, mode):\n        sched = HyperBandScheduler(time_attr="time_total_s", metric=metric, mode=mode)\n        stats = self.default_statistics()\n\n        for i in range(stats["max_trials"]):\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n        runner = _MockTrialRunner(sched)\n\n        big_bracket = sched._hyperbands[0][-1]\n\n        for trl in big_bracket.current_trials():\n            runner._launch_trial(trl)\n        current_length = len(big_bracket.current_trials())\n\n        # Provides results from 0 to 8 in order, keeping the last one running\n        for i, trl in enumerate(big_bracket.current_trials()):\n            action = sched.on_trial_result(runner, trl, result_func(1, i))\n            runner.process_action(trl, action)\n\n        new_length = len(big_bracket.current_trials())\n        self.assertEqual(action, TrialScheduler.CONTINUE)\n        self.assertEqual(new_length, self.downscale(current_length, sched))\n\n    def testAlternateMetrics(self):\n        """Checking that alternate metrics will pass."""\n\n        def result2(t, rew):\n            return dict(time_total_s=t, neg_mean_loss=rew)\n\n        self._test_metrics(result2, "neg_mean_loss", "max")\n\n    def testAlternateMetricsMin(self):\n        """Checking that alternate metrics will pass."""\n\n        def result2(t, rew):\n            return dict(time_total_s=t, mean_loss=-rew)\n\n        self._test_metrics(result2, "mean_loss", "min")\n\n    def testJumpingTime(self):\n        sched, mock_runner = self.schedulerSetup(81)\n        big_bracket = sched._hyperbands[0][-1]\n\n        for trl in big_bracket.current_trials():\n            mock_runner._launch_trial(trl)\n\n        # Provides results from 0 to 8 in order, keeping the last one running\n        main_trials = big_bracket.current_trials()[:-1]\n        jump = big_bracket.current_trials()[-1]\n        for i, trl in enumerate(main_trials):\n            action = sched.on_trial_result(mock_runner, trl, result(1, i))\n            mock_runner.process_action(trl, action)\n\n        action = sched.on_trial_result(mock_runner, jump, result(4, i))\n        self.assertEqual(action, TrialScheduler.PAUSE)\n\n        current_length = len(big_bracket.current_trials())\n        self.assertLess(current_length, 27)\n\n    def testRemove(self):\n        """Test with 4: start 1, remove 1 pending, add 2, remove 1 pending."""\n        sched, runner = self.schedulerSetup(4)\n        trials = sorted(sched._trial_info, key=lambda t: t.trial_id)\n        runner._launch_trial(trials[0])\n        sched.on_trial_result(runner, trials[0], result(1, 5))\n        self.assertEqual(trials[0].status, Trial.RUNNING)\n        self.assertEqual(trials[1].status, Trial.PENDING)\n\n        bracket, _ = sched._trial_info[trials[1]]\n        self.assertTrue(trials[1] in bracket._live_trials)\n        sched.on_trial_remove(runner, trials[1])\n        self.assertFalse(trials[1] in bracket._live_trials)\n\n        for i in range(2):\n            trial = Trial("__fake")\n            sched.on_trial_add(None, trial)\n\n        bracket, _ = sched._trial_info[trial]\n        self.assertTrue(trial in bracket._live_trials)\n        sched.on_trial_remove(runner, trial)  # where trial is not running\n        self.assertFalse(trial in bracket._live_trials)\n\n    def testFilterNoneBracket(self):\n        sched, runner = self.schedulerSetup(100, 20)\n        # "sched" should contains None brackets\n        non_brackets = [\n            b for hyperband in sched._hyperbands for b in hyperband if b is None\n        ]\n        self.assertTrue(non_brackets)\n        # Make sure "choose_trial_to_run" still works\n        trial = sched.choose_trial_to_run(runner)\n        self.assertIsNotNone(trial)\n\n\nclass BOHBSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(object_store_memory=int(1e8))\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def testLargestBracketFirst(self):\n        sched = HyperBandForBOHB(\n            metric="episode_reward_mean", mode="max", max_t=3, reduction_factor=3\n        )\n        runner = _MockTrialRunner(sched)\n        for i in range(3):\n            t = Trial("__fake")\n            sched.on_trial_add(runner, t)\n            runner._launch_trial(t)\n\n        self.assertEqual(sched.state()["num_brackets"], 1)\n        sched.on_trial_add(runner, Trial("__fake"))\n        self.assertEqual(sched.state()["num_brackets"], 2)\n\n    def testCheckTrialInfoUpdate(self):\n        def result(score, ts):\n            return {"episode_reward_mean": score, TRAINING_ITERATION: ts}\n\n        sched = HyperBandForBOHB(\n            metric="episode_reward_mean", mode="max", max_t=3, reduction_factor=3\n        )\n        runner = _MockTrialRunner(sched)\n        runner._search_alg = MagicMock()\n        runner._search_alg.searcher = MagicMock()\n        trials = [Trial("__fake") for i in range(3)]\n        for t in trials:\n            runner.add_trial(t)\n            runner._launch_trial(t)\n\n        for trial, trial_result in zip(trials, [result(1, 1), result(2, 1)]):\n            decision = sched.on_trial_result(runner, trial, trial_result)\n            self.assertEqual(decision, TrialScheduler.PAUSE)\n            runner._pause_trial(trial)\n        spy_result = result(0, 1)\n        decision = sched.on_trial_result(runner, trials[-1], spy_result)\n        self.assertEqual(decision, TrialScheduler.STOP)\n        sched.choose_trial_to_run(runner)\n        self.assertEqual(runner._search_alg.searcher.on_pause.call_count, 2)\n        self.assertEqual(runner._search_alg.searcher.on_unpause.call_count, 1)\n        self.assertTrue("hyperband_info" in spy_result)\n        self.assertEqual(spy_result["hyperband_info"]["budget"], 1)\n\n    def testCheckTrialInfoUpdateMin(self):\n        def result(score, ts):\n            return {"episode_reward_mean": score, TRAINING_ITERATION: ts}\n\n        sched = HyperBandForBOHB(\n            metric="episode_reward_mean", mode="min", max_t=3, reduction_factor=3\n        )\n        runner = _MockTrialRunner(sched)\n        runner._search_alg = MagicMock()\n        runner._search_alg.searcher = MagicMock()\n        trials = [Trial("__fake") for i in range(3)]\n        for t in trials:\n            runner.add_trial(t)\n            runner._launch_trial(t)\n\n        for trial, trial_result in zip(trials, [result(1, 1), result(2, 1)]):\n            decision = sched.on_trial_result(runner, trial, trial_result)\n            self.assertEqual(decision, TrialScheduler.PAUSE)\n            runner._pause_trial(trial)\n        spy_result = result(0, 1)\n        decision = sched.on_trial_result(runner, trials[-1], spy_result)\n        self.assertEqual(decision, TrialScheduler.CONTINUE)\n        sched.choose_trial_to_run(runner)\n        self.assertEqual(runner._search_alg.searcher.on_pause.call_count, 2)\n        self.assertTrue("hyperband_info" in spy_result)\n        self.assertEqual(spy_result["hyperband_info"]["budget"], 1)\n\n    def testPauseResumeChooseTrial(self):\n        def result(score, ts):\n            return {"episode_reward_mean": score, TRAINING_ITERATION: ts}\n\n        sched = HyperBandForBOHB(\n            metric="episode_reward_mean", mode="min", max_t=10, reduction_factor=3\n        )\n        runner = _MockTrialRunner(sched)\n        runner._search_alg = MagicMock()\n        runner._search_alg.searcher = MagicMock()\n        trials = [Trial("__fake") for i in range(3)]\n        for t in trials:\n            runner.add_trial(t)\n            runner._launch_trial(t)\n\n        all_results = [result(1, 5), result(2, 1), result(3, 5)]\n        for trial, trial_result in zip(trials, all_results):\n            decision = sched.on_trial_result(runner, trial, trial_result)\n            self.assertEqual(decision, TrialScheduler.PAUSE)\n            runner._pause_trial(trial)\n\n        run_trial = sched.choose_trial_to_run(runner)\n        self.assertEqual(run_trial, trials[1])\n        self.assertSequenceEqual(\n            [t.status for t in trials], [Trial.PAUSED, Trial.PENDING, Trial.PAUSED]\n        )\n\n    def testNonstopBOHB(self):\n        from ray.tune.search.bohb import TuneBOHB\n\n        def train(cfg, checkpoint_dir=None):\n            start = 0\n            if checkpoint_dir:\n                with open(os.path.join(checkpoint_dir, "checkpoint")) as f:\n                    start = int(f.read())\n\n            for i in range(start, 200):\n\n                time.sleep(0.1)\n                tune.report(episode_reward_mean=i)\n                with tune.checkpoint_dir(i) as checkpoint_dir:\n                    with open(os.path.join(checkpoint_dir, "checkpoint"), "w") as f:\n                        f.write(str(i))\n\n        config = {"test_variable": tune.uniform(0, 20)}\n        sched = HyperBandForBOHB(max_t=10, reduction_factor=3, stop_last_trials=False)\n        alg = ConcurrencyLimiter(TuneBOHB(), 4)\n        analysis = tune.run(\n            train,\n            scheduler=sched,\n            search_alg=alg,\n            stop={"training_iteration": 32},\n            num_samples=20,\n            config=config,\n            metric="episode_reward_mean",\n            mode="min",\n            verbose=1,\n            fail_fast="raise",\n        )\n        counter = Counter(\n            t.last_result.get("training_iteration") for t in analysis.trials\n        )\n        assert 32 in counter\n        assert counter[32] > 1\n\n\nclass _MockTrial(Trial):\n    def __init__(self, i, config):\n        self.trainable_name = "trial_{}".format(i)\n        self.trial_id = str(i)\n        self.config = config\n        self.experiment_tag = "{}tag".format(i)\n        self.trial_name_creator = None\n        self.logger_running = False\n        self.restored_checkpoint = None\n        self.resources = Resources(1, 0)\n        self.custom_trial_name = None\n        self.custom_dirname = None\n        self._default_result_or_future = None\n\n    def on_checkpoint(self, checkpoint):\n        if checkpoint.storage_mode == CheckpointStorage.MEMORY:\n            self.restored_checkpoint = checkpoint.dir_or_data["data"]\n        else:\n            self.restored_checkpoint = checkpoint.dir_or_data\n\n    @property\n    def checkpoint(self):\n        return _TrackedCheckpoint(\n            dir_or_data={"data": self.trainable_name},\n            storage_mode=CheckpointStorage.MEMORY,\n            metrics=None,\n        )\n\n\nclass PopulationBasedTestingSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    # Helper function to call pbt.on_trial_result and assert decision,\n    # or trial status upon existing.\n    # Need to have the `trial` in `RUNNING` status first.\n    def on_trial_result(self, pbt, runner, trial, result, expected_decision=None):\n        trial.status = Trial.RUNNING\n        decision = pbt.on_trial_result(runner, trial, result)\n        if expected_decision is None:\n            pass\n        elif expected_decision == TrialScheduler.PAUSE:\n            self.assertTrue(\n                trial.status == Trial.PAUSED or decision == expected_decision\n            )\n        elif expected_decision == TrialScheduler.CONTINUE:\n            self.assertEqual(decision, expected_decision)\n        return decision\n\n    def basicSetup(\n        self,\n        num_trials=5,\n        resample_prob=0.0,\n        explore=None,\n        perturbation_interval=10,\n        log_config=False,\n        require_attrs=True,\n        hyperparams=None,\n        hyperparam_mutations=None,\n        step_once=True,\n        synch=False,\n    ):\n        hyperparam_mutations = hyperparam_mutations or {\n            "float_factor": lambda: 100.0,\n            "int_factor": lambda: 10,\n            "id_factor": [100],\n        }\n        pbt = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="episode_reward_mean",\n            mode="max",\n            perturbation_interval=perturbation_interval,\n            resample_probability=resample_prob,\n            quantile_fraction=0.25,\n            hyperparam_mutations=hyperparam_mutations,\n            custom_explore_fn=explore,\n            log_config=log_config,\n            synch=synch,\n            require_attrs=require_attrs,\n        )\n        runner = _MockTrialRunner(pbt)\n        for i in range(num_trials):\n            trial_hyperparams = hyperparams or {\n                "float_factor": 2.0,\n                "const_factor": 3,\n                "int_factor": 10,\n                "id_factor": i,\n            }\n            trial = _MockTrial(i, trial_hyperparams)\n            runner.add_trial(trial)\n            trial.status = Trial.RUNNING\n        for i in range(num_trials):\n            trial = runner.trials[i]\n            if step_once:\n                if synch:\n                    self.on_trial_result(\n                        pbt,\n                        runner,\n                        trial,\n                        result(10, 50 * i),\n                        expected_decision=TrialScheduler.PAUSE,\n                    )\n                else:\n                    self.on_trial_result(\n                        pbt,\n                        runner,\n                        trial,\n                        result(10, 50 * i),\n                        expected_decision=TrialScheduler.CONTINUE,\n                    )\n        pbt.reset_stats()\n        return pbt, runner\n\n    def testSearchError(self):\n        pbt, runner = self.basicSetup(num_trials=0)\n\n        def mock_train(config):\n            return 1\n\n        with self.assertRaises(ValueError):\n            tune.run(\n                mock_train, config={"x": 1}, scheduler=pbt, search_alg=_MockSearcher()\n            )\n\n    def testMetricError(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n\n        # Should error if training_iteration not in result dict.\n        with self.assertRaises(RuntimeError):\n            self.on_trial_result(\n                pbt, runner, trials[0], result={"episode_reward_mean": 4}\n            )\n\n        # Should error if episode_reward_mean not in result dict.\n        with self.assertRaises(RuntimeError):\n            self.on_trial_result(\n                pbt,\n                runner,\n                trials[0],\n                result={"random_metric": 10, "training_iteration": 20},\n            )\n\n    def testMetricLog(self):\n        pbt, runner = self.basicSetup(require_attrs=False)\n        trials = runner.get_trials()\n\n        # Should not error if training_iteration not in result dict\n        with self.assertLogs("ray.tune.schedulers.pbt", level="WARN"):\n            self.on_trial_result(\n                pbt, runner, trials[0], result={"episode_reward_mean": 4}\n            )\n\n        # Should not error if episode_reward_mean not in result dict.\n        with self.assertLogs("ray.tune.schedulers.pbt", level="WARN"):\n            self.on_trial_result(\n                pbt,\n                runner,\n                trials[0],\n                result={"random_metric": 10, "training_iteration": 20},\n            )\n\n    def testCheckpointsMostPromisingTrials(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n\n        # no checkpoint: haven\'t hit next perturbation interval yet\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.on_trial_result(\n            pbt, runner, trials[0], result(15, 200), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.assertEqual(pbt._num_checkpoints, 0)\n\n        # checkpoint: both past interval and upper quantile\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, 200), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [200, 50, 100, 150, 200])\n        self.assertEqual(pbt._num_checkpoints, 1)\n        self.on_trial_result(\n            pbt, runner, trials[1], result(30, 201), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [200, 201, 100, 150, 200])\n        self.assertEqual(pbt._num_checkpoints, 2)\n\n        # not upper quantile any more\n        self.on_trial_result(\n            pbt, runner, trials[4], result(30, 199), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt._num_checkpoints, 2)\n        self.assertEqual(pbt._num_perturbations, 0)\n\n    def testCheckpointMostPromisingTrialsSynch(self):\n        pbt, runner = self.basicSetup(synch=True)\n        trials = runner.get_trials()\n\n        # no checkpoint: haven\'t hit next perturbation interval yet\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.on_trial_result(\n            pbt, runner, trials[0], result(15, 200), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.assertEqual(pbt._num_checkpoints, 0)\n\n        # trials should be paused until all trials are synced.\n        for i in range(len(trials) - 1):\n            self.on_trial_result(\n                pbt, runner, trials[i], result(20, 200 + i), TrialScheduler.PAUSE\n            )\n\n        self.assertEqual(pbt.last_scores(trials), [200, 201, 202, 203, 200])\n        self.assertEqual(pbt._num_checkpoints, 0)\n\n        self.on_trial_result(\n            pbt, runner, trials[-1], result(20, 204), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt._num_checkpoints, 2)\n\n    def testPerturbsLowPerformingTrials(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n\n        # no perturbation: haven\'t hit next perturbation interval\n        self.on_trial_result(\n            pbt, runner, trials[0], result(15, -100), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.assertTrue("@perturbed" not in trials[0].experiment_tag)\n        self.assertEqual(pbt._num_perturbations, 0)\n\n        # perturb since it\'s lower quantile\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt.last_scores(trials), [-100, 50, 100, 150, 200])\n        self.assertTrue("@perturbed" in trials[0].experiment_tag)\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertEqual(pbt._num_perturbations, 1)\n\n        # also perturbed\n        self.on_trial_result(\n            pbt, runner, trials[2], result(20, 40), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt.last_scores(trials), [-100, 50, 40, 150, 200])\n        self.assertEqual(pbt._num_perturbations, 2)\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertTrue("@perturbed" in trials[2].experiment_tag)\n\n    def testPerturbsLowPerformingTrialsSynch(self):\n        pbt, runner = self.basicSetup(synch=True)\n        trials = runner.get_trials()\n\n        # no perturbation: haven\'t hit next perturbation interval\n        self.on_trial_result(\n            pbt, runner, trials[-1], result(15, -100), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.assertTrue("@perturbed" not in trials[-1].experiment_tag)\n        self.assertEqual(pbt._num_perturbations, 0)\n\n        # Don\'t perturb until all trials are synched.\n        self.on_trial_result(\n            pbt, runner, trials[-1], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, -100])\n        self.assertTrue("@perturbed" not in trials[-1].experiment_tag)\n\n        # Synch all trials.\n        for i in range(len(trials) - 1):\n            self.on_trial_result(\n                pbt, runner, trials[i], result(20, -10 * i), TrialScheduler.PAUSE\n            )\n        self.assertEqual(pbt.last_scores(trials), [0, -10, -20, -30, -100])\n        self.assertIn(trials[-1].restored_checkpoint, ["trial_0", "trial_1"])\n        self.assertIn(trials[-2].restored_checkpoint, ["trial_0", "trial_1"])\n        self.assertEqual(pbt._num_perturbations, 2)\n\n    def testPerturbWithoutResample(self):\n        pbt, runner = self.basicSetup(resample_prob=0.0)\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertIn(trials[0].config["id_factor"], [100])\n        self.assertIn(trials[0].config["float_factor"], [2.4, 1.6])\n        self.assertEqual(type(trials[0].config["float_factor"]), float)\n        self.assertIn(trials[0].config["int_factor"], [8, 12])\n        self.assertEqual(type(trials[0].config["int_factor"]), int)\n        self.assertEqual(trials[0].config["const_factor"], 3)\n\n    def testPerturbWithResample(self):\n        pbt, runner = self.basicSetup(resample_prob=1.0)\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertEqual(trials[0].status, Trial.PAUSED)\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertEqual(trials[0].config["id_factor"], 100)\n        self.assertEqual(trials[0].config["float_factor"], 100.0)\n        self.assertEqual(type(trials[0].config["float_factor"]), float)\n        self.assertEqual(trials[0].config["int_factor"], 10)\n        self.assertEqual(type(trials[0].config["int_factor"]), int)\n        self.assertEqual(trials[0].config["const_factor"], 3)\n\n    def testTuneSamplePrimitives(self):\n        pbt, runner = self.basicSetup(\n            resample_prob=1.0,\n            hyperparam_mutations={\n                "float_factor": lambda: 100.0,\n                "int_factor": lambda: 10,\n                "id_factor": tune.choice([100]),\n            },\n        )\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertEqual(trials[0].config["id_factor"], 100)\n        self.assertEqual(trials[0].config["float_factor"], 100.0)\n        self.assertEqual(type(trials[0].config["float_factor"]), float)\n        self.assertEqual(trials[0].config["int_factor"], 10)\n        self.assertEqual(type(trials[0].config["int_factor"]), int)\n        self.assertEqual(trials[0].config["const_factor"], 3)\n\n    def testTuneSampleFromError(self):\n        with self.assertRaises(ValueError):\n            pbt, runner = self.basicSetup(\n                hyperparam_mutations={"float_factor": tune.sample_from(lambda: 100.0)}\n            )\n\n    def testPerturbationValues(self):\n        def assertProduces(fn, values):\n            random.seed(0)\n            seen = set()\n            for _ in range(100):\n                seen.add(fn()["v"])\n            self.assertEqual(seen, values)\n\n        # Categorical case\n        assertProduces(\n            lambda: _explore({"v": 4}, {"v": [3, 4, 8, 10]}, 0.0, lambda x: x), {3, 8}\n        )\n        assertProduces(\n            lambda: _explore({"v": 3}, {"v": [3, 4, 8, 10]}, 0.0, lambda x: x), {3, 4}\n        )\n        assertProduces(\n            lambda: _explore({"v": 10}, {"v": [3, 4, 8, 10]}, 0.0, lambda x: x), {8, 10}\n        )\n        assertProduces(\n            lambda: _explore({"v": 7}, {"v": [3, 4, 8, 10]}, 0.0, lambda x: x),\n            {3, 4, 8, 10},\n        )\n        assertProduces(\n            lambda: _explore({"v": 4}, {"v": [3, 4, 8, 10]}, 1.0, lambda x: x),\n            {3, 4, 8, 10},\n        )\n\n        # Continuous case\n        assertProduces(\n            lambda: _explore(\n                {"v": 100}, {"v": lambda: random.choice([10, 100])}, 0.0, lambda x: x\n            ),\n            {80, 120},\n        )\n        assertProduces(\n            lambda: _explore(\n                {"v": 100.0}, {"v": lambda: random.choice([10, 100])}, 0.0, lambda x: x\n            ),\n            {80.0, 120.0},\n        )\n        assertProduces(\n            lambda: _explore(\n                {"v": 100.0}, {"v": lambda: random.choice([10, 100])}, 1.0, lambda x: x\n            ),\n            {10.0, 100.0},\n        )\n\n        def deep_add(seen, new_values):\n            for k, new_value in new_values.items():\n                if isinstance(new_value, dict):\n                    if k not in seen:\n                        seen[k] = {}\n                    seen[k].update(deep_add(seen[k], new_value))\n                else:\n                    if k not in seen:\n                        seen[k] = set()\n                    seen[k].add(new_value)\n\n            return seen\n\n        def assertNestedProduces(fn, values):\n            random.seed(0)\n            seen = {}\n            for _ in range(100):\n                new_config = fn()\n                seen = deep_add(seen, new_config)\n            self.assertEqual(seen, values)\n\n        # Nested mutation and spec\n        assertNestedProduces(\n            lambda: _explore(\n                {\n                    "a": {"b": 4},\n                    "1": {"2": {"3": 100}},\n                },\n                {\n                    "a": {"b": [3, 4, 8, 10]},\n                    "1": {"2": {"3": lambda: random.choice([10, 100])}},\n                },\n                0.0,\n                lambda x: x,\n            ),\n            {\n                "a": {"b": {3, 8}},\n                "1": {"2": {"3": {80, 120}}},\n            },\n        )\n\n        custom_explore_fn = MagicMock(side_effect=lambda x: x)\n\n        # Nested mutation and spec\n        assertNestedProduces(\n            lambda: _explore(\n                {\n                    "a": {"b": 4},\n                    "1": {"2": {"3": 100}},\n                },\n                {\n                    "a": {"b": [3, 4, 8, 10]},\n                    "1": {"2": {"3": lambda: random.choice([10, 100])}},\n                },\n                0.0,\n                custom_explore_fn,\n            ),\n            {\n                "a": {"b": {3, 8}},\n                "1": {"2": {"3": {80, 120}}},\n            },\n        )\n\n        # Expect call count to be 100 because we call explore 100 times\n        self.assertEqual(custom_explore_fn.call_count, 100)\n\n    def testDictPerturbation(self):\n        pbt, runner = self.basicSetup(\n            resample_prob=1.0,\n            hyperparams={\n                "float_factor": 2.0,\n                "nest": {"nest_float": 3.0},\n                "int_factor": 10,\n                "const_factor": 3,\n            },\n            hyperparam_mutations={\n                "float_factor": lambda: 100.0,\n                "nest": {"nest_float": lambda: 101.0},\n                "int_factor": lambda: 10,\n            },\n        )\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertEqual(trials[0].config["float_factor"], 100.0)\n        self.assertIsInstance(trials[0].config["float_factor"], float)\n        self.assertEqual(trials[0].config["int_factor"], 10)\n        self.assertIsInstance(trials[0].config["int_factor"], int)\n        self.assertEqual(trials[0].config["const_factor"], 3)\n        self.assertEqual(trials[0].config["nest"]["nest_float"], 101.0)\n        self.assertIsInstance(trials[0].config["nest"]["nest_float"], float)\n\n    def testYieldsTimeToOtherTrials(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n        trials[0].status = Trial.PENDING  # simulate not enough resources\n        self.on_trial_result(\n            pbt, runner, trials[1], result(20, 1000), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 1000, 100, 150, 200])\n        self.assertEqual(pbt.choose_trial_to_run(runner), trials[0])\n\n    def testSchedulesMostBehindTrialToRun(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n        self.on_trial_result(pbt, runner, trials[0], result(800, 1000))\n        self.on_trial_result(pbt, runner, trials[1], result(700, 1001))\n        self.on_trial_result(pbt, runner, trials[2], result(600, 1002))\n        self.on_trial_result(pbt, runner, trials[3], result(500, 1003))\n        self.on_trial_result(pbt, runner, trials[4], result(700, 1004))\n        self.assertEqual(pbt.choose_trial_to_run(runner), None)\n        for i in range(5):\n            trials[i].status = Trial.PENDING\n        self.assertEqual(pbt.choose_trial_to_run(runner), trials[3])\n\n    def testSchedulesMostBehindTrialToRunSynch(self):\n        pbt, runner = self.basicSetup(synch=True)\n        trials = runner.get_trials()\n        runner.process_action(\n            trials[0], self.on_trial_result(pbt, runner, trials[0], result(800, 1000))\n        )\n        runner.process_action(\n            trials[1], self.on_trial_result(pbt, runner, trials[1], result(700, 1001))\n        )\n        runner.process_action(\n            trials[2], self.on_trial_result(pbt, runner, trials[2], result(600, 1002))\n        )\n        runner.process_action(\n            trials[3], self.on_trial_result(pbt, runner, trials[3], result(500, 1003))\n        )\n        runner.process_action(\n            trials[4], self.on_trial_result(pbt, runner, trials[4], result(700, 1004))\n        )\n        self.assertIn(\n            pbt.choose_trial_to_run(runner), [trials[0], trials[1], trials[3]]\n        )\n\n    def testPerturbationResetsLastPerturbTime(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n        self.on_trial_result(pbt, runner, trials[0], result(10000, 1005))\n        self.on_trial_result(pbt, runner, trials[1], result(10000, 1004))\n        self.on_trial_result(pbt, runner, trials[2], result(600, 1003))\n        self.assertEqual(pbt._num_perturbations, 0)\n        self.on_trial_result(pbt, runner, trials[3], result(500, 1002))\n        self.assertEqual(pbt._num_perturbations, 1)\n        self.on_trial_result(pbt, runner, trials[3], result(600, 100))\n        self.assertEqual(pbt._num_perturbations, 1)\n        self.on_trial_result(pbt, runner, trials[3], result(11000, 100))\n        self.assertEqual(pbt._num_perturbations, 2)\n\n    def testLogConfig(self):\n        def check_policy(policy):\n            self.assertIsInstance(policy[2], int)\n            self.assertIsInstance(policy[3], int)\n            self.assertIn(policy[0], ["0tag", "2tag", "3tag", "4tag"])\n            self.assertIn(policy[1], ["0tag", "2tag", "3tag", "4tag"])\n            self.assertIn(policy[2], [0, 2, 3, 4])\n            self.assertIn(policy[3], [0, 2, 3, 4])\n            for i in [4, 5]:\n                self.assertIsInstance(policy[i], dict)\n                for key in ["const_factor", "int_factor", "float_factor", "id_factor"]:\n                    self.assertIn(key, policy[i])\n                self.assertIsInstance(policy[i]["float_factor"], float)\n                self.assertIsInstance(policy[i]["int_factor"], int)\n                self.assertIn(policy[i]["const_factor"], [3])\n                self.assertIn(policy[i]["int_factor"], [8, 10, 12])\n                self.assertIn(policy[i]["float_factor"], [2.4, 2, 1.6])\n                self.assertIn(policy[i]["id_factor"], [3, 4, 100])\n\n        pbt, runner = self.basicSetup(log_config=True)\n        trials = runner.get_trials()\n        tmpdir = tempfile.mkdtemp()\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {TRAINING_ITERATION: i}\n        self.on_trial_result(pbt, runner, trials[0], result(15, -100))\n        self.on_trial_result(pbt, runner, trials[0], result(20, -100))\n        self.on_trial_result(pbt, runner, trials[2], result(20, 40))\n        log_files = ["pbt_global.txt", "pbt_policy_0.txt", "pbt_policy_2.txt"]\n        for log_file in log_files:\n            self.assertTrue(os.path.exists(os.path.join(tmpdir, log_file)))\n            raw_policy = open(os.path.join(tmpdir, log_file), "r").readlines()\n            for line in raw_policy:\n                check_policy(json.loads(line))\n        shutil.rmtree(tmpdir)\n\n    def testLogConfigSynch(self):\n        def check_policy(policy):\n            self.assertIsInstance(policy[2], int)\n            self.assertIsInstance(policy[3], int)\n            self.assertIn(policy[0], ["0tag", "1tag"])\n            self.assertIn(policy[1], ["3tag", "4tag"])\n            self.assertIn(policy[2], [0, 1])\n            self.assertIn(policy[3], [3, 4])\n            for i in [4, 5]:\n                self.assertIsInstance(policy[i], dict)\n                for key in ["const_factor", "int_factor", "float_factor", "id_factor"]:\n                    self.assertIn(key, policy[i])\n                self.assertIsInstance(policy[i]["float_factor"], float)\n                self.assertIsInstance(policy[i]["int_factor"], int)\n                self.assertIn(policy[i]["const_factor"], [3])\n                self.assertIn(policy[i]["int_factor"], [8, 10, 12])\n                self.assertIn(policy[i]["float_factor"], [2.4, 2, 1.6])\n                self.assertIn(policy[i]["id_factor"], [3, 4, 100])\n\n        pbt, runner = self.basicSetup(log_config=True, synch=True, step_once=False)\n        trials = runner.get_trials()\n        tmpdir = tempfile.mkdtemp()\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {TRAINING_ITERATION: i}\n            self.on_trial_result(pbt, runner, trials[i], result(10, i))\n        log_files = ["pbt_global.txt", "pbt_policy_0.txt", "pbt_policy_1.txt"]\n        for log_file in log_files:\n            self.assertTrue(os.path.exists(os.path.join(tmpdir, log_file)))\n            raw_policy = open(os.path.join(tmpdir, log_file), "r").readlines()\n            for line in raw_policy:\n                check_policy(json.loads(line))\n        shutil.rmtree(tmpdir)\n\n    def testReplay(self):\n        # Returns unique increasing parameter mutations\n        class _Counter:\n            def __init__(self, start=0):\n                self.count = start - 1\n\n            def __call__(self, *args, **kwargs):\n                self.count += 1\n                return self.count\n\n        pbt, runner = self.basicSetup(\n            num_trials=4,\n            perturbation_interval=5,\n            log_config=True,\n            step_once=False,\n            synch=False,\n            hyperparam_mutations={\n                "float_factor": lambda: 100.0,\n                "int_factor": _Counter(1000),\n            },\n        )\n        trials = runner.get_trials()\n        tmpdir = tempfile.mkdtemp()\n\n        # Internal trial state to collect the real PBT history\n        class _TrialState:\n            def __init__(self, config):\n                self.step = 0\n                self.config = config\n                self.history = []\n\n            def forward(self, t):\n                while self.step < t:\n                    self.history.append(self.config)\n                    self.step += 1\n\n        trial_state = []\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {TRAINING_ITERATION: 0}\n            trial_state.append(_TrialState(trial.config))\n\n        # Helper function to simulate stepping trial k a number of steps,\n        # and reporting a score at the end\n        def trial_step(k, steps, score):\n            res = result(trial_state[k].step + steps, score)\n\n            trials[k].last_result = res\n            trial_state[k].forward(res[TRAINING_ITERATION])\n\n            old_config = trials[k].config\n            self.on_trial_result(pbt, runner, trials[k], res)\n            new_config = trials[k].config\n            trial_state[k].config = new_config.copy()\n\n            if old_config != new_config:\n                # Copy history from source trial\n                source = -1\n                for m, cand in enumerate(trials):\n                    if cand.trainable_name == trials[k].restored_checkpoint:\n                        source = m\n                        break\n                assert source >= 0\n                trial_state[k].history = trial_state[source].history.copy()\n                trial_state[k].step = trial_state[source].step\n\n        # Initial steps\n        trial_step(0, 10, 0)\n        trial_step(1, 11, 10)\n        trial_step(2, 12, 0)\n        trial_step(3, 13, 0)\n\n        # Next block\n        trial_step(0, 10, -10)  # 0 <-- 1, new_t=11\n        trial_step(2, 8, -20)  # 2 <-- 1, new_t=11\n        trial_step(3, 9, 0)\n        trial_step(1, 7, 0)\n\n        # Next block\n        trial_step(1, 12, 0)\n        trial_step(2, 13, 0)\n        trial_step(3, 14, 10)\n        trial_step(0, 11, 0)  # 0 <-- 3, new_t=13+9+14=36\n\n        # Next block\n        trial_step(0, 6, 20)\n        trial_step(3, 9, -40)  # 3 <-- 0, new_t=42\n        trial_step(2, 8, -50)  # 2 <-- 0, new_t=42\n        trial_step(1, 7, 30)\n        trial_step(2, 8, -60)  # 2 <-- 1, new_t=37\n\n        # Next block\n        trial_step(0, 10, 0)\n        trial_step(1, 10, 0)\n        trial_step(2, 10, 0)\n        trial_step(3, 10, 0)\n\n        # Playback trainable to collect configs at each step\n        class Playback(Trainable):\n            def setup(self, config):\n                self.config = config\n                self.replayed = []\n                self.iter = 0\n\n            def step(self):\n                self.iter += 1\n                self.replayed.append(self.config)\n                return {\n                    "reward": 0,\n                    "done": False,\n                    "replayed": self.replayed,\n                    TRAINING_ITERATION: self.iter,\n                }\n\n            def save_checkpoint(self, checkpoint_dir):\n                path = os.path.join(checkpoint_dir, "checkpoint")\n                with open(path, "w") as f:\n                    f.write(json.dumps({"iter": self.iter, "replayed": self.replayed}))\n                return path\n\n            def load_checkpoint(self, checkpoint_path):\n                with open(checkpoint_path) as f:\n                    checkpoint_json = json.loads(f.read())\n                    self.iter = checkpoint_json["iter"]\n                    self.replayed = checkpoint_json["replayed"]\n\n        # Loop through all trials and check if PBT history is the\n        # same as the playback history\n        for i, trial in enumerate(trials):\n            if trial.trial_id == "1":  # Did not exploit anything\n                continue\n\n            replay = PopulationBasedTrainingReplay(\n                os.path.join(tmpdir, "pbt_policy_{}.txt".format(trial.trial_id))\n            )\n            analysis = tune.run(\n                Playback,\n                scheduler=replay,\n                stop={TRAINING_ITERATION: trial_state[i].step},\n            )\n\n            replayed = analysis.trials[0].last_result["replayed"]\n            self.assertSequenceEqual(trial_state[i].history, replayed)\n\n        # Trial 1 did not exploit anything and should raise an error\n        with self.assertRaises(ValueError):\n            replay = PopulationBasedTrainingReplay(\n                os.path.join(tmpdir, "pbt_policy_{}.txt".format(trials[1].trial_id))\n            )\n            tune.run(\n                Playback,\n                scheduler=replay,\n                stop={TRAINING_ITERATION: trial_state[1].step},\n            )\n\n        shutil.rmtree(tmpdir)\n\n    def testReplaySynch(self):\n        # Returns unique increasing parameter mutations\n        class _Counter:\n            def __init__(self, start=0):\n                self.count = start - 1\n\n            def __call__(self, *args, **kwargs):\n                self.count += 1\n                return self.count\n\n        pbt, runner = self.basicSetup(\n            num_trials=4,\n            perturbation_interval=5,\n            log_config=True,\n            step_once=False,\n            synch=True,\n            hyperparam_mutations={\n                "float_factor": lambda: 100.0,\n                "int_factor": _Counter(1000),\n            },\n        )\n        trials = runner.get_trials()\n        tmpdir = tempfile.mkdtemp()\n\n        # Internal trial state to collect the real PBT history\n        class _TrialState:\n            def __init__(self, config):\n                self.step = 0\n                self.config = config\n                self.history = []\n\n            def forward(self, t):\n                while self.step < t:\n                    self.history.append(self.config)\n                    self.step += 1\n\n        trial_state = []\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {TRAINING_ITERATION: 0}\n            trial_state.append(_TrialState(trial.config))\n\n        # Helper function to simulate stepping trial k a number of steps,\n        # and reporting a score at the end\n        def trial_step(k, steps, score, synced=False):\n            res = result(trial_state[k].step + steps, score)\n\n            trials[k].last_result = res\n            trial_state[k].forward(res[TRAINING_ITERATION])\n\n            if not synced:\n                action = self.on_trial_result(pbt, runner, trials[k], res)\n                runner.process_action(trials[k], action)\n                return\n            else:\n                # Reached synchronization point\n                old_configs = [trial.config for trial in trials]\n                action = self.on_trial_result(pbt, runner, trials[k], res)\n                runner.process_action(trials[k], action)\n                new_configs = [trial.config for trial in trials]\n\n                for i in range(len(trials)):\n                    old_config = old_configs[i]\n                    new_config = new_configs[i]\n                    if old_config != new_config:\n                        # Copy history from source trial\n                        source = -1\n                        for m, cand in enumerate(trials):\n                            if cand.trainable_name == trials[i].restored_checkpoint:\n                                source = m\n                                break\n                        assert source >= 0\n                        trial_state[i].history = trial_state[source].history.copy()\n                        trial_state[i].step = trial_state[source].step\n                        trial_state[i].config = new_config.copy()\n\n        # Initial steps\n        trial_step(0, 10, 0)\n        trial_step(1, 11, 10)\n        trial_step(2, 12, 0)\n        trial_step(3, 13, -1, synced=True)\n\n        # 3 <-- 1, new_t 11\n        # next_perturb_sync = 13\n\n        # Next block\n        trial_step(0, 17, -10)  # 20\n        trial_step(2, 15, -20)  # 20\n        trial_step(3, 16, 0)  # 20\n        trial_step(1, 7, 1, synced=True)  # 18\n\n        # 2 <-- 1, new_t=11+7=18\n        # next_perturb_sync = 20\n\n        # Next block\n        trial_step(2, 13, 0)  # 31\n        trial_step(3, 14, 10)  # 34\n        trial_step(0, 11, -1)  # 31\n        trial_step(1, 12, 0, synced=True)  # 30\n\n        # 0 <-- 3, new_t=11+9+14=34\n        # next_perturb_sync = 34\n\n        # Next block\n        trial_step(0, 6, 20)  # 40\n        trial_step(3, 9, -40)  # 43\n        trial_step(2, 8, -50)  # 39\n        trial_step(1, 7, 30, synced=True)  # 37\n\n        # 2 <-- 1, new_t=18+13+8=37\n        # next_perturb_sync = 43\n\n        # Playback trainable to collect configs at each step\n        class Playback(Trainable):\n            def setup(self, config):\n                self.config = config\n                self.replayed = []\n                self.iter = 0\n\n            def step(self):\n                self.iter += 1\n                self.replayed.append(self.config)\n                return {\n                    "reward": 0,\n                    "done": False,\n                    "replayed": self.replayed,\n                    TRAINING_ITERATION: self.iter,\n                }\n\n            def save_checkpoint(self, checkpoint_dir):\n                path = os.path.join(checkpoint_dir, "checkpoint")\n                with open(path, "w") as f:\n                    f.write(json.dumps({"iter": self.iter, "replayed": self.replayed}))\n                return path\n\n            def load_checkpoint(self, checkpoint_path):\n                with open(checkpoint_path) as f:\n                    checkpoint_json = json.loads(f.read())\n                    self.iter = checkpoint_json["iter"]\n                    self.replayed = checkpoint_json["replayed"]\n\n        # Loop through all trials and check if PBT history is the\n        # same as the playback history\n        for i, trial in enumerate(trials):\n            if trial.trial_id in ["1"]:  # Did not exploit anything\n                continue\n\n            replay = PopulationBasedTrainingReplay(\n                os.path.join(tmpdir, "pbt_policy_{}.txt".format(trial.trial_id))\n            )\n            analysis = tune.run(\n                Playback,\n                scheduler=replay,\n                stop={TRAINING_ITERATION: trial_state[i].step},\n            )\n\n            replayed = analysis.trials[0].last_result["replayed"]\n            self.assertSequenceEqual(trial_state[i].history, replayed)\n\n        # Trial 1 did not exploit anything and should raise an error\n        with self.assertRaises(ValueError):\n            replay = PopulationBasedTrainingReplay(\n                os.path.join(tmpdir, "pbt_policy_{}.txt".format(trials[1].trial_id))\n            )\n            tune.run(\n                Playback,\n                scheduler=replay,\n                stop={TRAINING_ITERATION: trial_state[1].step},\n            )\n\n        shutil.rmtree(tmpdir)\n\n    def testPostprocessingHook(self):\n        def explore(new_config):\n            new_config["id_factor"] = 42\n            new_config["float_factor"] = 43\n            return new_config\n\n        pbt, runner = self.basicSetup(resample_prob=0.0, explore=explore)\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertEqual(trials[0].config["id_factor"], 42)\n        self.assertEqual(trials[0].config["float_factor"], 43)\n\n    def testFastPerturb(self):\n        pbt, runner = self.basicSetup(\n            perturbation_interval=1, step_once=False, log_config=True\n        )\n        trials = runner.get_trials()\n\n        tmpdir = tempfile.mkdtemp()\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {}\n        self.on_trial_result(pbt, runner, trials[0], result(1, 10))\n        self.on_trial_result(\n            pbt, runner, trials[2], result(1, 200), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt._num_checkpoints, 1)\n\n        pbt._exploit(runner.trial_executor, trials[1], trials[2])\n        shutil.rmtree(tmpdir)\n\n    def testContextExit(self):\n        vals = [5, 1]\n\n        class MockContext:\n            def __init__(self, config):\n                self.config = config\n                self.active = False\n\n            def __enter__(self):\n                print("Set up resource.", self.config)\n                with open("status.txt", "wt") as fp:\n                    fp.write("Activate\\n")\n                self.active = True\n                return self\n\n            def __exit__(self, type, value, traceback):\n                print("Clean up resource.", self.config)\n                with open("status.txt", "at") as fp:\n                    fp.write("Cleanup\\n")\n                self.active = False\n\n        def train(config):\n            with MockContext(config):\n                for i in range(10):\n                    tune.report(metric=i + config["x"])\n\n        class MockScheduler(FIFOScheduler):\n            def on_trial_result(self, trial_runner, trial, result):\n                return TrialScheduler.STOP\n\n        scheduler = MockScheduler()\n\n        out = tune.run(train, config={"x": tune.grid_search(vals)}, scheduler=scheduler)\n\n        ever_active = set()\n        active = set()\n        for trial in out.trials:\n            with open(os.path.join(trial.logdir, "status.txt"), "rt") as fp:\n                status = fp.read()\n            print(f"Status for trial {trial}: {status}")\n            if "Activate" in status:\n                ever_active.add(trial)\n                active.add(trial)\n            if "Cleanup" in status:\n                active.remove(trial)\n\n        print(f"Ever active: {ever_active}")\n        print(f"Still active: {active}")\n\n        self.assertEqual(len(ever_active), len(vals))\n        self.assertEqual(len(active), 0)\n\n\nclass E2EPopulationBasedTestingSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=4)\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def basicSetup(\n        self,\n        resample_prob=0.0,\n        explore=None,\n        perturbation_interval=10,\n        log_config=False,\n        hyperparams=None,\n        hyperparam_mutations=None,\n        step_once=True,\n    ):\n        hyperparam_mutations = hyperparam_mutations or {\n            "float_factor": lambda: 100.0,\n            "int_factor": lambda: 10,\n            "id_factor": [100],\n        }\n        pbt = PopulationBasedTraining(\n            metric="mean_accuracy",\n            mode="max",\n            time_attr="training_iteration",\n            perturbation_interval=perturbation_interval,\n            resample_probability=resample_prob,\n            quantile_fraction=0.25,\n            hyperparam_mutations=hyperparam_mutations,\n            custom_explore_fn=explore,\n            log_config=log_config,\n        )\n        return pbt\n\n    def testCheckpointing(self):\n        pbt = self.basicSetup(perturbation_interval=2)\n\n        class train(tune.Trainable):\n            def step(self):\n                return {"mean_accuracy": self.training_iteration}\n\n            def save_checkpoint(self, path):\n                checkpoint = os.path.join(path, "checkpoint")\n                with open(checkpoint, "w") as f:\n                    f.write("OK")\n                return checkpoint\n\n            def reset_config(self, config):\n                return True\n\n            def load_checkpoint(self, checkpoint):\n                pass\n\n        trial_hyperparams = {\n            "float_factor": 2.0,\n            "const_factor": 3,\n            "int_factor": 10,\n            "id_factor": 0,\n        }\n\n        analysis = tune.run(\n            train,\n            num_samples=3,\n            scheduler=pbt,\n            checkpoint_freq=3,\n            config=trial_hyperparams,\n            stop={"training_iteration": 30},\n        )\n\n        for trial in analysis.trials:\n            self.assertEqual(trial.status, Trial.TERMINATED)\n            self.assertTrue(trial.has_checkpoint())\n\n    def testCheckpointDict(self):\n        pbt = self.basicSetup(perturbation_interval=2)\n\n        class train_dict(tune.Trainable):\n            def setup(self, config):\n                self.state = {"hi": 1}\n\n            def step(self):\n                return {"mean_accuracy": self.training_iteration}\n\n            def save_checkpoint(self, path):\n                return self.state\n\n            def load_checkpoint(self, state):\n                self.state = state\n\n            def reset_config(self, config):\n                return True\n\n        trial_hyperparams = {\n            "float_factor": 2.0,\n            "const_factor": 3,\n            "int_factor": 10,\n            "id_factor": 0,\n        }\n\n        analysis = tune.run(\n            train_dict,\n            num_samples=3,\n            scheduler=pbt,\n            checkpoint_freq=3,\n            config=trial_hyperparams,\n            stop={"training_iteration": 30},\n        )\n\n        for trial in analysis.trials:\n            self.assertEqual(trial.status, Trial.TERMINATED)\n            self.assertTrue(trial.has_checkpoint())\n\n\nclass AsyncHyperBandSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def basicSetup(self, scheduler):\n        t1 = Trial("PPO")  # mean is 450, max 900, t_max=10\n        t2 = Trial("PPO")  # mean is 450, max 450, t_max=5\n        scheduler.on_trial_add(None, t1)\n        scheduler.on_trial_add(None, t2)\n        for i in range(10):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t1, result(i, i * 100)),\n                TrialScheduler.CONTINUE,\n            )\n        for i in range(5):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t2, result(i, 450)),\n                TrialScheduler.CONTINUE,\n            )\n        return t1, t2\n\n    def nanSetup(self, scheduler):\n        t1 = Trial("PPO")  # mean is 450, max 450, t_max=10\n        t2 = Trial("PPO")  # mean is nan, max nan, t_max=10\n        scheduler.on_trial_add(None, t1)\n        scheduler.on_trial_add(None, t2)\n        for i in range(10):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t1, result(i, 450)),\n                TrialScheduler.CONTINUE,\n            )\n        for i in range(10):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t2, result(i, np.nan)),\n                TrialScheduler.CONTINUE,\n            )\n        return t1, t2\n\n    def nanInfSetup(self, scheduler, runner=None):\n        t1 = Trial("PPO")\n        t2 = Trial("PPO")\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(runner, t1)\n        scheduler.on_trial_add(runner, t2)\n        scheduler.on_trial_add(runner, t3)\n        for i in range(10):\n            scheduler.on_trial_result(runner, t1, result(i, np.nan))\n        for i in range(10):\n            scheduler.on_trial_result(runner, t2, result(i, float("inf")))\n        for i in range(10):\n            scheduler.on_trial_result(runner, t3, result(i, float("-inf")))\n        return t1, t2, t3\n\n    def testAsyncHBOnComplete(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean", mode="max", max_t=10, brackets=1\n        )\n        t1, t2 = self.basicSetup(scheduler)\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(None, t3)\n        scheduler.on_trial_complete(None, t3, result(10, 1000))\n        self.assertEqual(\n            scheduler.on_trial_result(None, t2, result(101, 0)), TrialScheduler.STOP\n        )\n\n    def testAsyncHBGracePeriod(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=2.5,\n            reduction_factor=3,\n            brackets=1,\n        )\n        t1, t2 = self.basicSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, 1000))\n        scheduler.on_trial_complete(None, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(None, t3)\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(1, 10)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(2, 10)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(3, 10)), TrialScheduler.STOP\n        )\n\n    def testAsyncHBAllCompletes(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean", mode="max", max_t=10, brackets=10\n        )\n        trials = [Trial("PPO") for i in range(10)]\n        for t in trials:\n            scheduler.on_trial_add(None, t)\n\n        for t in trials:\n            self.assertEqual(\n                scheduler.on_trial_result(None, t, result(10, -2)), TrialScheduler.STOP\n            )\n\n    def testAsyncHBUsesPercentile(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=1,\n            max_t=10,\n            reduction_factor=2,\n            brackets=1,\n        )\n        t1, t2 = self.basicSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, 1000))\n        scheduler.on_trial_complete(None, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(None, t3)\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(1, 260)), TrialScheduler.STOP\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(2, 260)), TrialScheduler.STOP\n        )\n\n    def testAsyncHBNanPercentile(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=1,\n            max_t=10,\n            reduction_factor=2,\n            brackets=1,\n        )\n        t1, t2 = self.nanSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, 450))\n        scheduler.on_trial_complete(None, t2, result(10, np.nan))\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(None, t3)\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(1, 260)), TrialScheduler.STOP\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(2, 260)), TrialScheduler.STOP\n        )\n\n    def testAsyncHBSaveRestore(self):\n        _, tmpfile = tempfile.mkstemp()\n\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=1,\n            max_t=10,\n            reduction_factor=2,\n            brackets=1,\n        )\n\n        # Add some trials\n        trials = [Trial("PPO") for i in range(10)]\n        for t in trials:\n            scheduler.on_trial_add(None, t)\n\n        # Report some results\n        for t in trials[0:5]:\n            self.assertNotEqual(\n                scheduler.on_trial_result(None, t, result(1, 10)), TrialScheduler.STOP\n            )\n\n        # Report worse result: Trial should stop\n        self.assertEqual(\n            scheduler.on_trial_result(None, trials[5], result(1, 5)),\n            TrialScheduler.STOP,\n        )\n\n        scheduler.save(tmpfile)\n\n        scheduler2 = AsyncHyperBandScheduler()\n        scheduler2.restore(tmpfile)\n\n        # Report a new bad result: Trial should stop\n        self.assertEqual(\n            scheduler2.on_trial_result(None, trials[6], result(1, 4)),\n            TrialScheduler.STOP,\n        )\n\n        # Create a new trial and report bad result: Trial should stop\n        # Report a new bad result: Trial should stop\n        new_trial = Trial("PPO")\n        scheduler2.on_trial_add(None, new_trial)\n        self.assertEqual(\n            scheduler2.on_trial_result(None, new_trial, result(1, 2)),\n            TrialScheduler.STOP,\n        )\n\n    def testAsyncHBNonStopTrials(self):\n        trials = [Trial("PPO") for i in range(4)]\n        scheduler = AsyncHyperBandScheduler(\n            metric="metric",\n            mode="max",\n            grace_period=1,\n            max_t=3,\n            reduction_factor=2,\n            brackets=1,\n            stop_last_trials=False,\n        )\n        scheduler.on_trial_add(None, trials[0])\n        scheduler.on_trial_add(None, trials[1])\n        scheduler.on_trial_add(None, trials[2])\n        scheduler.on_trial_add(None, trials[3])\n\n        # Report one result\n        action = scheduler.on_trial_result(\n            None, trials[0], {"training_iteration": 2, "metric": 10}\n        )\n        assert action == TrialScheduler.CONTINUE\n        action = scheduler.on_trial_result(\n            None, trials[1], {"training_iteration": 2, "metric": 8}\n        )\n        assert action == TrialScheduler.STOP\n        action = scheduler.on_trial_result(\n            None, trials[2], {"training_iteration": 2, "metric": 6}\n        )\n        assert action == TrialScheduler.STOP\n        action = scheduler.on_trial_result(\n            None, trials[3], {"training_iteration": 2, "metric": 4}\n        )\n        assert action == TrialScheduler.STOP\n\n        # Report more. This will fail if `stop_last_trials=True`\n        action = scheduler.on_trial_result(\n            None, trials[0], {"training_iteration": 4, "metric": 10}\n        )\n        assert action == TrialScheduler.CONTINUE\n\n        action = scheduler.on_trial_result(\n            None, trials[0], {"training_iteration": 8, "metric": 10}\n        )\n        assert action == TrialScheduler.CONTINUE\n\n        # Also continue if we fall below the cutoff eventually\n        action = scheduler.on_trial_result(\n            None, trials[0], {"training_iteration": 14, "metric": 1}\n        )\n        assert action == TrialScheduler.CONTINUE\n\n    def testMedianStoppingNanInf(self):\n        scheduler = MedianStoppingRule(metric="episode_reward_mean", mode="max")\n\n        t1, t2, t3 = self.nanInfSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, np.nan))\n        scheduler.on_trial_complete(None, t2, result(10, float("inf")))\n        scheduler.on_trial_complete(None, t3, result(10, float("-inf")))\n\n    def testHyperbandNanInf(self):\n        scheduler = HyperBandScheduler(metric="episode_reward_mean", mode="max")\n        t1, t2, t3 = self.nanInfSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, np.nan))\n        scheduler.on_trial_complete(None, t2, result(10, float("inf")))\n        scheduler.on_trial_complete(None, t3, result(10, float("-inf")))\n\n    def testBOHBNanInf(self):\n        scheduler = HyperBandForBOHB(metric="episode_reward_mean", mode="max")\n\n        runner = _MockTrialRunner(scheduler)\n        runner._search_alg = MagicMock()\n        runner._search_alg.searcher = MagicMock()\n\n        t1, t2, t3 = self.nanInfSetup(scheduler, runner)\n        # skip trial complete in this mock setting\n\n    def testPBTNanInf(self):\n        scheduler = PopulationBasedTraining(metric="episode_reward_mean", mode="max")\n        t1, t2, t3 = self.nanInfSetup(scheduler, runner=MagicMock())\n        scheduler.on_trial_complete(None, t1, result(10, np.nan))\n        scheduler.on_trial_complete(None, t2, result(10, float("inf")))\n        scheduler.on_trial_complete(None, t3, result(10, float("-inf")))\n\n    def _test_metrics(self, result_func, metric, mode):\n        scheduler = AsyncHyperBandScheduler(\n            grace_period=1,\n            time_attr="training_iteration",\n            metric=metric,\n            mode=mode,\n            brackets=1,\n        )\n        t1 = Trial("PPO")  # mean is 450, max 900, t_max=10\n        t2 = Trial("PPO")  # mean is 450, max 450, t_max=5\n        scheduler.on_trial_add(None, t1)\n        scheduler.on_trial_add(None, t2)\n        for i in range(10):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t1, result_func(i, i * 100)),\n                TrialScheduler.CONTINUE,\n            )\n        for i in range(5):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t2, result_func(i, 450)),\n                TrialScheduler.CONTINUE,\n            )\n        scheduler.on_trial_complete(None, t1, result_func(10, 1000))\n        self.assertEqual(\n            scheduler.on_trial_result(None, t2, result_func(5, 450)),\n            TrialScheduler.CONTINUE,\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t2, result_func(6, 0)),\n            TrialScheduler.CONTINUE,\n        )\n\n    def testAlternateMetrics(self):\n        def result2(t, rew):\n            return dict(training_iteration=t, neg_mean_loss=rew)\n\n        self._test_metrics(result2, "neg_mean_loss", "max")\n\n    def testAlternateMetricsMin(self):\n        def result2(t, rew):\n            return dict(training_iteration=t, mean_loss=-rew)\n\n        self._test_metrics(result2, "mean_loss", "min")\n\n    def _testAnonymousMetricEndToEnd(self, scheduler_cls, searcher=None):\n        def train(config):\n            return config["value"]\n\n        out = tune.run(\n            train,\n            mode="max",\n            num_samples=1,\n            config={"value": tune.uniform(-2.0, 2.0)},\n            scheduler=scheduler_cls(),\n            search_alg=searcher,\n        )\n\n        self.assertTrue(bool(out.best_trial))\n\n    def testAnonymousMetricEndToEndFIFO(self):\n        self._testAnonymousMetricEndToEnd(FIFOScheduler)\n\n    def testAnonymousMetricEndToEndASHA(self):\n        self._testAnonymousMetricEndToEnd(AsyncHyperBandScheduler)\n\n    def testAnonymousMetricEndToEndBOHB(self):\n        from ray.tune.search.bohb import TuneBOHB\n\n        self._testAnonymousMetricEndToEnd(HyperBandForBOHB, TuneBOHB())\n\n    def testAnonymousMetricEndToEndMedian(self):\n        self._testAnonymousMetricEndToEnd(MedianStoppingRule)\n\n    def testAnonymousMetricEndToEndPBT(self):\n        self._testAnonymousMetricEndToEnd(PopulationBasedTraining)\n\n\nif __name__ == "__main__":\n    import pytest\n\n    sys.exit(pytest.main(["-v", __file__]))\n',
            'python/ray/tune/tests/test_trial_scheduler_pbt.py': 'import numpy as np\nimport os\nimport pickle\nimport random\nimport unittest\nimport sys\nimport time\nfrom unittest.mock import MagicMock\n\n\nimport ray\nfrom ray import tune\nfrom ray.air._internal.checkpoint_manager import _TrackedCheckpoint, CheckpointStorage\nfrom ray.tune import Trainable\nfrom ray.tune.experiment import Trial\nfrom ray.tune.execution.trial_runner import TrialRunner\nfrom ray.tune.execution.ray_trial_executor import RayTrialExecutor\nfrom ray.tune.schedulers import PopulationBasedTraining\nfrom ray._private.test_utils import object_memory_usage\n\n\n# Import psutil after ray so the packaged version is used.\nimport psutil\n\nMB = 1024 ** 2\n\n\nclass MockParam(object):\n    def __init__(self, params):\n        self._params = params\n        self._index = 0\n\n    def __call__(self, *args, **kwargs):\n        val = self._params[self._index % len(self._params)]\n        self._index += 1\n        return val\n\n\nclass PopulationBasedTrainingMemoryTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=1, object_store_memory=100 * MB)\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def testMemoryCheckpointFree(self):\n        class MyTrainable(Trainable):\n            def setup(self, config):\n                # Make sure this is large enough so ray uses object store\n                # instead of in-process store.\n                self.large_object = random.getrandbits(int(10e6))\n                self.iter = 0\n                self.a = config["a"]\n\n            def step(self):\n                self.iter += 1\n                return {"metric": self.iter + self.a}\n\n            def save_checkpoint(self, checkpoint_dir):\n                file_path = os.path.join(checkpoint_dir, "model.mock")\n\n                with open(file_path, "wb") as fp:\n                    pickle.dump((self.large_object, self.iter, self.a), fp)\n                return file_path\n\n            def load_checkpoint(self, path):\n                with open(path, "rb") as fp:\n                    self.large_object, self.iter, self.a = pickle.load(fp)\n\n        class CustomExecutor(RayTrialExecutor):\n            def save(self, *args, **kwargs):\n                checkpoint = super(CustomExecutor, self).save(*args, **kwargs)\n                assert object_memory_usage() <= (12 * 80e6)\n                return checkpoint\n\n        param_a = MockParam([1, -1])\n\n        pbt = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="metric",\n            mode="max",\n            perturbation_interval=1,\n            hyperparam_mutations={"b": [-1]},\n        )\n\n        tune.run(\n            MyTrainable,\n            name="ray_demo",\n            scheduler=pbt,\n            stop={"training_iteration": 10},\n            num_samples=3,\n            checkpoint_freq=1,\n            fail_fast=True,\n            config={"a": tune.sample_from(lambda _: param_a())},\n            trial_executor=CustomExecutor(reuse_actors=False),\n        )\n\n\nclass PopulationBasedTrainingFileDescriptorTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n        os.environ["TUNE_GLOBAL_CHECKPOINT_S"] = "0"\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def testFileFree(self):\n        class MyTrainable(Trainable):\n            def setup(self, config):\n                self.iter = 0\n                self.a = config["a"]\n\n            def step(self):\n                self.iter += 1\n                return {"metric": self.iter + self.a}\n\n            def save_checkpoint(self, checkpoint_dir):\n                file_path = os.path.join(checkpoint_dir, "model.mock")\n\n                with open(file_path, "wb") as fp:\n                    pickle.dump((self.iter, self.a), fp)\n                return file_path\n\n            def load_checkpoint(self, path):\n                with open(path, "rb") as fp:\n                    self.iter, self.a = pickle.load(fp)\n\n        from ray.tune.callback import Callback\n\n        class FileCheck(Callback):\n            def __init__(self, verbose=False):\n                self.iter_ = 0\n                self.process = psutil.Process()\n                self.verbose = verbose\n\n            def on_trial_result(self, *args, **kwargs):\n                self.iter_ += 1\n                all_files = self.process.open_files()\n                if self.verbose:\n                    print("Iteration", self.iter_)\n                    print("=" * 10)\n                    print("Object memory use: ", object_memory_usage())\n                    print("Virtual Mem:", self.get_virt_mem() >> 30, "gb")\n                    print("File Descriptors:", len(all_files))\n                assert len(all_files) < 20\n\n            @classmethod\n            def get_virt_mem(cls):\n                return psutil.virtual_memory().used\n\n        param_a = MockParam([1, -1])\n\n        pbt = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="metric",\n            mode="max",\n            perturbation_interval=1,\n            quantile_fraction=0.5,\n            hyperparam_mutations={"b": [-1]},\n        )\n\n        tune.run(\n            MyTrainable,\n            name="ray_demo",\n            scheduler=pbt,\n            stop={"training_iteration": 10},\n            num_samples=4,\n            checkpoint_freq=2,\n            keep_checkpoints_num=1,\n            verbose=False,\n            fail_fast=True,\n            config={"a": tune.sample_from(lambda _: param_a())},\n            callbacks=[FileCheck()],\n        )\n\n\nclass PopulationBasedTrainingSynchTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n        def MockTrainingFuncSync(config, checkpoint_dir=None):\n            iter = 0\n\n            if checkpoint_dir:\n                checkpoint_path = os.path.join(checkpoint_dir, "checkpoint")\n                with open(checkpoint_path, "rb") as fp:\n                    a, iter = pickle.load(fp)\n\n            a = config["a"]  # Use the new hyperparameter if perturbed.\n\n            while True:\n                iter += 1\n                with tune.checkpoint_dir(step=iter) as checkpoint_dir:\n                    checkpoint_path = os.path.join(checkpoint_dir, "checkpoint")\n                    with open(checkpoint_path, "wb") as fp:\n                        pickle.dump((a, iter), fp)\n                # Different sleep times so that asynch test runs do not\n                # randomly succeed. If well performing trials finish later,\n                # then bad performing trials will already have continued\n                # to train, which is exactly what we want to test when\n                # comparing sync vs. async.\n                time.sleep(a / 20)\n                # Score gets better every iteration.\n                tune.report(mean_accuracy=iter + a, a=a)\n\n        self.MockTrainingFuncSync = MockTrainingFuncSync\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def synchSetup(self, synch, param=None):\n        if param is None:\n            param = [10, 20, 40]\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="mean_accuracy",\n            mode="max",\n            perturbation_interval=1,\n            log_config=True,\n            hyperparam_mutations={"c": lambda: 1},\n            synch=synch,\n        )\n\n        param_a = MockParam(param)\n\n        random.seed(100)\n        np.random.seed(100)\n        analysis = tune.run(\n            self.MockTrainingFuncSync,\n            config={"a": tune.sample_from(lambda _: param_a()), "c": 1},\n            fail_fast=True,\n            num_samples=3,\n            scheduler=scheduler,\n            name="testPBTSync",\n            stop={"training_iteration": 3},\n        )\n        return analysis\n\n    def testAsynchFail(self):\n        analysis = self.synchSetup(False)\n        self.assertTrue(\n            any(\n                analysis.dataframe(metric="mean_accuracy", mode="max")["mean_accuracy"]\n                != 43\n            )\n        )\n\n    def testSynchPass(self):\n        analysis = self.synchSetup(True)\n        self.assertTrue(\n            all(\n                analysis.dataframe(metric="mean_accuracy", mode="max")["mean_accuracy"]\n                == 43\n            )\n        )\n\n    def testSynchPassLast(self):\n        analysis = self.synchSetup(True, param=[30, 20, 10])\n        self.assertTrue(\n            all(\n                analysis.dataframe(metric="mean_accuracy", mode="max")["mean_accuracy"]\n                == 33\n            )\n        )\n\n\nclass PopulationBasedTrainingConfigTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def testNoConfig(self):\n        def MockTrainingFunc(config):\n            a = config["a"]\n            b = config["b"]\n            c1 = config["c"]["c1"]\n            c2 = config["c"]["c2"]\n\n            while True:\n                tune.report(mean_accuracy=a * b * (c1 + c2))\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="mean_accuracy",\n            mode="max",\n            perturbation_interval=1,\n            hyperparam_mutations={\n                "a": tune.uniform(0, 0.3),\n                "b": [1, 2, 3],\n                "c": {\n                    "c1": lambda: np.random.uniform(0.5),\n                    "c2": tune.choice([2, 3, 4]),\n                },\n            },\n        )\n\n        tune.run(\n            MockTrainingFunc,\n            fail_fast=True,\n            num_samples=4,\n            scheduler=scheduler,\n            name="testNoConfig",\n            stop={"training_iteration": 3},\n        )\n\n\nclass PopulationBasedTrainingResumeTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def testPermutationContinuation(self):\n        """\n        Tests continuation of runs after permutation.\n        Sometimes, runs were continued from deleted checkpoints.\n        This deterministic initialisation would fail when the\n        fix was not applied.\n        See issues #9036, #9036\n        """\n\n        class MockTrainable(tune.Trainable):\n            def setup(self, config):\n                self.iter = 0\n                self.a = config["a"]\n                self.b = config["b"]\n                self.c = config["c"]\n\n            def step(self):\n                self.iter += 1\n                return {"mean_accuracy": (self.a - self.iter) * self.b}\n\n            def save_checkpoint(self, tmp_checkpoint_dir):\n                checkpoint_path = os.path.join(tmp_checkpoint_dir, "model.mock")\n                with open(checkpoint_path, "wb") as fp:\n                    pickle.dump((self.a, self.b, self.iter), fp)\n                return tmp_checkpoint_dir\n\n            def load_checkpoint(self, tmp_checkpoint_dir):\n                checkpoint_path = os.path.join(tmp_checkpoint_dir, "model.mock")\n                with open(checkpoint_path, "rb") as fp:\n                    self.a, self.b, self.iter = pickle.load(fp)\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="mean_accuracy",\n            mode="max",\n            perturbation_interval=1,\n            log_config=True,\n            hyperparam_mutations={"c": lambda: 1},\n        )\n\n        param_a = MockParam([10, 20, 30, 40])\n        param_b = MockParam([1.2, 0.9, 1.1, 0.8])\n\n        random.seed(100)\n        np.random.seed(1000)\n        tune.run(\n            MockTrainable,\n            config={\n                "a": tune.sample_from(lambda _: param_a()),\n                "b": tune.sample_from(lambda _: param_b()),\n                "c": 1,\n            },\n            fail_fast=True,\n            num_samples=4,\n            checkpoint_freq=1,\n            checkpoint_at_end=True,\n            keep_checkpoints_num=1,\n            checkpoint_score_attr="min-training_iteration",\n            scheduler=scheduler,\n            name="testPermutationContinuation",\n            stop={"training_iteration": 3},\n        )\n\n    def testPermutationContinuationFunc(self):\n        def MockTrainingFunc(config, checkpoint_dir=None):\n            iter = 0\n            a = config["a"]\n            b = config["b"]\n\n            if checkpoint_dir:\n                checkpoint_path = os.path.join(checkpoint_dir, "model.mock")\n                with open(checkpoint_path, "rb") as fp:\n                    a, b, iter = pickle.load(fp)\n\n            while True:\n                iter += 1\n                with tune.checkpoint_dir(step=iter) as checkpoint_dir:\n                    checkpoint_path = os.path.join(checkpoint_dir, "model.mock")\n                    with open(checkpoint_path, "wb") as fp:\n                        pickle.dump((a, b, iter), fp)\n                tune.report(mean_accuracy=(a - iter) * b)\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="mean_accuracy",\n            mode="max",\n            perturbation_interval=1,\n            log_config=True,\n            hyperparam_mutations={"c": lambda: 1},\n        )\n        param_a = MockParam([10, 20, 30, 40])\n        param_b = MockParam([1.2, 0.9, 1.1, 0.8])\n        random.seed(100)\n        np.random.seed(1000)\n        tune.run(\n            MockTrainingFunc,\n            config={\n                "a": tune.sample_from(lambda _: param_a()),\n                "b": tune.sample_from(lambda _: param_b()),\n                "c": 1,\n            },\n            fail_fast=True,\n            num_samples=4,\n            keep_checkpoints_num=1,\n            checkpoint_score_attr="min-training_iteration",\n            scheduler=scheduler,\n            name="testPermutationContinuationFunc",\n            stop={"training_iteration": 3},\n        )\n\n    def testBurnInPeriod(self):\n        runner = TrialRunner(trial_executor=MagicMock())\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="error",\n            mode="min",\n            perturbation_interval=5,\n            burn_in_period=50,\n            log_config=True,\n            synch=True,\n        )\n\n        class MockTrial(Trial):\n            @property\n            def checkpoint(self):\n                return _TrackedCheckpoint(\n                    dir_or_data={"data": "None"},\n                    storage_mode=CheckpointStorage.MEMORY,\n                    metrics={},\n                )\n\n            @property\n            def status(self):\n                return Trial.PAUSED\n\n            @status.setter\n            def status(self, status):\n                pass\n\n        trial1 = MockTrial("PPO", config=dict(num=1))\n        trial2 = MockTrial("PPO", config=dict(num=2))\n        trial3 = MockTrial("PPO", config=dict(num=3))\n        trial4 = MockTrial("PPO", config=dict(num=4))\n\n        runner.add_trial(trial1)\n        runner.add_trial(trial2)\n        runner.add_trial(trial3)\n        runner.add_trial(trial4)\n\n        scheduler.on_trial_add(runner, trial1)\n        scheduler.on_trial_add(runner, trial2)\n        scheduler.on_trial_add(runner, trial3)\n        scheduler.on_trial_add(runner, trial4)\n\n        # Add initial results.\n        scheduler.on_trial_result(\n            runner, trial1, result=dict(training_iteration=1, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial2, result=dict(training_iteration=1, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial3, result=dict(training_iteration=1, error=10)\n        )\n        scheduler.on_trial_result(\n            runner, trial4, result=dict(training_iteration=1, error=100)\n        )\n\n        # Add more results. Without burn-in, this would now exploit\n        scheduler.on_trial_result(\n            runner, trial1, result=dict(training_iteration=30, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial2, result=dict(training_iteration=30, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial3, result=dict(training_iteration=30, error=10)\n        )\n        scheduler.on_trial_result(\n            runner, trial4, result=dict(training_iteration=30, error=100)\n        )\n\n        self.assertEqual(trial4.config["num"], 4)\n\n        # Add more results. Since this is after burn-in, it should now exploit\n        scheduler.on_trial_result(\n            runner, trial1, result=dict(training_iteration=50, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial2, result=dict(training_iteration=50, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial3, result=dict(training_iteration=50, error=10)\n        )\n        scheduler.on_trial_result(\n            runner, trial4, result=dict(training_iteration=50, error=100)\n        )\n\n        self.assertEqual(trial4.config["num"], 3)\n\n        # Assert that trials do not hang after `burn_in_period`\n        self.assertTrue(all(t.status == "PAUSED" for t in runner.get_trials()))\n        self.assertTrue(scheduler.choose_trial_to_run(runner))\n\n        # Assert that trials do not hang when a terminated trial is added\n        trial5 = Trial("PPO", config=dict(num=5))\n        runner.add_trial(trial5)\n        scheduler.on_trial_add(runner, trial5)\n        trial5.set_status(Trial.TERMINATED)\n        self.assertTrue(scheduler.choose_trial_to_run(runner))\n\n\nif __name__ == "__main__":\n    import pytest\n\n    sys.exit(pytest.main(["-v", __file__]))\n',
        }
